{
  "name": "PrintMaster Pro - Ordering App",
  "description": "A high-performance order management system for a printing typography shop specializing in T-shirts, Hoodies, and Caps with multi-step customization and Trello/Email integration.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ProductType {
  TSHIRT = 'TSHIRT',
  HOODIE = 'HOODIE',
  CAP = 'CAP'
}

export enum OrderSubtype {
  SCHOOL = 'Школа',
  PERSONAL = 'Личный дизайн',
  TEAM = 'Команда'
}

export enum HoodieType {
  ZIP = 'На молнии с капюшоном',
  KANGAROO = 'Кенгуру с капюшоном',
  SWEATER = 'Свитер без капюшона'
}

export enum CapType {
  BASEBALL = 'Бейсболка',
  BEANIE = 'Шапка-бини',
  SNAPBACK = 'Снэпбек'
}

export interface Player {
  id: string;
  name: string;
  number: string;
  gender: 'Мальчик' | 'Девочка';
  sleeve: string;
  size: string;
}

export interface OrderItem {
  id: string;
  type: ProductType;
  subtype: OrderSubtype;
  school?: string;
  printPlaces: string[];
  images: string[]; // Base64 or URLs
  players?: Player[];
  hoodieType?: HoodieType;
  capType?: CapType;
  gender?: 'Мальчик' | 'Девочка' | 'Универсальный';
  sleeve?: string;
  size: string;
  color: string;
  quantity: number;
}

export interface CustomerData {
  name: string;
  phone: string;
  email: string;
  address?: string;
  comments?: string;
}

export interface Order {
  orderNumber: string;
  customer: CustomerData;
  items: OrderItem[];
  createdAt: string;
}

export const COLORS = [
  { name: 'Белый', hex: '#FFFFFF' },
  { name: 'Чёрный', hex: '#000000' },
  { name: 'Тёмно синий / Navy', hex: '#001F3F' },
  { name: 'Тёмно зелёный', hex: '#004D00' },
  { name: 'Royal', hex: '#4169E1' },
  { name: 'Бирюзовый / Turquoise', hex: '#40E0D0' },
  { name: 'Оранжевый', hex: '#FF8C00' },
  { name: 'Красный', hex: '#FF0000' },
  { name: 'Фуксия', hex: '#FF00FF' },
];

export const SCHOOL_SIZES_KIDS = ['6', '8', '10', '12', '14', '16', '18'];
export const SCHOOL_SIZES_ADULTS = ['S', 'M', 'L', 'XL', '2XL'];

export const PERSONAL_SIZES_KIDS = ['2', '4', '6', '8', '10', '12', '14', '16', '18'];
export const PERSONAL_SIZES_ADULTS = ['S', 'M', 'L', 'XL', '2XL', '3XL', '4XL'];

export const TEAM_SIZES_KIDS = ['10', '12', '14', '16', '18'];
export const TEAM_SIZES_ADULTS = ['S', 'M', 'L', 'XL', '2XL', '3XL', '4XL'];

export const SLEEVES = {
  BOY: ['Короткий', 'Длинный'],
  GIRL: ['Короткий', 'Длинный', '3/4']
};

export const PRINT_PLACES = ['Спереди', 'Сзади', 'Левый рукав', 'Правый рукав'];

export const SCHOOL_LIST = [
  "Школа №1", "Лицей №15", "Гимназия №3", "Школа Искусств", "Спортивная школа 'Олимп'",
  "Школа №100", "МБОУ СОШ №42", "Президентский лицей"
];

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getDesignFeedback(itemType: string, subtype: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User is designing a ${itemType} with ${subtype} style. Provide 3 creative typography design tips for this specific product in Russian. Keep it short and catchy.`
    });
    return response.text;
  } catch (error) {
    console.error("Gemini design tips error:", error);
    return null;
  }
}

export async function generateOrderSummaryDescription(orderData: any) {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Generate a professional, warm order confirmation summary for a customer in Russian. The order has ${orderData.items.length} items. Keep it formal yet friendly.`
        });
        return response.text;
    } catch (e) {
        return "Ваш заказ успешно сформирован и готов к отправке!";
    }
}

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-medium transition-all duration-200 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-md hover:shadow-lg",
    secondary: "bg-purple-600 text-white hover:bg-purple-700 shadow-md",
    outline: "border-2 border-indigo-600 text-indigo-600 hover:bg-indigo-50",
    danger: "bg-red-500 text-white hover:bg-red-600"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-lg"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';
import { Player } from '../types';
import { Button } from './ui/Button';
import { TEAM_SIZES_KIDS, TEAM_SIZES_ADULTS, SLEEVES } from '../constants';

interface PlayerTableProps {
  players: Player[];
  onChange: (players: Player[]) => void;
}

export const PlayerTable: React.FC<PlayerTableProps> = ({ players, onChange }) => {
  const addPlayer = () => {
    const newPlayer: Player = {
      id: Math.random().toString(36).substr(2, 9),
      name: '',
      number: '',
      gender: 'Мальчик',
      sleeve: 'Короткий',
      size: 'S'
    };
    onChange([...players, newPlayer]);
  };

  const removePlayer = (id: string) => {
    onChange(players.filter(p => p.id !== id));
  };

  const updatePlayer = (id: string, field: keyof Player, value: string) => {
    onChange(players.map(p => p.id === id ? { ...p, [field]: value } : p));
  };

  return (
    <div className="mt-4 overflow-x-auto bg-white rounded-xl shadow-inner p-4">
      <h3 className="text-lg font-semibold mb-3 text-gray-700">Список команды</h3>
      <table className="min-w-full divide-y divide-gray-200">
        <thead>
          <tr className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
            <th className="px-2 py-2">Имя</th>
            <th className="px-2 py-2">Номер</th>
            <th className="px-2 py-2">Пол</th>
            <th className="px-2 py-2">Рукав</th>
            <th className="px-2 py-2">Размер</th>
            <th className="px-2 py-2"></th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {players.map((player) => (
            <tr key={player.id}>
              <td className="px-2 py-2">
                <input 
                  type="text" 
                  value={player.name}
                  onChange={(e) => updatePlayer(player.id, 'name', e.target.value)}
                  className="w-full border-b focus:border-indigo-500 outline-none p-1 text-sm"
                  placeholder="Имя"
                />
              </td>
              <td className="px-2 py-2">
                <input 
                  type="text" 
                  value={player.number}
                  onChange={(e) => updatePlayer(player.id, 'number', e.target.value)}
                  className="w-16 border-b focus:border-indigo-500 outline-none p-1 text-sm text-center"
                  placeholder="№"
                />
              </td>
              <td className="px-2 py-2">
                <select 
                   value={player.gender}
                   onChange={(e) => updatePlayer(player.id, 'gender', e.target.value as any)}
                   className="text-sm outline-none bg-transparent border-b"
                >
                  <option>Мальчик</option>
                  <option>Девочка</option>
                </select>
              </td>
              <td className="px-2 py-2">
                 <select 
                   value={player.sleeve}
                   onChange={(e) => updatePlayer(player.id, 'sleeve', e.target.value)}
                   className="text-sm outline-none bg-transparent border-b"
                >
                  {player.gender === 'Мальчик' 
                    ? SLEEVES.BOY.map(s => <option key={s} value={s}>{s}</option>)
                    : SLEEVES.GIRL.map(s => <option key={s} value={s}>{s}</option>)
                  }
                </select>
              </td>
              <td className="px-2 py-2">
                <select 
                   value={player.size}
                   onChange={(e) => updatePlayer(player.id, 'size', e.target.value)}
                   className="text-sm outline-none bg-transparent border-b"
                >
                  <optgroup label="Дети">
                    {TEAM_SIZES_KIDS.map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                    {TEAM_SIZES_ADULTS.map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </select>
              </td>
              <td className="px-2 py-2">
                <button 
                  onClick={() => removePlayer(player.id)}
                  className="text-red-500 hover:text-red-700"
                >
                  ✕
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <Button 
        onClick={addPlayer} 
        variant="outline" 
        size="sm" 
        className="mt-4 border-dashed w-full"
      >
        + Добавить игрока
      </Button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  onAddToCart: (item: OrderItem) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, onAddToCart, onCancel }) => {
  const [subtype, setSubtype] = useState<OrderSubtype>(OrderSubtype.SCHOOL);
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [tips, setTips] = useState<string | null>(null);

  useEffect(() => {
    // Reset defaults based on type/subtype
    if (productType === ProductType.CAP) {
        setSubtype(OrderSubtype.PERSONAL);
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
        if (subtype === OrderSubtype.TEAM) setSubtype(OrderSubtype.SCHOOL);
    }

    // Fetch AI tips
    getDesignFeedback(productType, subtype).then(setTips);
  }, [productType, subtype]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const readers = Array.from(files).map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      });
      Promise.all(readers).then(results => {
        setFormData(prev => ({ ...prev, images: [...(prev.images || []), ...results] }));
      });
    }
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const handleAdd = () => {
    onAddToCart({
      ...formData,
      id: Math.random().toString(36).substr(2, 9),
      type: productType,
      subtype: subtype,
    } as OrderItem);
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">
          Настройка: {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : 'Шапка'}
        </h2>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {/* Subtype Selector */}
      {productType !== ProductType.CAP && (
        <div className="grid grid-cols-3 gap-3 mb-8">
          {[OrderSubtype.SCHOOL, OrderSubtype.PERSONAL, OrderSubtype.TEAM].map(s => {
             if (productType === ProductType.HOODIE && s === OrderSubtype.TEAM) return null;
             return (
               <button
                 key={s}
                 onClick={() => setSubtype(s)}
                 className={`py-2 px-4 rounded-xl text-sm font-semibold transition-all ${
                   subtype === s ? 'bg-indigo-600 text-white shadow-lg' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                 }`}
               >
                 {s}
               </button>
             );
          })}
        </div>
      )}

      {/* AI Tips */}
      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {/* Type specific fields */}
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.hoodieType}
              onChange={e => setFormData({ ...formData, hoodieType: e.target.value as HoodieType })}
            >
              {Object.values(HoodieType).map(v => <option key={v} value={v}>{v}</option>)}
            </select>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.capType}
              onChange={e => setFormData({ ...formData, capType: e.target.value as CapType })}
            >
              {Object.values(CapType).map(v => <option key={v} value={v}>{v}</option>)}
            </select>
          </div>
        )}

        {subtype === OrderSubtype.SCHOOL && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.school}
              onChange={e => setFormData({ ...formData, school: e.target.value })}
            >
              <option value="">-- Выбор из 100+ школ --</option>
              {SCHOOL_LIST.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        )}

        {(subtype === OrderSubtype.PERSONAL || subtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {(productType === ProductType.CAP ? ['Спереди'] : PRINT_PLACES).map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Загрузить изображения</label>
              <div className="flex items-center gap-4">
                <input 
                  type="file" 
                  multiple 
                  onChange={handleImageUpload}
                  className="hidden" 
                  id="image-upload" 
                />
                <label 
                  htmlFor="image-upload" 
                  className="cursor-pointer bg-gray-100 hover:bg-gray-200 py-3 px-6 rounded-xl border-2 border-dashed border-gray-300 text-gray-500 text-sm font-medium flex items-center gap-2"
                >
                  📁 Выбрать файлы
                </label>
                <div className="flex -space-x-2 overflow-hidden">
                  {formData.images?.map((img, idx) => (
                    <img key={idx} src={img} className="inline-block h-8 w-8 rounded-full ring-2 ring-white object-cover" />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {subtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
          />
        )}

        {/* Global params: Color, Gender, Size, Qty */}
        {subtype !== OrderSubtype.TEAM && (
          <div className="grid grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Цвет</label>
              <div className="flex flex-wrap gap-2">
                {COLORS.map(c => (
                  <button
                    key={c.hex}
                    onClick={() => setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all ${
                      formData.color === c.name ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            {productType !== ProductType.CAP && (
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
                <div className="flex gap-2">
                   {['Мальчик', 'Девочка'].map(g => (
                     <button
                       key={g}
                       onClick={() => setFormData({ ...formData, gender: g as any })}
                       className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                         formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                       }`}
                     >
                       {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                     </button>
                   ))}
                </div>
              </div>
            )}

            {productType === ProductType.TSHIRT && (
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
                <select 
                  className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm"
                  value={formData.sleeve}
                  onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
                >
                  {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            )}

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm"
                value={formData.size}
                onChange={e => setFormData({ ...formData, size: e.target.value })}
              >
                {productType === ProductType.CAP ? (
                  <option>Универсальный</option>
                ) : (
                  <>
                    <optgroup label="Дети">
                      {(subtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                    <optgroup label="Взрослые">
                       {(subtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                  </>
                )}
              </select>
            </div>

            <div className="col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold"
                >+</button>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button onClick={handleAdd} variant="primary" fullWidth>Добавить в корзину</Button>
      </div>
    </div>
  );
};

import React from 'react';
import { OrderItem } from '../types';
import { Button } from './ui/Button';

interface CartViewProps {
  items: OrderItem[];
  onRemove: (id: string) => void;
  onNext: () => void;
}

export const CartView: React.FC<CartViewProps> = ({ items, onRemove, onNext }) => {
  if (items.length === 0) return null;

  return (
    <div className="mt-12 bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center gap-2">
        🛒 Ваша корзина <span className="bg-indigo-600 text-white text-xs px-2 py-1 rounded-full">{items.length}</span>
      </h2>
      <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
        {items.map((item) => (
          <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl hover:bg-gray-100 transition-colors group">
            <div className="flex gap-4 items-center">
              <div className="w-16 h-16 bg-white rounded-xl shadow-sm flex items-center justify-center text-2xl">
                {item.type === 'TSHIRT' ? '👕' : item.type === 'HOODIE' ? '🧥' : '🧢'}
              </div>
              <div>
                <p className="font-bold text-gray-800">{item.subtype} - {item.type}</p>
                <p className="text-xs text-gray-500 uppercase font-semibold">
                  {item.color} • {item.size} • x{item.quantity} 
                  {item.school && ` • ${item.school}`}
                  {item.players && ` • Команда (${item.players.length} чел.)`}
                </p>
              </div>
            </div>
            <button 
              onClick={() => onRemove(item.id)}
              className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-2"
            >
              🗑️
            </button>
          </div>
        ))}
      </div>
      <div className="mt-8 pt-6 border-t border-gray-100 flex justify-between items-center">
        <div>
          <p className="text-gray-500 text-sm">Общее количество:</p>
          <p className="text-xl font-bold text-gray-800">
            {items.reduce((acc, item) => acc + (item.subtype === 'Команда' ? (item.players?.length || 0) : item.quantity), 0)} шт.
          </p>
        </div>
        <Button onClick={onNext} variant="primary" size="lg">Оформить заказ →</Button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CustomerData } from '../types';
import { Button } from './ui/Button';

interface CustomerInfoProps {
  onSubmit: (data: CustomerData) => void;
  onBack: () => void;
}

export const CustomerInfo: React.FC<CustomerInfoProps> = ({ onSubmit, onBack }) => {
  const [data, setData] = useState<CustomerData>({
    name: '',
    phone: '',
    email: '',
    address: '',
    comments: ''
  });

  const [errors, setErrors] = useState<Partial<Record<keyof CustomerData, string>>>({});

  const validate = () => {
    const newErrors: any = {};
    if (!data.name) newErrors.name = 'Имя обязательно';
    if (!data.phone) newErrors.phone = 'Телефон обязателен';
    if (!data.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) newErrors.email = 'Некорректный email';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit(data);
    }
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 max-w-xl mx-auto">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 text-center">Контактные данные</h2>
      <form onSubmit={handleSubmit} className="space-y-5">
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-1">ФИО *</label>
          <input 
            type="text" 
            className={`w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 ring-indigo-400 ${errors.name ? 'border-red-400' : 'border-gray-200'}`}
            value={data.name}
            onChange={e => setData({...data, name: e.target.value})}
            placeholder="Иван Иванов"
          />
          {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name}</p>}
        </div>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">Телефон *</label>
            <input 
              type="tel" 
              className={`w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 ring-indigo-400 ${errors.phone ? 'border-red-400' : 'border-gray-200'}`}
              value={data.phone}
              onChange={e => setData({...data, phone: e.target.value})}
              placeholder="+7 (___) ___ __ __"
            />
            {errors.phone && <p className="text-red-500 text-xs mt-1">{errors.phone}</p>}
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">Email *</label>
            <input 
              type="email" 
              className={`w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 ring-indigo-400 ${errors.email ? 'border-red-400' : 'border-gray-200'}`}
              value={data.email}
              onChange={e => setData({...data, email: e.target.value})}
              placeholder="example@mail.com"
            />
            {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
          </div>
        </div>
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-1">Адрес доставки</label>
          <input 
            type="text" 
            className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none"
            value={data.address}
            onChange={e => setData({...data, address: e.target.value})}
            placeholder="Город, улица, дом..."
          />
        </div>
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-1">Комментарий к заказу</label>
          <textarea 
            className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none h-24"
            value={data.comments}
            onChange={e => setData({...data, comments: e.target.value})}
            placeholder="Любые пожелания..."
          />
        </div>
        <div className="flex gap-4 pt-4">
          <Button onClick={onBack} variant="outline" fullWidth type="button">Назад к товарам</Button>
          <Button variant="primary" fullWidth type="submit">Подтвердить заказ</Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ProductType, OrderItem, CustomerData, Order } from './types';
import { Button } from './components/ui/Button';
import { OrderForm } from './components/OrderForm';
import { CartView } from './components/CartView';
import { CustomerInfo } from './components/CustomerInfo';
import { generateOrderSummaryDescription } from './services/geminiService';

enum Step {
  SELECT_PRODUCT,
  CONFIGURE,
  CHECKOUT,
  SUCCESS
}

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.SELECT_PRODUCT);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [activeType, setActiveType] = useState<ProductType | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [orderId, setOrderId] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');

  const selectProduct = (type: ProductType) => {
    setActiveType(type);
    setStep(Step.CONFIGURE);
  };

  const addToCart = (item: OrderItem) => {
    setCart(prev => [...prev, item]);
    setStep(Step.SELECT_PRODUCT);
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const submitOrder = async (data: CustomerData) => {
    setCustomer(data);
    setIsSubmitting(true);

    const newOrderId = `ORD-${Date.now()}`;
    setOrderId(newOrderId);

    const fullOrder: Order = {
      orderNumber: newOrderId,
      customer: data,
      items: cart,
      createdAt: new Date().toISOString()
    };

    // Simulate Backend API Call
    console.log("Sending order to backend (Email/Trello)...", fullOrder);

    // Get AI Summary for Success Screen
    const summary = await generateOrderSummaryDescription(fullOrder);
    setAiSummary(summary);

    setTimeout(() => {
      setIsSubmitting(false);
      setStep(Step.SUCCESS);
    }, 1500);
  };

  const reset = () => {
    setCart([]);
    setStep(Step.SELECT_PRODUCT);
    setCustomer(null);
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="gradient-bg text-white py-12 px-6 shadow-xl mb-12">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div>
             <h1 className="text-4xl font-black tracking-tight">PRINTMASTER PRO</h1>
             <p className="text-indigo-100 mt-2 font-medium">Ваша индивидуальная печать на одежде</p>
          </div>
          <div className="hidden md:block bg-white/20 px-6 py-3 rounded-2xl backdrop-blur-md">
            <p className="text-sm font-bold">WhatsApp: +7 (900) 123-45-67</p>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">

        {step === Step.SELECT_PRODUCT && (
          <div className="space-y-12 animate-in fade-in duration-700">
            <h2 className="text-3xl font-bold text-center text-gray-800">Что будем печатать сегодня?</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <ProductCard 
                title="Футболка" 
                icon="👕" 
                desc="3 варианта заказа: Школа, Личный дизайн, Команда"
                onClick={() => selectProduct(ProductType.TSHIRT)}
              />
              <ProductCard 
                title="Худи" 
                icon="🧥" 
                desc="На молнии, кенгуру или свитер. Школа или Личный дизайн"
                onClick={() => selectProduct(ProductType.HOODIE)}
              />
              <ProductCard 
                title="Шапка" 
                icon="🧢" 
                desc="3 типа шапок. Только личный дизайн"
                onClick={() => selectProduct(ProductType.CAP)}
              />
            </div>

            <CartView items={cart} onRemove={removeItem} onNext={() => setStep(Step.CHECKOUT)} />
          </div>
        )}

        {step === Step.CONFIGURE && activeType && (
          <OrderForm 
            productType={activeType} 
            onAddToCart={addToCart} 
            onCancel={() => setStep(Step.SELECT_PRODUCT)}
          />
        )}

        {step === Step.CHECKOUT && (
          <CustomerInfo 
            onSubmit={submitOrder} 
            onBack={() => setStep(Step.SELECT_PRODUCT)}
          />
        )}

        {step === Step.SUCCESS && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-green-500">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Заказ отправлен!</h2>
            <p className="text-gray-500 mb-2">Ваш номер заказа:</p>
            <p className="text-2xl font-mono font-bold text-indigo-600 bg-indigo-50 inline-block px-4 py-2 rounded-xl mb-6">{orderId}</p>

            <div className="bg-gray-50 p-6 rounded-2xl mb-8 text-left border border-gray-100 italic">
               <p className="text-gray-700 leading-relaxed">{aiSummary}</p>
            </div>

            <div className="space-y-4">
              <p className="text-sm text-gray-500">Мы скоро свяжемся с вами в WhatsApp для подтверждения макета.</p>
              <Button onClick={reset} variant="primary" fullWidth>Создать новый заказ</Button>
            </div>
          </div>
        )}
      </main>

      {isSubmitting && (
        <div className="fixed inset-0 bg-white/80 backdrop-blur-sm flex flex-col items-center justify-center z-50">
          <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-xl font-bold text-indigo-800">Отправляем ваш заказ...</p>
          <p className="text-gray-500 mt-2">Генерируем PDF и создаем карточку в Trello</p>
        </div>
      )}
    </div>
  );
};

const ProductCard: React.FC<{title: string, icon: string, desc: string, onClick: () => void}> = ({ title, icon, desc, onClick }) => (
  <div 
    onClick={onClick}
    className="bg-white rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center"
  >
    <div className="text-7xl mb-6 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-2xl font-bold text-gray-800 mb-2">{title}</h3>
    <p className="text-gray-500 text-sm leading-relaxed">{desc}</p>
    <div className="mt-6">
       <span className="inline-block bg-indigo-50 text-indigo-600 font-bold px-4 py-2 rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-colors">Выбрать</span>
    </div>
  </div>
);

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  onAddToCart: (item: OrderItem) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, onAddToCart, onCancel }) => {
  const [subtype, setSubtype] = useState<OrderSubtype>(OrderSubtype.SCHOOL);
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [tips, setTips] = useState<string | null>(null);

  useEffect(() => {
    // Reset defaults based on type/subtype
    if (productType === ProductType.CAP) {
        setSubtype(OrderSubtype.PERSONAL);
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
        if (subtype === OrderSubtype.TEAM) setSubtype(OrderSubtype.SCHOOL);
    }

    // Fetch AI tips
    getDesignFeedback(productType, subtype).then(setTips);
  }, [productType, subtype]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      // Fix: Explicitly type 'file' as File to avoid 'unknown' inference error when calling readAsDataURL
      const readers = Array.from(files).map((file: File) => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      });
      Promise.all(readers).then(results => {
        setFormData(prev => ({ ...prev, images: [...(prev.images || []), ...results] }));
      });
    }
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const handleAdd = () => {
    onAddToCart({
      ...formData,
      id: Math.random().toString(36).substr(2, 9),
      type: productType,
      subtype: subtype,
    } as OrderItem);
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">
          Настройка: {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : 'Шапка'}
        </h2>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {/* Subtype Selector */}
      {productType !== ProductType.CAP && (
        <div className="grid grid-cols-3 gap-3 mb-8">
          {[OrderSubtype.SCHOOL, OrderSubtype.PERSONAL, OrderSubtype.TEAM].map(s => {
             if (productType === ProductType.HOODIE && s === OrderSubtype.TEAM) return null;
             return (
               <button
                 key={s}
                 onClick={() => setSubtype(s)}
                 className={`py-2 px-4 rounded-xl text-sm font-semibold transition-all ${
                   subtype === s ? 'bg-indigo-600 text-white shadow-lg' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                 }`}
               >
                 {s}
               </button>
             );
          })}
        </div>
      )}

      {/* AI Tips */}
      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {/* Type specific fields */}
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.hoodieType}
              onChange={e => setFormData({ ...formData, hoodieType: e.target.value as HoodieType })}
            >
              {Object.values(HoodieType).map(v => <option key={v} value={v}>{v}</option>)}
            </select>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.capType}
              onChange={e => setFormData({ ...formData, capType: e.target.value as CapType })}
            >
              {Object.values(CapType).map(v => <option key={v} value={v}>{v}</option>)}
            </select>
          </div>
        )}

        {subtype === OrderSubtype.SCHOOL && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.school}
              onChange={e => setFormData({ ...formData, school: e.target.value })}
            >
              <option value="">-- Выбор из 100+ школ --</option>
              {SCHOOL_LIST.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        )}

        {(subtype === OrderSubtype.PERSONAL || subtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {(productType === ProductType.CAP ? ['Спереди'] : PRINT_PLACES).map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Загрузить изображения</label>
              <div className="flex items-center gap-4">
                <input 
                  type="file" 
                  multiple 
                  onChange={handleImageUpload}
                  className="hidden" 
                  id="image-upload" 
                />
                <label 
                  htmlFor="image-upload" 
                  className="cursor-pointer bg-gray-100 hover:bg-gray-200 py-3 px-6 rounded-xl border-2 border-dashed border-gray-300 text-gray-500 text-sm font-medium flex items-center gap-2"
                >
                  📁 Выбрать файлы
                </label>
                <div className="flex -space-x-2 overflow-hidden">
                  {formData.images?.map((img, idx) => (
                    <img key={idx} src={img} className="inline-block h-8 w-8 rounded-full ring-2 ring-white object-cover" />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {subtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
          />
        )}

        {/* Global params: Color, Gender, Size, Qty */}
        {subtype !== OrderSubtype.TEAM && (
          <div className="grid grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Цвет</label>
              <div className="flex flex-wrap gap-2">
                {COLORS.map(c => (
                  <button
                    key={c.hex}
                    onClick={() => setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all ${
                      formData.color === c.name ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            {productType !== ProductType.CAP && (
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
                <div className="flex gap-2">
                   {['Мальчик', 'Девочка'].map(g => (
                     <button
                       key={g}
                       onClick={() => setFormData({ ...formData, gender: g as any })}
                       className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                         formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                       }`}
                     >
                       {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                     </button>
                   ))}
                </div>
              </div>
            )}

            {productType === ProductType.TSHIRT && (
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
                <select 
                  className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm"
                  value={formData.sleeve}
                  onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
                >
                  {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            )}

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm"
                value={formData.size}
                onChange={e => setFormData({ ...formData, size: e.target.value })}
              >
                {productType === ProductType.CAP ? (
                  <option>Универсальный</option>
                ) : (
                  <>
                    <optgroup label="Дети">
                      {(subtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                    <optgroup label="Взрослые">
                       {(subtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                  </>
                )}
              </select>
            </div>

            <div className="col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold"
                >+</button>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button onClick={handleAdd} variant="primary" fullWidth>Добавить в корзину</Button>
      </div>
    </div>
  );
};

