    text: `Поступил новый заказ №${order.orderNumber} от ${order.customer.name}.\nДетали во вложении.`,
    attachments: [
      {
        filename: `Order_${order.orderNumber}.pdf`,
        content: pdfBuffer
      }
    ]
  };

  try {
    await transporter.sendMail(mailOptions);
