import express from 'express';
import cors from 'cors';
import { generateOrderPDF } from './services/pdfService';
import { sendOrderEmail } from './services/emailService';
import { createTrelloCard } from './services/trelloService';
import { Order } from './types';

const app = express();
const PORT = process.env.PORT || 3001;

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Simple in-memory storage for order history
const ordersHistory: Order[] = [];

app.post('/api/orders', async (req, res) => {
  const orderData: Order = req.body;

  try {
    console.log(`Processing order: ${orderData.orderNumber}`);

    // Set initial status if not present
    orderData.status = orderData.status || 'Новый';

    // Save to local history
    ordersHistory.push(orderData);

    // 1. Generate PDF buffer
    const pdfBuffer = await generateOrderPDF(orderData);

    // 2. Send Email with PDF attachment
    await sendOrderEmail(orderData, pdfBuffer);

    // 3. Create Trello Card
    await createTrelloCard(orderData);

    res.status(200).json({ 
      success: true, 
      message: 'Order processed successfully',
      orderNumber: orderData.orderNumber 
    });
  } catch (error) {
    console.error('Order processing failed:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Internal server error during order processing' 
    });
  }
});

// Admin endpoint to get all orders
app.get('/api/orders', (req, res) => {
  res.status(200).json(ordersHistory);
});

// Admin endpoint to update order status
app.patch('/api/orders/:orderNumber', (req, res) => {
  const { orderNumber } = req.params;
  const { status } = req.body;

  const orderIndex = ordersHistory.findIndex(o => o.orderNumber === orderNumber);
  if (orderIndex > -1) {
    ordersHistory[orderIndex].status = status;
    return res.status(200).json(ordersHistory[orderIndex]);
  }

  res.status(404).json({ message: 'Order not found' });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Order, OrderStatus } from '../types';
import { Button } from './ui/Button';

const API_URL = 'http://localhost:3001/api';

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');

  useEffect(() => {
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const response = await axios.get(`${API_URL}/orders`);
      setOrders(response.data);
    } catch (error) {
      console.error("Failed to fetch orders:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateStatus = async (orderNumber: string, newStatus: OrderStatus) => {
    try {
      await axios.patch(`${API_URL}/orders/${orderNumber}`, { status: newStatus });
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, status: newStatus } : o));
    } catch (error) {
      console.error("Failed to update status:", error);
    }
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase());
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      const dateA = new Date(a.createdAt).getTime();
      const dateB = new Date(b.createdAt).getTime();
      return sortOrder === 'desc' ? dateB - dateA : dateA - dateB;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'Новый': return 'bg-blue-100 text-blue-700';
      case 'В работе': return 'bg-yellow-100 text-yellow-700';
      case 'Завершен': return 'bg-green-100 text-green-700';
      case 'Отменен': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <h2 className="text-3xl font-black text-gray-800">История заказов</h2>
        <div className="flex flex-wrap gap-3 w-full md:w-auto">
          <input 
            type="text" 
            placeholder="Поиск по имени, почте или ID..."
            className="flex-1 md:w-64 p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
          <select 
            className="p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none cursor-pointer"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            <option value="Новый">Новый</option>
            <option value="В работе">В работе</option>
            <option value="Завершен">Завершен</option>
            <option value="Отменен">Отменен</option>
          </select>
          <Button onClick={fetchOrders} variant="outline" size="sm">Обновить</Button>
        </div>
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500">Загрузка данных...</p>
        </div>
      ) : filteredOrders.length === 0 ? (
        <div className="py-20 text-center text-gray-500 italic">
          Заказов не найдено
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc')}>
                  Дата {sortOrder === 'desc' ? '↓' : '↑'}
                </th>
                <th className="px-4 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID Заказа</th>
                <th className="px-4 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Клиент</th>
                <th className="px-4 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
