                        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-2">
                          {item.players.map(p => (
                            <div key={p.id} className="text-[10px] bg-white p-2 rounded border border-gray-100">
                              <span className="font-bold text-indigo-600">#{p.number}</span> <span className="text-gray-800">{p.name}</span>
                              <div className="text-gray-400">{p.size}, {p.gender}, {p.sleeve}</div>
