export enum ProductType {
  TSHIRT = 'TSHIRT',
  HOODIE = 'HOODIE',
  CAP = 'CAP'
}

export enum OrderSubtype {
  SCHOOL = 'Школа',
  PERSONAL = 'Личный дизайн',
  TEAM = 'Команда'
}

export enum HoodieType {
  ZIP = 'На молнии с капюшоном',
  KANGAROO = 'Кенгуру с капюшоном',
  SWEATER = 'Свитер без капюшона'
}

export enum CapType {
  BASEBALL = 'Бейсболка',
  BEANIE = 'Шапка-бини',
  SNAPBACK = 'Снэпбек'
}

export type OrderStatus = 'New' | 'Processing' | 'Completed' | 'Cancelled';

export interface Player {
  id: string;
  name: string;
  number: string;
  gender: 'Мальчик' | 'Девочка';
  sleeve: string;
  size: string;
}

export interface OrderItem {
  id: string;
  type: ProductType;
  subtype: OrderSubtype;
  school?: string;
  printPlaces: string[];
  images: string[]; // Base64 or URLs
  players?: Player[];
  hoodieType?: HoodieType;
  capType?: CapType;
  gender?: 'Мальчик' | 'Девочка' | 'Универсальный';
  sleeve?: string;
  size: string;
  color: string;
  quantity: number;
}

export interface CustomerData {
  name: string;
  phone: string;
  email: string;
  address?: string;
  comments?: string;
}

export interface Order {
  orderNumber: string;
  customer: CustomerData;
  items: OrderItem[];
  createdAt: string;
  status: OrderStatus;
  internalNotes?: string;
}

import React, { useState, useEffect } from 'react';
import { ProductType, OrderItem, CustomerData, Order } from './types';
import { Button } from './components/ui/Button';
import { OrderForm } from './components/OrderForm';
import { CartView } from './components/CartView';
import { CustomerInfo } from './components/CustomerInfo';
import { AdminDashboard } from './components/AdminDashboard';
import { generateOrderSummaryDescription } from './services/geminiService';
import axios from 'axios';

enum Step {
  SELECT_PRODUCT,
  CONFIGURE,
  CHECKOUT,
  SUCCESS,
  ERROR,
  ADMIN
}

const API_URL = 'http://localhost:3001/api'; // Change this when deploying

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.SELECT_PRODUCT);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [activeType, setActiveType] = useState<ProductType | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [orderId, setOrderId] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>('');

  const selectProduct = (type: ProductType) => {
    setActiveType(type);
    setStep(Step.CONFIGURE);
  };

  const addToCart = (item: OrderItem) => {
    setCart(prev => [...prev, item]);
    setStep(Step.SELECT_PRODUCT);
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const submitOrder = async (data: CustomerData) => {
    setCustomer(data);
    setIsSubmitting(true);

    const newOrderId = `ORD-${Date.now()}`;
    setOrderId(newOrderId);

    const fullOrder: Order = {
      orderNumber: newOrderId,
      customer: data,
      items: cart,
      createdAt: new Date().toISOString(),
      status: 'New'
    };

    try {
      // 1. Send to Backend
      await axios.post(`${API_URL}/orders`, fullOrder);

      // 2. Get AI Summary for Success Screen (Parallel or after)
      const summary = await generateOrderSummaryDescription(fullOrder);
      setAiSummary(summary);

      setStep(Step.SUCCESS);
    } catch (error) {
      console.error("Order submission failed:", error);
      setErrorMessage("Произошла ошибка при отправке заказа. Пожалуйста, попробуйте еще раз или свяжитесь с нами через WhatsApp.");
      setStep(Step.ERROR);
    } finally {
      setIsSubmitting(false);
    }
  };

  const reset = () => {
    setCart([]);
    setStep(Step.SELECT_PRODUCT);
    setCustomer(null);
    setErrorMessage('');
  };

  const toggleAdmin = () => {
    if (step === Step.ADMIN) {
      setStep(Step.SELECT_PRODUCT);
    } else {
      setStep(Step.ADMIN);
    }
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="gradient-bg text-white py-12 px-6 shadow-xl mb-12">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div>
             <h1 className="text-4xl font-black tracking-tight cursor-pointer" onClick={() => setStep(Step.SELECT_PRODUCT)}>PRINTMASTER PRO</h1>
             <p className="text-indigo-100 mt-2 font-medium">Ваша индивидуальная печать на одежде</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:block bg-white/20 px-6 py-3 rounded-2xl backdrop-blur-md">
              <p className="text-sm font-bold">WhatsApp: +7 (900) 123-45-67</p>
            </div>
            <button 
              onClick={toggleAdmin}
              className="bg-white/10 hover:bg-white/30 p-2 rounded-xl transition-all"
              title="Панель управления"
            >
              {step === Step.ADMIN ? '🏠' : '⚙️'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">

        {step === Step.SELECT_PRODUCT && (
          <div className="space-y-12 animate-in fade-in duration-700">
            <h2 className="text-3xl font-bold text-center text-gray-800">Что будем печатать сегодня?</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <ProductCard 
                title="Футболка" 
                icon="👕" 
                desc="3 варианта заказа: Школа, Личный дизайн, Команда"
                onClick={() => selectProduct(ProductType.TSHIRT)}
              />
              <ProductCard 
                title="Худи" 
                icon="🧥" 
                desc="На молнии, кенгуру или свитер. Школа или Личный дизайн"
                onClick={() => selectProduct(ProductType.HOODIE)}
              />
              <ProductCard 
                title="Шапка" 
                icon="🧢" 
                desc="3 типа шапок. Только личный дизайн"
                onClick={() => selectProduct(ProductType.CAP)}
              />
            </div>

            <CartView items={cart} onRemove={removeItem} onNext={() => setStep(Step.CHECKOUT)} />
          </div>
        )}

        {step === Step.CONFIGURE && activeType && (
          <OrderForm 
            productType={activeType} 
            onAddToCart={addToCart} 
            onCancel={() => setStep(Step.SELECT_PRODUCT)}
          />
        )}

        {step === Step.CHECKOUT && (
          <CustomerInfo 
            onSubmit={submitOrder} 
            onBack={() => setStep(Step.SELECT_PRODUCT)}
          />
        )}

        {step === Step.ADMIN && (
          <AdminDashboard />
        )}

        {step === Step.SUCCESS && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-green-500">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Заказ отправлен!</h2>
            <p className="text-gray-500 mb-2">Ваш номер заказа:</p>
            <p className="text-2xl font-mono font-bold text-indigo-600 bg-indigo-50 inline-block px-4 py-2 rounded-xl mb-6">{orderId}</p>

            <div className="bg-gray-50 p-6 rounded-2xl mb-8 text-left border border-gray-100 italic">
               <p className="text-gray-700 leading-relaxed">{aiSummary}</p>
            </div>

            <div className="space-y-4">
              <p className="text-sm text-gray-500">Мы скоро свяжемся с вами в WhatsApp для подтверждения макета.</p>
              <Button onClick={reset} variant="primary" fullWidth>Создать новый заказ</Button>
            </div>
          </div>
        )}

        {step === Step.ERROR && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-red-500">
            <div className="w-20 h-20 bg-red-100 text-red-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✕</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Упс! Что-то пошло не так</h2>
            <p className="text-gray-600 mb-8">{errorMessage}</p>
            <div className="flex gap-4">
              <Button onClick={() => setStep(Step.CHECKOUT)} variant="outline" fullWidth>Вернуться к оформлению</Button>
              <Button onClick={() => window.open('https://wa.me/79001234567', '_blank')} variant="primary" fullWidth>Связаться в WhatsApp</Button>
            </div>
          </div>
        )}
      </main>

      {isSubmitting && (
        <div className="fixed inset-0 bg-white/80 backdrop-blur-sm flex flex-col items-center justify-center z-50">
          <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-xl font-bold text-indigo-800">Отправляем ваш заказ...</p>
          <p className="text-gray-500 mt-2">Генерируем PDF и создаем карточку в Trello</p>
        </div>
      )}
    </div>
  );
};

const ProductCard: React.FC<{title: string, icon: string, desc: string, onClick: () => void}> = ({ title, icon, desc, onClick }) => (
  <div 
    onClick={onClick}
    className="bg-white rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center"
  >
    <div className="text-7xl mb-6 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-2xl font-bold text-gray-800 mb-2">{title}</h3>
    <p className="text-gray-500 text-sm leading-relaxed">{desc}</p>
    <div className="mt-6">
       <span className="inline-block bg-indigo-50 text-indigo-600 font-bold px-4 py-2 rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-colors">Выбрать</span>
    </div>
  </div>
);

export default App;

import express from 'express';
import cors from 'cors';
import { generateOrderPDF } from './services/pdfService';
import { sendOrderEmail } from './services/emailService';
import { createTrelloCard } from './services/trelloService';
import { Order } from './types';

const app = express();
const PORT = process.env.PORT || 3001;

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Simple in-memory storage for order history
const ordersHistory: Order[] = [];

app.post('/api/orders', async (req, res) => {
  const orderData: Order = req.body;

  try {
    console.log(`Processing order: ${orderData.orderNumber}`);

    // Set initial status if not present
    orderData.status = orderData.status || 'New';

    // Save to local history
    ordersHistory.push(orderData);

    // 1. Generate PDF buffer
    const pdfBuffer = await generateOrderPDF(orderData);

    // 2. Send Email with PDF attachment
    await sendOrderEmail(orderData, pdfBuffer);

    // 3. Create Trello Card
    await createTrelloCard(orderData);

    res.status(200).json({ 
      success: true, 
      message: 'Order processed successfully',
      orderNumber: orderData.orderNumber 
    });
  } catch (error) {
    console.error('Order processing failed:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Internal server error during order processing' 
    });
  }
});

// Admin endpoint to get all orders
app.get('/api/orders', (req, res) => {
  res.status(200).json(ordersHistory);
});

// Admin endpoint to update order data (status, notes, etc)
app.patch('/api/orders/:orderNumber', (req, res) => {
  const { orderNumber } = req.params;
  const updateData = req.body;

  const orderIndex = ordersHistory.findIndex(o => o.orderNumber === orderNumber);
  if (orderIndex > -1) {
    ordersHistory[orderIndex] = { ...ordersHistory[orderIndex], ...updateData };
    return res.status(200).json(ordersHistory[orderIndex]);
  }

  res.status(404).json({ message: 'Order not found' });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Order, OrderStatus, OrderItem } from '../types';
import { Button } from './ui/Button';

const API_URL = 'http://localhost:3001/api';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const response = await axios.get(`${API_URL}/orders`);
      setOrders(response.data);
    } catch (error) {
      console.error("Failed to fetch orders:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const response = await axios.patch(`${API_URL}/orders/${orderNumber}`, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return response.data;
    } catch (error) {
      console.error("Failed to update order:", error);
      throw error;
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <div className="flex flex-wrap gap-3 w-full md:w-auto">
          <input 
            type="text" 
            placeholder="Поиск..."
            className="flex-1 md:w-64 p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
          <select 
            className="p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none cursor-pointer text-sm"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
          <Button onClick={fetchOrders} variant="outline" size="sm">🔄</Button>
        </div>
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация с сервером...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Действия</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredOrders.map((order) => (
                <tr key={order.orderNumber} className="hover:bg-indigo-50/30 transition-colors group">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                    {new Date(order.createdAt).toLocaleDateString()}
                    <div className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="font-mono text-[10px] font-bold text-indigo-500">
                      {order.orderNumber.split('-')[1]}
                    </span>
                    {order.internalNotes && (
                      <span className="ml-2 inline-block w-2 h-2 rounded-full bg-amber-400 shadow-sm" title="Есть внутренняя заметка"></span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm font-bold text-gray-800">{order.customer.name}</div>
                    <div className="text-[10px] text-gray-400">{order.customer.phone}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex -space-x-2">
                      {order.items.slice(0, 3).map((item, idx) => (
                        <div key={idx} className="w-8 h-8 rounded-full bg-white border-2 border-gray-100 flex items-center justify-center text-sm shadow-sm" title={item.type}>
                          {item.type === 'TSHIRT' ? '👕' : item.type === 'HOODIE' ? '🧥' : '🧢'}
                        </div>
                      ))}
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <select 
                      className={`text-xs font-bold rounded-full px-3 py-1 outline-none appearance-none cursor-pointer border-none ${getStatusColor(order.status)}`}
                      value={order.status}
                      onChange={(e) => updateOrderData(order.orderNumber, { status: e.target.value as OrderStatus })}
                    >
                      {Object.entries(STATUS_LABELS).map(([key, label]) => (
                        <option key={key} value={key}>{label}</option>
                      ))}
                    </select>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <button 
                      onClick={() => setSelectedOrder(order)}
                      className="p-2 text-indigo-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      👁️
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Detail Modal */}
      {selectedOrder && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <div>
                <h3 className="text-xl font-bold text-gray-800">Детали заказа {selectedOrder.orderNumber}</h3>
                <p className="text-sm text-gray-500">{new Date(selectedOrder.createdAt).toLocaleString()}</p>
              </div>
              <button onClick={() => setSelectedOrder(null)} className="text-gray-400 hover:text-gray-600 text-2xl">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-8">
              {/* Customer Info Box */}
              <div className="grid md:grid-cols-2 gap-6 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Клиент</h4>
                  <p className="font-bold text-gray-800">{selectedOrder.customer.name}</p>
                  <p className="text-sm text-gray-600">{selectedOrder.customer.email}</p>
                  <p className="text-sm text-gray-600">{selectedOrder.customer.phone}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Доставка</h4>
                  <p className="text-sm text-gray-700"><strong>Адрес:</strong> {selectedOrder.customer.address || 'Не указан'}</p>
                  <p className="text-sm text-gray-700 mt-1"><strong>Заметка:</strong> {selectedOrder.customer.comments || 'Нет'}</p>
                </div>
              </div>

              {/* Internal Notes */}
              <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-600 uppercase tracking-wider mb-2">📝 Внутренние заметки</h4>
                <textarea 
                  className="w-full p-4 bg-white border border-amber-200 rounded-xl outline-none focus:ring-2 ring-amber-400 text-sm h-24 resize-none"
                  value={editingNotes}
                  onChange={(e) => setEditingNotes(e.target.value)}
                />
                <div className="mt-2 flex justify-end">
                   <Button 
                    size="sm" 
                    variant="primary" 
                    className="bg-amber-600 hover:bg-amber-700" 
                    onClick={handleSaveNotes}
                    disabled={isSavingNotes || editingNotes === (selectedOrder.internalNotes || '')}
                  >
                    {isSavingNotes ? 'Сохранение...' : 'Сохранить заметку'}
                  </Button>
                </div>
              </div>

              {/* Items List */}
              <div className="space-y-6">
                {selectedOrder.items.map((item, idx) => (
                  <div key={idx} className="border border-gray-100 rounded-2xl p-5">
                    <div className="flex justify-between items-start">
                      <div className="flex gap-4">
                        <div className="w-12 h-12 bg-gray-50 rounded-xl flex items-center justify-center text-2xl">
                          {item.type === 'TSHIRT' ? '👕' : item.type === 'HOODIE' ? '🧥' : '🧢'}
                        </div>
                        <div>
                          <p className="font-bold text-gray-800">{item.type} — {item.subtype}</p>
                          <p className="text-xs text-indigo-500 font-bold uppercase">{item.color} • {item.size} • x{item.quantity}</p>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="p-6 border-t border-gray-100 flex justify-end gap-3 bg-gray-50">
              <Button onClick={() => setSelectedOrder(null)} variant="outline">Закрыть</Button>
              <select 
                className={`text-sm font-bold rounded-xl px-4 py-2 outline-none border border-gray-200 ${getStatusColor(selectedOrder.status)}`}
                value={selectedOrder.status}
                onChange={(e) => updateOrderData(selectedOrder.orderNumber, { status: e.target.value as OrderStatus })}
              >
                {Object.entries(STATUS_LABELS).map(([key, label]) => (
                  <option key={key} value={key}>{label}</option>
                ))}
              </select>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export enum ProductType {
  TSHIRT = 'TSHIRT',
  HOODIE = 'HOODIE',
  CAP = 'CAP'
}

export enum OrderSubtype {
  SCHOOL = 'Школа',
  PERSONAL = 'Личный дизайн',
  TEAM = 'Команда'
}

export enum HoodieType {
  ZIP = 'На молнии с капюшоном',
  KANGAROO = 'Кенгуру с капюшоном',
  SWEATER = 'Свитер без капюшона'
}

export enum CapType {
  BASEBALL = 'Бейсболка',
  BEANIE = 'Шапка-бини',
  SNAPBACK = 'Снэпбек'
}

export type OrderStatus = 'New' | 'Processing' | 'Completed' | 'Cancelled';

export interface Player {
  id: string;
  name: string;
  number: string;
  gender: 'Мальчик' | 'Девочка';
  sleeve: string;
  size: string;
}

export interface OrderItem {
  id: string;
  type: ProductType;
  subtype: OrderSubtype;
  school?: string;
  printPlaces: string[];
  images: string[]; // Base64 or URLs
  players?: Player[];
  hoodieType?: HoodieType;
  capType?: CapType;
  gender?: 'Мальчик' | 'Девочка' | 'Универсальный';
  sleeve?: string;
  size: string;
  color: string;
  quantity: number;
}

export interface CustomerData {
  name: string;
  phone: string;
  email: string;
  address?: string;
  comments?: string;
}

export interface Order {
  orderNumber: string;
  customer: CustomerData;
  items: OrderItem[];
  createdAt: string;
  status: OrderStatus;
  internalNotes?: string;
}

import React, { useState, useEffect } from 'react';
import { ProductType, OrderItem, CustomerData, Order } from './types';
import { Button } from './components/ui/Button';
import { OrderForm } from './components/OrderForm';
import { CartView } from './components/CartView';
import { CustomerInfo } from './components/CustomerInfo';
import { AdminDashboard } from './components/AdminDashboard';
import { generateOrderSummaryDescription } from './services/geminiService';
import axios from 'axios';

enum Step {
  SELECT_PRODUCT,
  CONFIGURE,
  CHECKOUT,
  SUCCESS,
  ERROR,
  ADMIN
}

const API_URL = 'http://localhost:3001/api'; // Change this when deploying

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.SELECT_PRODUCT);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [activeType, setActiveType] = useState<ProductType | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [orderId, setOrderId] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>('');

  const selectProduct = (type: ProductType) => {
    setActiveType(type);
    setStep(Step.CONFIGURE);
  };

  const addToCart = (item: OrderItem) => {
    setCart(prev => [...prev, item]);
    setStep(Step.SELECT_PRODUCT);
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const submitOrder = async (data: CustomerData) => {
    setCustomer(data);
    setIsSubmitting(true);

    const newOrderId = `ORD-${Date.now()}`;
    setOrderId(newOrderId);

    const fullOrder: Order = {
      orderNumber: newOrderId,
      customer: data,
      items: cart,
      createdAt: new Date().toISOString(),
      status: 'New' // Initial value as requested
    };

    try {
      // 1. Send to Backend
      await axios.post(`${API_URL}/orders`, fullOrder);

      // 2. Get AI Summary for Success Screen (Parallel or after)
      const summary = await generateOrderSummaryDescription(fullOrder);
      setAiSummary(summary);

      setStep(Step.SUCCESS);
    } catch (error) {
      console.error("Order submission failed:", error);
      setErrorMessage("Произошла ошибка при отправке заказа. Пожалуйста, попробуйте еще раз или свяжитесь с нами через WhatsApp.");
      setStep(Step.ERROR);
    } finally {
      setIsSubmitting(false);
    }
  };

  const reset = () => {
    setCart([]);
    setStep(Step.SELECT_PRODUCT);
    setCustomer(null);
    setErrorMessage('');
  };

  const toggleAdmin = () => {
    if (step === Step.ADMIN) {
      setStep(Step.SELECT_PRODUCT);
    } else {
      setStep(Step.ADMIN);
    }
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="gradient-bg text-white py-12 px-6 shadow-xl mb-12">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div>
             <h1 className="text-4xl font-black tracking-tight cursor-pointer" onClick={() => setStep(Step.SELECT_PRODUCT)}>PRINTMASTER PRO</h1>
             <p className="text-indigo-100 mt-2 font-medium">Ваша индивидуальная печать на одежде</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:block bg-white/20 px-6 py-3 rounded-2xl backdrop-blur-md">
              <p className="text-sm font-bold">WhatsApp: +7 (900) 123-45-67</p>
            </div>
            <button 
              onClick={toggleAdmin}
              className="bg-white/10 hover:bg-white/30 p-2 rounded-xl transition-all"
              title="Панель управления"
            >
              {step === Step.ADMIN ? '🏠' : '⚙️'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">

        {step === Step.SELECT_PRODUCT && (
          <div className="space-y-12 animate-in fade-in duration-700">
            <h2 className="text-3xl font-bold text-center text-gray-800">Что будем печатать сегодня?</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <ProductCard 
                title="Футболка" 
                icon="👕" 
                desc="3 варианта заказа: Школа, Личный дизайн, Команда"
                onClick={() => selectProduct(ProductType.TSHIRT)}
              />
              <ProductCard 
                title="Худи" 
                icon="🧥" 
                desc="На молнии, кенгуру или свитер. Школа или Личный дизайн"
                onClick={() => selectProduct(ProductType.HOODIE)}
              />
              <ProductCard 
                title="Шапка" 
                icon="🧢" 
                desc="3 типа шапок. Только личный дизайн"
                onClick={() => selectProduct(ProductType.CAP)}
              />
            </div>

            <CartView items={cart} onRemove={removeItem} onNext={() => setStep(Step.CHECKOUT)} />
          </div>
        )}

        {step === Step.CONFIGURE && activeType && (
          <OrderForm 
            productType={activeType} 
            onAddToCart={addToCart} 
            onCancel={() => setStep(Step.SELECT_PRODUCT)}
          />
        )}

        {step === Step.CHECKOUT && (
          <CustomerInfo 
            onSubmit={submitOrder} 
            onBack={() => setStep(Step.SELECT_PRODUCT)}
          />
        )}

        {step === Step.ADMIN && (
          <AdminDashboard />
        )}

        {step === Step.SUCCESS && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-green-500">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Заказ отправлен!</h2>
            <div className="flex flex-col items-center gap-2 mb-6">
               <p className="text-gray-500">Номер заказа:</p>
               <p className="text-2xl font-mono font-bold text-indigo-600 bg-indigo-50 inline-block px-4 py-2 rounded-xl">{orderId}</p>
               <span className="text-xs bg-blue-100 text-blue-700 font-bold px-2 py-1 rounded-full uppercase tracking-wider">Статус: Новый</span>
            </div>

            <div className="bg-gray-50 p-6 rounded-2xl mb-8 text-left border border-gray-100 italic">
               <p className="text-gray-700 leading-relaxed">{aiSummary}</p>
            </div>

            <div className="space-y-4">
              <p className="text-sm text-gray-500">Мы скоро свяжемся с вами в WhatsApp для подтверждения макета.</p>
              <Button onClick={reset} variant="primary" fullWidth>Создать новый заказ</Button>
            </div>
          </div>
        )}

        {step === Step.ERROR && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-red-500">
            <div className="w-20 h-20 bg-red-100 text-red-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✕</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Упс! Что-то пошло не так</h2>
            <p className="text-gray-600 mb-8">{errorMessage}</p>
            <div className="flex gap-4">
              <Button onClick={() => setStep(Step.CHECKOUT)} variant="outline" fullWidth>Вернуться к оформлению</Button>
              <Button onClick={() => window.open('https://wa.me/79001234567', '_blank')} variant="primary" fullWidth>Связаться в WhatsApp</Button>
            </div>
          </div>
        )}
      </main>

      {isSubmitting && (
        <div className="fixed inset-0 bg-white/80 backdrop-blur-sm flex flex-col items-center justify-center z-50">
          <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-xl font-bold text-indigo-800">Отправляем ваш заказ...</p>
          <p className="text-gray-500 mt-2">Генерируем PDF и создаем карточку в Trello</p>
        </div>
      )}
    </div>
  );
};

