import express from 'express';
import cors from 'cors';
import { generateOrderPDF } from './services/pdfService';
import { sendOrderEmail } from './services/emailService';
import { createTrelloCard } from './services/trelloService';
import { Order } from './types';

const app = express();
const PORT = process.env.PORT || 3001;

// In a real app, this should be an environment variable
const ADMIN_PASSWORD = process.env.ADMIN_PASSWORD || 'admin123';

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Simple in-memory storage for order history
const ordersHistory: Order[] = [];

// Login endpoint
app.post('/api/login', (req, res) => {
  const { password } = req.body;
  if (password === ADMIN_PASSWORD) {
    return res.status(200).json({ success: true, token: 'mock-jwt-token' });
  }
  res.status(401).json({ success: false, message: 'Неверный пароль' });
});

app.post('/api/orders', async (req, res) => {
  const orderData: Order = req.body;

  try {
    console.log(`Processing order: ${orderData.orderNumber}`);

    // Set initial status if not present
    orderData.status = orderData.status || 'New';
    // Initialize viewed state
    orderData.viewed = false;

    // Save to local history
    ordersHistory.push(orderData);

    // 1. Generate PDF buffer
    const pdfBuffer = await generateOrderPDF(orderData);

    // 2. Send Email with PDF attachment
    await sendOrderEmail(orderData, pdfBuffer);

    // 3. Create Trello Card
    await createTrelloCard(orderData);

    res.status(200).json({ 
      success: true, 
      message: 'Order processed successfully',
      orderNumber: orderData.orderNumber 
    });
  } catch (error) {
    console.error('Order processing failed:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Internal server error during order processing' 
    });
  }
});

// Admin endpoint to get all orders
app.get('/api/orders', (req, res) => {
  res.status(200).json(ordersHistory);
});

// Admin endpoint to update order data (status, notes, etc)
app.patch('/api/orders/:orderNumber', (req, res) => {
  const { orderNumber } = req.params;
  const updateData = req.body;

  const orderIndex = ordersHistory.findIndex(o => o.orderNumber === orderNumber);
  if (orderIndex > -1) {
    ordersHistory[orderIndex] = { ...ordersHistory[orderIndex], ...updateData };
    return res.status(200).json(ordersHistory[orderIndex]);
  }

  res.status(404).json({ message: 'Order not found' });
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});

import axios from 'axios';
import { Order } from '../types';

const API_URL = 'http://localhost:3001/api';
const LOCAL_STORAGE_KEY = 'printmaster_orders_backup';

export const apiService = {
  /**
   * Simple login method
   */
  login: async (password: string): Promise<boolean> => {
    try {
      const response = await axios.post(`${API_URL}/login`, { password }, { timeout: 2000 });
      return response.data.success === true;
    } catch (error) {
      // Offline fallback: if server is down, allow "admin123" locally for preview purposes
      console.warn("Auth server unreachable. Using local validation for preview.");
      return password === 'admin123';
    }
  },

  getOrders: async (): Promise<Order[]> => {
    let remoteOrders: Order[] = [];
    try {
      const response = await axios.get(`${API_URL}/orders`, { timeout: 2000 });
      remoteOrders = response.data;
    } catch (error) {
      console.warn("Backend unreachable. Operating in Local Mode.");
    }

    const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
    const localOrders: Order[] = localData ? JSON.parse(localData) : [];

    const orderMap = new Map<string, Order>();
    remoteOrders.forEach(o => orderMap.set(o.orderNumber, o));
    localOrders.forEach(o => orderMap.set(o.orderNumber, o));

    return Array.from(orderMap.values()).sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  },

  submitOrder: async (order: Order): Promise<void> => {
    const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
    const localOrders: Order[] = localData ? JSON.parse(localData) : [];
    localOrders.push(order);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(localOrders));

    try {
      await axios.post(`${API_URL}/orders`, order, { timeout: 3000 });
    } catch (error) {
      console.warn("Order saved locally, but server sync failed.");
    }
  },

  updateOrder: async (orderNumber: string, data: Partial<Order>): Promise<Order> => {
    const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
    let localOrders: Order[] = localData ? JSON.parse(localData) : [];

    let updatedOrder: Order | null = null;
    localOrders = localOrders.map(o => {
      if (o.orderNumber === orderNumber) {
        updatedOrder = { ...o, ...data };
        return updatedOrder;
      }
      return o;
    });

    if (updatedOrder) {
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(localOrders));
    }

    try {
      const response = await axios.patch(`${API_URL}/orders/${orderNumber}`, data, { timeout: 2000 });
      return response.data;
    } catch (error) {
      console.warn("Order updated locally, but server sync failed.");
      if (!updatedOrder) throw new Error("Order not found in local storage.");
      return updatedOrder;
    }
  }
};

import React, { useState } from 'react';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

interface AdminLoginProps {
  onLoginSuccess: () => void;
}

export const AdminLogin: React.FC<AdminLoginProps> = ({ onLoginSuccess }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const success = await apiService.login(password);
      if (success) {
        sessionStorage.setItem('isAdminAuthenticated', 'true');
        onLoginSuccess();
      } else {
        setError('Неверный пароль доступа');
      }
    } catch (err) {
      setError('Ошибка при авторизации. Попробуйте снова.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center py-20 px-4 animate-in fade-in zoom-in duration-300">
      <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 max-w-sm w-full">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">🔐</div>
          <h2 className="text-2xl font-black text-gray-800">Вход для админа</h2>
          <p className="text-gray-500 text-sm mt-2">Введите пароль для доступа к заказам</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Пароль</label>
            <input 
              type="password" 
              className={`w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 ring-indigo-400 transition-all ${error ? 'border-red-400' : 'border-gray-200'}`}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              autoFocus
            />
            {error && <p className="text-red-500 text-xs mt-2 ml-1 font-medium">{error}</p>}
          </div>

          <Button 
            variant="primary" 
            fullWidth 
            type="submit" 
            disabled={loading || !password}
          >
            {loading ? 'Проверка...' : 'Войти в панель'}
          </Button>

          <p className="text-center text-[10px] text-gray-400 uppercase tracking-widest">
            PrintMaster Pro Security
          </p>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ProductType, OrderItem, CustomerData, Order } from './types';
import { Button } from './components/ui/Button';
import { OrderForm } from './components/OrderForm';
import { CartView } from './components/CartView';
import { CustomerInfo } from './components/CustomerInfo';
import { AdminDashboard } from './components/AdminDashboard';
import { AdminLogin } from './components/AdminLogin';
import { generateOrderSummaryDescription } from './services/geminiService';
import { apiService } from './services/apiService';

enum Step {
  SELECT_PRODUCT,
  CONFIGURE,
  CHECKOUT,
  SUCCESS,
  ERROR,
  ADMIN
}

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.SELECT_PRODUCT);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [activeType, setActiveType] = useState<ProductType | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [orderId, setOrderId] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);

  useEffect(() => {
    const authStatus = sessionStorage.getItem('isAdminAuthenticated') === 'true';
    setIsAdminAuthenticated(authStatus);
  }, []);

  const selectProduct = (type: ProductType) => {
    setActiveType(type);
    setStep(Step.CONFIGURE);
  };

  const addToCart = (item: OrderItem) => {
    setCart(prev => [...prev, item]);
    setStep(Step.SELECT_PRODUCT);
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const submitOrder = async (data: CustomerData) => {
    setCustomer(data);
    setIsSubmitting(true);

    const newOrderId = `ORD-${Date.now()}`;
    setOrderId(newOrderId);

    const fullOrder: Order = {
      orderNumber: newOrderId,
      customer: data,
      items: cart,
      createdAt: new Date().toISOString(),
      status: 'New',
      viewed: false
    };

    try {
      await apiService.submitOrder(fullOrder);
      const summary = await generateOrderSummaryDescription(fullOrder);
      setAiSummary(summary);
      setStep(Step.SUCCESS);
    } catch (error) {
      console.error("Order submission failed:", error);
      setErrorMessage("Произошла ошибка при отправке заказа.");
      setStep(Step.ERROR);
    } finally {
      setIsSubmitting(false);
    }
  };

  const reset = () => {
    setCart([]);
    setStep(Step.SELECT_PRODUCT);
    setCustomer(null);
    setErrorMessage('');
  };

  const toggleAdmin = () => {
    setStep(prev => prev === Step.ADMIN ? Step.SELECT_PRODUCT : Step.ADMIN);
  };

  const handleLoginSuccess = () => {
    setIsAdminAuthenticated(true);
  };

  return (
    <div className="min-h-screen pb-12">
      <header className="gradient-bg text-white py-12 px-6 shadow-xl mb-12">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div>
             <h1 className="text-4xl font-black tracking-tight cursor-pointer" onClick={() => setStep(Step.SELECT_PRODUCT)}>PRINTMASTER PRO</h1>
             <p className="text-indigo-100 mt-2 font-medium">Ваша индивидуальная печать на одежде</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:block bg-white/20 px-6 py-3 rounded-2xl backdrop-blur-md">
              <p className="text-sm font-bold">WhatsApp: +7 (900) 123-45-67</p>
            </div>
            <button 
              onClick={toggleAdmin}
              className={`p-2 rounded-xl transition-all ${step === Step.ADMIN ? 'bg-white text-indigo-600' : 'bg-white/10 hover:bg-white/30 text-white'}`}
              title="Панель управления"
            >
              {step === Step.ADMIN ? '🏠' : '⚙️'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">

        {step === Step.SELECT_PRODUCT && (
          <div className="space-y-12 animate-in fade-in duration-700">
            <h2 className="text-3xl font-bold text-center text-gray-800">Что будем печатать сегодня?</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <ProductCard title="Футболка" icon="👕" desc="Школа, Личный дизайн, Команда" onClick={() => selectProduct(ProductType.TSHIRT)} />
              <ProductCard title="Худи" icon="🧥" desc="3 модели. Школа или Личный дизайн" onClick={() => selectProduct(ProductType.HOODIE)} />
              <ProductCard title="Шапка" icon="🧢" desc="3 типа. Личный дизайн" onClick={() => selectProduct(ProductType.CAP)} />
            </div>
            <CartView items={cart} onRemove={removeItem} onNext={() => setStep(Step.CHECKOUT)} />
          </div>
        )}

        {step === Step.CONFIGURE && activeType && (
          <OrderForm productType={activeType} onAddToCart={addToCart} onCancel={() => setStep(Step.SELECT_PRODUCT)} />
        )}

        {step === Step.CHECKOUT && (
          <CustomerInfo onSubmit={submitOrder} onBack={() => setStep(Step.SELECT_PRODUCT)} />
        )}

        {step === Step.ADMIN && (
          isAdminAuthenticated ? <AdminDashboard /> : <AdminLogin onLoginSuccess={handleLoginSuccess} />
        )}

        {step === Step.SUCCESS && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-green-500">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Заказ отправлен!</h2>
            <div className="flex flex-col items-center gap-2 mb-6">
               <p className="text-gray-500">Номер заказа:</p>
               <p className="text-2xl font-mono font-bold text-indigo-600 bg-indigo-50 inline-block px-4 py-2 rounded-xl">{orderId}</p>
            </div>
            <div className="bg-gray-50 p-6 rounded-2xl mb-8 text-left border border-gray-100 italic"><p className="text-gray-700 leading-relaxed">{aiSummary}</p></div>
            <Button onClick={reset} variant="primary" fullWidth>Создать новый заказ</Button>
          </div>
        )}

        {step === Step.ERROR && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-red-500">
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Ошибка</h2>
            <p className="text-gray-600 mb-8">{errorMessage}</p>
            <Button onClick={() => setStep(Step.CHECKOUT)} variant="outline" fullWidth>Назад</Button>
          </div>
        )}
      </main>
    </div>
  );
};

const ProductCard: React.FC<{title: string, icon: string, desc: string, onClick: () => void}> = ({ title, icon, desc, onClick }) => (
  <div onClick={onClick} className="bg-white rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center">
    <div className="text-7xl mb-6 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-2xl font-bold text-gray-800 mb-2">{title}</h3>
    <p className="text-gray-500 text-sm">{desc}</p>
  </div>
);

export default App;

import React, { useState, useEffect } from 'react';
import { ProductType, OrderSubtype, OrderItem, CustomerData, Order } from './types';
import { Button } from './components/ui/Button';
import { OrderForm } from './components/OrderForm';
import { CartView } from './components/CartView';
import { CustomerInfo } from './components/CustomerInfo';
import { AdminDashboard } from './components/AdminDashboard';
import { AdminLogin } from './components/AdminLogin';
import { generateOrderSummaryDescription } from './services/geminiService';
import { apiService } from './services/apiService';

enum Step {
  SELECT_CATEGORY,
  SELECT_PRODUCT,
  CONFIGURE,
  CHECKOUT,
  SUCCESS,
  ERROR,
  ADMIN
}

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.SELECT_CATEGORY);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<OrderSubtype | null>(null);
  const [activeType, setActiveType] = useState<ProductType | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [orderId, setOrderId] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);

  useEffect(() => {
    const authStatus = sessionStorage.getItem('isAdminAuthenticated') === 'true';
    setIsAdminAuthenticated(authStatus);
  }, []);

  const selectCategory = (category: OrderSubtype) => {
    setActiveCategory(category);
    setStep(Step.SELECT_PRODUCT);
  };

  const selectProduct = (type: ProductType) => {
    setActiveType(type);
    setStep(Step.CONFIGURE);
  };

  const addToCart = (item: OrderItem) => {
    setCart(prev => [...prev, item]);
    setStep(Step.SELECT_CATEGORY);
    setActiveCategory(null);
    setActiveType(null);
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const submitOrder = async (data: CustomerData) => {
    setCustomer(data);
    setIsSubmitting(true);

    const newOrderId = `ORD-${Date.now()}`;
    setOrderId(newOrderId);

    const fullOrder: Order = {
      orderNumber: newOrderId,
      customer: data,
      items: cart,
      createdAt: new Date().toISOString(),
      status: 'New',
      viewed: false
    };

    try {
      await apiService.submitOrder(fullOrder);
      const summary = await generateOrderSummaryDescription(fullOrder);
      setAiSummary(summary);
      setStep(Step.SUCCESS);
    } catch (error) {
      console.error("Order submission failed:", error);
      setErrorMessage("Произошла ошибка при отправке заказа.");
      setStep(Step.ERROR);
    } finally {
      setIsSubmitting(false);
    }
  };

  const reset = () => {
    setCart([]);
    setStep(Step.SELECT_CATEGORY);
    setActiveCategory(null);
    setActiveType(null);
    setCustomer(null);
    setErrorMessage('');
  };

  const toggleAdmin = () => {
    setStep(prev => prev === Step.ADMIN ? Step.SELECT_CATEGORY : Step.ADMIN);
  };

  const handleLoginSuccess = () => {
    setIsAdminAuthenticated(true);
  };

  return (
    <div className="min-h-screen pb-12">
      <header className="gradient-bg text-white py-12 px-6 shadow-xl mb-12">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div>
             <h1 className="text-4xl font-black tracking-tight cursor-pointer" onClick={() => setStep(Step.SELECT_CATEGORY)}>PRINTMASTER PRO</h1>
             <p className="text-indigo-100 mt-2 font-medium">Ваша индивидуальная печать на одежде</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:block bg-white/20 px-6 py-3 rounded-2xl backdrop-blur-md">
              <p className="text-sm font-bold">WhatsApp: +7 (900) 123-45-67</p>
            </div>
            <button 
              onClick={toggleAdmin}
              className={`p-2 rounded-xl transition-all ${step === Step.ADMIN ? 'bg-white text-indigo-600' : 'bg-white/10 hover:bg-white/30 text-white'}`}
              title="Панель управления"
            >
              {step === Step.ADMIN ? '🏠' : '⚙️'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">

        {step === Step.SELECT_CATEGORY && (
          <div className="space-y-12 animate-in fade-in duration-700">
            <h2 className="text-3xl font-bold text-center text-gray-800">Выберите тип заказа</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <SelectionCard 
                title="Школа" 
                icon="🏫" 
                desc="Выбор из библиотеки логотипов школ (100+). Печать спереди." 
                onClick={() => selectCategory(OrderSubtype.SCHOOL)} 
              />
              <SelectionCard 
                title="Команда" 
                icon="⚽" 
                desc="Дизайн для команд с таблицей игроков (имена, номера, размеры)." 
                onClick={() => selectCategory(OrderSubtype.TEAM)} 
              />
              <SelectionCard 
                title="Личный дизайн" 
                icon="🎨" 
                desc="Ваши изображения на футболках, худи или шапках." 
                onClick={() => selectCategory(OrderSubtype.PERSONAL)} 
              />
            </div>
            <CartView items={cart} onRemove={removeItem} onNext={() => setStep(Step.CHECKOUT)} />
          </div>
        )}

        {step === Step.SELECT_PRODUCT && activeCategory && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="text-center">
                <button onClick={() => setStep(Step.SELECT_CATEGORY)} className="text-indigo-600 font-bold hover:underline mb-4">← Назад к категориям</button>
                <h2 className="text-3xl font-bold text-gray-800">Что именно будем печатать?</h2>
                <p className="text-gray-500">Категория: {activeCategory}</p>
             </div>
             <div className="grid md:grid-cols-3 gap-8 max-w-4xl mx-auto">
                <ProductSmallCard 
                  title="Футболка" 
                  icon="👕" 
                  onClick={() => selectProduct(ProductType.TSHIRT)} 
                />
                {(activeCategory === OrderSubtype.SCHOOL || activeCategory === OrderSubtype.PERSONAL) && (
                  <ProductSmallCard 
                    title="Худи" 
                    icon="🧥" 
                    onClick={() => selectProduct(ProductType.HOODIE)} 
                  />
                )}
                {activeCategory === OrderSubtype.PERSONAL && (
                  <ProductSmallCard 
                    title="Шапка" 
                    icon="🧢" 
                    onClick={() => selectProduct(ProductType.CAP)} 
                  />
                )}
             </div>
          </div>
        )}

        {step === Step.CONFIGURE && activeType && activeCategory && (
          <OrderForm 
            productType={activeType} 
            initialSubtype={activeCategory}
            onAddToCart={addToCart} 
            onCancel={() => setStep(Step.SELECT_PRODUCT)} 
          />
        )}

        {step === Step.CHECKOUT && (
          <CustomerInfo onSubmit={submitOrder} onBack={() => setStep(Step.SELECT_CATEGORY)} />
        )}

        {step === Step.ADMIN && (
          isAdminAuthenticated ? <AdminDashboard /> : <AdminLogin onLoginSuccess={handleLoginSuccess} />
        )}

        {step === Step.SUCCESS && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-green-500">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Заказ отправлен!</h2>
            <div className="flex flex-col items-center gap-2 mb-6">
               <p className="text-gray-500">Номер заказа:</p>
               <p className="text-2xl font-mono font-bold text-indigo-600 bg-indigo-50 inline-block px-4 py-2 rounded-xl">{orderId}</p>
            </div>
            <div className="bg-gray-50 p-6 rounded-2xl mb-8 text-left border border-gray-100 italic"><p className="text-gray-700 leading-relaxed">{aiSummary}</p></div>
            <Button onClick={reset} variant="primary" fullWidth>Создать новый заказ</Button>
          </div>
        )}

        {step === Step.ERROR && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-red-500">
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Ошибка</h2>
            <p className="text-gray-600 mb-8">{errorMessage}</p>
            <Button onClick={() => setStep(Step.CHECKOUT)} variant="outline" fullWidth>Назад</Button>
          </div>
        )}
      </main>
    </div>
  );
};

const SelectionCard: React.FC<{title: string, icon: string, desc: string, onClick: () => void}> = ({ title, icon, desc, onClick }) => (
  <div onClick={onClick} className="bg-white rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center flex flex-col items-center">
    <div className="text-6xl mb-6 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-2xl font-bold text-gray-800 mb-2">{title}</h3>
    <p className="text-gray-500 text-sm leading-relaxed">{desc}</p>
    <div className="mt-auto pt-6 w-full">
       <span className="inline-block w-full bg-indigo-50 text-indigo-600 font-bold px-4 py-3 rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-colors">Выбрать</span>
    </div>
  </div>
);

const ProductSmallCard: React.FC<{title: string, icon: string, onClick: () => void}> = ({ title, icon, onClick }) => (
  <div onClick={onClick} className="bg-white rounded-2xl p-6 shadow-md hover:shadow-xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center">
    <div className="text-5xl mb-4 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-xl font-bold text-gray-800">{title}</h3>
  </div>
);

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [tips, setTips] = useState<string | null>(null);

  useEffect(() => {
    // Reset defaults based on type/subtype
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    }

    // Fetch AI tips
    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const readers = Array.from(files).map((file: File) => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      });
      Promise.all(readers).then(results => {
        setFormData(prev => ({ ...prev, images: [...(prev.images || []), ...results] }));
      });
    }
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const handleAdd = () => {
    onAddToCart({
      ...formData,
      id: Math.random().toString(36).substr(2, 9),
      type: productType,
      subtype: initialSubtype,
    } as OrderItem);
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : 'Шапка'}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {/* AI Tips */}
      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {/* Type specific fields */}
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-left rounded-xl border text-sm transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.capType}
              onChange={e => setFormData({ ...formData, capType: e.target.value as CapType })}
            >
              {Object.values(CapType).map(v => <option key={v} value={v}>{v}</option>)}
            </select>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <select 
              className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none"
              value={formData.school}
              onChange={e => setFormData({ ...formData, school: e.target.value })}
            >
              <option value="">-- Выбор из 100+ школ --</option>
              {SCHOOL_LIST.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {(productType === ProductType.CAP ? ['Спереди'] : PRINT_PLACES).map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Загрузить изображения</label>
              <div className="flex items-center gap-4">
                <input 
                  type="file" 
                  multiple 
                  onChange={handleImageUpload}
                  className="hidden" 
                  id="image-upload" 
                />
                <label 
                  htmlFor="image-upload" 
                  className="cursor-pointer bg-gray-100 hover:bg-gray-200 py-3 px-6 rounded-xl border-2 border-dashed border-gray-300 text-gray-500 text-sm font-medium flex items-center gap-2"
                >
                  📁 Выбрать файлы
                </label>
                <div className="flex -space-x-2 overflow-hidden">
                  {formData.images?.map((img, idx) => (
                    <img key={idx} src={img} className="inline-block h-8 w-8 rounded-full ring-2 ring-white object-cover" />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
          />
        )}

        {/* Global params: Color, Gender, Size, Qty */}
        {initialSubtype !== OrderSubtype.TEAM && (
          <div className="grid grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Цвет</label>
              <div className="flex flex-wrap gap-2">
                {COLORS.map(c => (
                  <button
                    key={c.hex}
                    onClick={() => setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all ${
                      formData.color === c.name ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            {productType !== ProductType.CAP && (
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
                <div className="flex gap-2">
                   {['Мальчик', 'Девочка'].map(g => (
                     <button
                       key={g}
                       onClick={() => setFormData({ ...formData, gender: g as any })}
                       className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                         formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                       }`}
                     >
                       {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                     </button>
                   ))}
                </div>
              </div>
            )}

            {productType === ProductType.TSHIRT && (
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
                <select 
                  className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm"
                  value={formData.sleeve}
                  onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
                >
                  {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            )}

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm"
                value={formData.size}
                onChange={e => setFormData({ ...formData, size: e.target.value })}
              >
                {productType === ProductType.CAP ? (
                  <option>Универсальный</option>
                ) : (
                  <>
                    <optgroup label="Дети">
                      {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                    <optgroup label="Взрослые">
                       {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                  </>
                )}
              </select>
            </div>

            <div className="col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold"
                >+</button>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="mt-8 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button onClick={handleAdd} variant="primary" fullWidth>Добавить в корзину</Button>
      </div>
    </div>
  );
};

export const COLORS = [
  { name: 'Белый', hex: '#FFFFFF' },
  { name: 'Чёрный', hex: '#000000' },
  { name: 'Тёмно синий / Navy', hex: '#001F3F' },
  { name: 'Тёмно зелёный', hex: '#004D00' },
  { name: 'Royal', hex: '#4169E1' },
  { name: 'Бирюзовый / Turquoise', hex: '#40E0D0' },
  { name: 'Оранжевый', hex: '#FF8C00' },
  { name: 'Красный', hex: '#FF0000' },
  { name: 'Фуксия', hex: '#FF00FF' },
];

export const SCHOOL_SIZES_KIDS = ['6', '8', '10', '12', '14', '16', '18'];
export const SCHOOL_SIZES_ADULTS = ['S', 'M', 'L', 'XL', '2XL'];

export const PERSONAL_SIZES_KIDS = ['2', '4', '6', '8', '10', '12', '14', '16', '18'];
export const PERSONAL_SIZES_ADULTS = ['S', 'M', 'L', 'XL', '2XL', '3XL', '4XL'];

