export default App;

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  // State for multi-color quantities (Only used for SCHOOL TSHIRT/HOODIE)
  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});

  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);

  useEffect(() => {
    // Reset defaults based on type/subtype
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    }

    // Fetch AI tips
    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const readers = Array.from(files).map((file: File) => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      });
      Promise.all(readers).then(results => {
        setFormData(prev => ({ ...prev, images: [...(prev.images || []), ...results] }));
      });
    }
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const toggleMultiColor = (colorName: string) => {
    setMultiColorSelections(prev => {
      const next = { ...prev };
      if (next[colorName]) {
        delete next[colorName];
      } else {
        next[colorName] = 1;
      }
      return next;
    });
  };

  const updateMultiColorQty = (colorName: string, delta: number) => {
    setMultiColorSelections(prev => ({
      ...prev,
      [colorName]: Math.max(1, (prev[colorName] || 0) + delta)
    }));
  };

  const handleAdd = () => {
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;

      const items: OrderItem[] = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName]
      } as OrderItem));

      onAddToCart(items);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : 'Шапка'}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(CapType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, capType: v as CapType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.capType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <div className="mb-4">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                    formData.school === school.name 
                      ? 'bg-indigo-50 border-indigo-500 shadow-md' 
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-12 h-12 mb-2 bg-white rounded-lg p-1 shadow-sm overflow-hidden flex items-center justify-center">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-bold leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-600'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {(productType === ProductType.CAP ? ['Спереди'] : PRINT_PLACES).map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Загрузить изображения</label>
              <div className="flex items-center gap-4">
                <input 
                  type="file" 
                  multiple 
                  onChange={handleImageUpload}
                  className="hidden" 
                  id="image-upload" 
                />
                <label 
                  htmlFor="image-upload" 
                  className="cursor-pointer bg-gray-100 hover:bg-gray-200 py-3 px-6 rounded-xl border-2 border-dashed border-gray-300 text-gray-500 text-sm font-medium flex items-center gap-2"
                >
                  📁 Выбрать файлы
                </label>
                <div className="flex -space-x-2 overflow-hidden">
                  {formData.images?.map((img, idx) => (
                    <img key={idx} src={img} className="inline-block h-8 w-8 rounded-full ring-2 ring-white object-cover" />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
          />
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Цвет {isMultiColorMode ? '(выберите несколько)' : ''}
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => {
                const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
                return (
                  <button
                    key={c.hex}
                    onClick={() => isMultiColorMode ? toggleMultiColor(c.name) : setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all relative ${
                      isSelected ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  >
                    {isMultiColorMode && isSelected && (
                      <span className="absolute -top-2 -right-2 bg-indigo-600 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">✓</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {productType !== ProductType.CAP && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
              <div className="flex gap-2">
                 {['Мальчик', 'Девочка'].map(g => (
                   <button
                     key={g}
                     onClick={() => setFormData({ ...formData, gender: g as any })}
                     className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                       formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                     }`}
                   >
                     {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                   </button>
                 ))}
              </div>
            </div>
          )}

          {productType === ProductType.TSHIRT && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.sleeve}
                onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
              >
                {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          )}

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
            <select 
              className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
              value={formData.size}
              onChange={e => setFormData({ ...formData, size: e.target.value })}
            >
              {productType === ProductType.CAP ? (
                <option>Универсальный</option>
              ) : (
                <>
                  <optgroup label="Дети">
                    {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                     {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </>
              )}
            </select>
          </div>

          {!isMultiColorMode ? (
            <div className="col-span-1 sm:col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >+</button>
              </div>
            </div>
          ) : (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <label className="block text-sm font-bold text-indigo-700 mb-4 uppercase tracking-wider text-xs">Выбранные цвета и количество</label>
               {Object.keys(multiColorSelections).length === 0 ? (
                 <p className="text-gray-400 text-sm italic py-2">Пожалуйста, выберите хотя бы один цвет выше</p>
               ) : (
                 <div className="space-y-3">
                   {Object.entries(multiColorSelections).map(([colorName, qty]) => {
                     const colorHex = COLORS.find(c => c.name === colorName)?.hex || '#ccc';
                     return (
                       <div key={colorName} className="flex items-center justify-between bg-white p-3 rounded-xl shadow-sm">
                         <div className="flex items-center gap-3">
                           <div className="w-6 h-6 rounded-md shadow-inner" style={{ backgroundColor: colorHex }}></div>
                           <span className="text-sm font-bold text-gray-700">{colorName}</span>
                         </div>
                         <div className="flex items-center gap-3">
                            <button 
                              onClick={() => updateMultiColorQty(colorName, -1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >-</button>
                            <span className="w-6 text-center text-sm font-black">{qty}</span>
                            <button 
                              onClick={() => updateMultiColorQty(colorName, 1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >+</button>
                         </div>
                       </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      <div className="mt-10 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          fullWidth
          disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0)}
        >
          {formData.id ? 'Обновить' : 'В корзину'}
        </Button>
      </div>
    </div>
  );
};

export enum ProductType {
  TSHIRT = 'TSHIRT',
  HOODIE = 'HOODIE',
  CAP = 'CAP',
  TANK_TOP = 'TANK_TOP'
}

export enum OrderSubtype {
  SCHOOL = 'Школа',
  PERSONAL = 'Личный дизайн',
  TEAM = 'Команда'
}

export enum HoodieType {
  ZIP = 'На молнии с капюшоном',
  KANGAROO = 'Кенгуру с капюшоном',
  SWEATER = 'Свитер без капюшона'
}

export enum CapType {
  BASEBALL = 'Бейсболка',
  BEANIE = 'Шапка-бини',
  SNAPBACK = 'Снэпбек'
}

export type OrderStatus = 'New' | 'Processing' | 'Completed' | 'Cancelled';

export interface Player {
  id: string;
  name: string;
  number: string;
  gender: 'Мальчик' | 'Девочка';
  sleeve: string;
  size: string;
}

export interface OrderItem {
  id: string;
  type: ProductType;
  subtype: OrderSubtype;
  school?: string;
  printPlaces: string[];
  images: string[]; // Base64 or URLs
  players?: Player[];
  hoodieType?: HoodieType;
  capType?: CapType;
  gender?: 'Мальчик' | 'Девочка' | 'Универсальный';
  sleeve?: string;
  size: string;
  color: string;
  quantity: number;
}

export interface CustomerData {
  name: string;
  phone: string;
  email: string;
  address?: string;
  comments?: string;
}

export interface Order {
  orderNumber: string;
  customer: CustomerData;
  items: OrderItem[];
  createdAt: string;
  status: OrderStatus;
  viewed: boolean;
  internalNotes?: string;
}

import React, { useState, useEffect } from 'react';
import { ProductType, OrderSubtype, OrderItem, CustomerData, Order } from './types';
import { Button } from './components/ui/Button';
import { OrderForm } from './components/OrderForm';
import { CartView } from './components/CartView';
import { CustomerInfo } from './components/CustomerInfo';
import { AdminDashboard } from './components/AdminDashboard';
import { AdminLogin } from './components/AdminLogin';
import { generateOrderSummaryDescription } from './services/geminiService';
import { apiService } from './services/apiService';

enum Step {
  SELECT_CATEGORY,
  SELECT_PRODUCT,
  CONFIGURE,
  CHECKOUT,
  SUCCESS,
  ERROR,
  ADMIN
}

const App: React.FC = () => {
  const [step, setStep] = useState<Step>(Step.SELECT_CATEGORY);
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<OrderSubtype | null>(null);
  const [activeType, setActiveType] = useState<ProductType | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [orderId, setOrderId] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);

  useEffect(() => {
    const authStatus = sessionStorage.getItem('isAdminAuthenticated') === 'true';
    setIsAdminAuthenticated(authStatus);
  }, []);

  const selectCategory = (category: OrderSubtype) => {
    setActiveCategory(category);
    setStep(Step.SELECT_PRODUCT);
  };

  const selectProduct = (type: ProductType) => {
    setActiveType(type);
    setStep(Step.CONFIGURE);
  };

  const addToCart = (item: OrderItem | OrderItem[]) => {
    const itemsToAdd = Array.isArray(item) ? item : [item];
    setCart(prev => [...prev, ...itemsToAdd]);
    setStep(Step.SELECT_CATEGORY);
    setActiveCategory(null);
    setActiveType(null);
  };

  const removeItem = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const submitOrder = async (data: CustomerData) => {
    setCustomer(data);
    setIsSubmitting(true);

    const newOrderId = `ORD-${Date.now()}`;
    setOrderId(newOrderId);

    const fullOrder: Order = {
      orderNumber: newOrderId,
      customer: data,
      items: cart,
      createdAt: new Date().toISOString(),
      status: 'New',
      viewed: false
    };

    try {
      await apiService.submitOrder(fullOrder);
      const summary = await generateOrderSummaryDescription(fullOrder);
      setAiSummary(summary);
      setStep(Step.SUCCESS);
    } catch (error) {
      console.error("Order submission failed:", error);
      setErrorMessage("Произошла ошибка при отправке заказа.");
      setStep(Step.ERROR);
    } finally {
      setIsSubmitting(false);
    }
  };

  const reset = () => {
    setCart([]);
    setStep(Step.SELECT_CATEGORY);
    setActiveCategory(null);
    setActiveType(null);
    setCustomer(null);
    setErrorMessage('');
  };

  const toggleAdmin = () => {
    setStep(prev => prev === Step.ADMIN ? Step.SELECT_CATEGORY : Step.ADMIN);
  };

  const handleLoginSuccess = () => {
    setIsAdminAuthenticated(true);
  };

  return (
    <div className="min-h-screen pb-12">
      <header className="gradient-bg text-white py-12 px-6 shadow-xl mb-12">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div>
             <h1 className="text-4xl font-black tracking-tight cursor-pointer" onClick={() => setStep(Step.SELECT_CATEGORY)}>PRINTMASTER PRO</h1>
             <p className="text-indigo-100 mt-2 font-medium">Ваша индивидуальная печать на одежде</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden md:block bg-white/20 px-6 py-3 rounded-2xl backdrop-blur-md">
              <p className="text-sm font-bold">WhatsApp: +7 (900) 123-45-67</p>
            </div>
            <button 
              onClick={toggleAdmin}
              className={`p-2 rounded-xl transition-all ${step === Step.ADMIN ? 'bg-white text-indigo-600' : 'bg-white/10 hover:bg-white/30 text-white'}`}
              title="Панель управления"
            >
              {step === Step.ADMIN ? '🏠' : '⚙️'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6">

        {step === Step.SELECT_CATEGORY && (
          <div className="space-y-12 animate-in fade-in duration-700">
            <h2 className="text-3xl font-bold text-center text-gray-800">Выберите тип заказа</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <SelectionCard 
                title="Школа" 
                icon="🏫" 
                desc="Выбор из библиотеки логотипов школ (100+). Печать спереди." 
                onClick={() => selectCategory(OrderSubtype.SCHOOL)} 
              />
              <SelectionCard 
                title="Команда" 
                icon="⚽" 
                desc="Дизайн для команд с таблицей игроков (имена, номера, размеры)." 
                onClick={() => selectCategory(OrderSubtype.TEAM)} 
              />
              <SelectionCard 
                title="Личный дизайн" 
                icon="🎨" 
                desc="Ваши изображения на футболках, худи или шапках." 
                onClick={() => selectCategory(OrderSubtype.PERSONAL)} 
              />
            </div>
            <CartView items={cart} onRemove={removeItem} onNext={() => setStep(Step.CHECKOUT)} />
          </div>
        )}

        {step === Step.SELECT_PRODUCT && activeCategory && (
          <div className="space-y-12 animate-in fade-in duration-500">
             <div className="text-center">
                <button onClick={() => setStep(Step.SELECT_CATEGORY)} className="text-indigo-600 font-bold hover:underline mb-4">← Назад к категориям</button>
                <h2 className="text-3xl font-bold text-gray-800">Что именно будем печатать?</h2>
                <p className="text-gray-500">Категория: {activeCategory}</p>
             </div>
             <div className="grid md:grid-cols-3 gap-8 max-w-4xl mx-auto">
                <ProductSmallCard 
                  title="Футболка" 
                  icon="👕" 
                  onClick={() => selectProduct(ProductType.TSHIRT)} 
                />
                {activeCategory === OrderSubtype.TEAM && (
                  <ProductSmallCard 
                    title="Майка" 
                    icon="🎽" 
                    onClick={() => selectProduct(ProductType.TANK_TOP)} 
                  />
                )}
                {(activeCategory === OrderSubtype.SCHOOL || activeCategory === OrderSubtype.PERSONAL) && (
                  <ProductSmallCard 
                    title="Худи" 
                    icon="🧥" 
                    onClick={() => selectProduct(ProductType.HOODIE)} 
                  />
                )}
                {activeCategory === OrderSubtype.PERSONAL && (
                  <ProductSmallCard 
                    title="Шапка" 
                    icon="🧢" 
                    onClick={() => selectProduct(ProductType.CAP)} 
                  />
                )}
             </div>
          </div>
        )}

        {step === Step.CONFIGURE && activeType && activeCategory && (
          <OrderForm 
            productType={activeType} 
            initialSubtype={activeCategory}
            onAddToCart={addToCart} 
            onCancel={() => setStep(Step.SELECT_PRODUCT)} 
          />
        )}

        {step === Step.CHECKOUT && (
          <CustomerInfo onSubmit={submitOrder} onBack={() => setStep(Step.SELECT_CATEGORY)} />
        )}

        {step === Step.ADMIN && (
          isAdminAuthenticated ? <AdminDashboard /> : <AdminLogin onLoginSuccess={handleLoginSuccess} />
        )}

        {step === Step.SUCCESS && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-green-500">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Заказ отправлен!</h2>
            <div className="flex flex-col items-center gap-2 mb-6">
               <p className="text-gray-500">Номер заказа:</p>
               <p className="text-2xl font-mono font-bold text-indigo-600 bg-indigo-50 inline-block px-4 py-2 rounded-xl">{orderId}</p>
            </div>
            <div className="bg-gray-50 p-6 rounded-2xl mb-8 text-left border border-gray-100 italic"><p className="text-gray-700 leading-relaxed">{aiSummary}</p></div>
            <Button onClick={reset} variant="primary" fullWidth>Создать новый заказ</Button>
          </div>
        )}

        {step === Step.ERROR && (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center max-w-2xl mx-auto border-t-8 border-red-500">
            <h2 className="text-3xl font-bold text-gray-800 mb-4">Ошибка</h2>
            <p className="text-gray-600 mb-8">{errorMessage}</p>
            <Button onClick={() => setStep(Step.CHECKOUT)} variant="outline" fullWidth>Назад</Button>
          </div>
        )}
      </main>
    </div>
  );
};

const SelectionCard: React.FC<{title: string, icon: string, desc: string, onClick: () => void}> = ({ title, icon, desc, onClick }) => (
  <div onClick={onClick} className="bg-white rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center flex flex-col items-center">
    <div className="text-6xl mb-6 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-2xl font-bold text-gray-800 mb-2">{title}</h3>
    <p className="text-gray-500 text-sm leading-relaxed">{desc}</p>
    <div className="mt-auto pt-6 w-full">
       <span className="inline-block w-full bg-indigo-50 text-indigo-600 font-bold px-4 py-3 rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-colors">Выбрать</span>
    </div>
  </div>
);

const ProductSmallCard: React.FC<{title: string, icon: string, onClick: () => void}> = ({ title, icon, onClick }) => (
  <div onClick={onClick} className="bg-white rounded-2xl p-6 shadow-md hover:shadow-xl transition-all cursor-pointer group border-2 border-transparent hover:border-indigo-400 text-center">
    <div className="text-5xl mb-4 group-hover:scale-110 transition-transform">{icon}</div>
    <h3 className="text-xl font-bold text-gray-800">{title}</h3>
  </div>
);

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  // State for multi-color quantities (Only used for SCHOOL TSHIRT/HOODIE)
  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});

  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);

  useEffect(() => {
    // Reset defaults based on type/subtype
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов' }));
    }

    // Fetch AI tips
    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const readers = Array.from(files).map((file: File) => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      });
      Promise.all(readers).then(results => {
        setFormData(prev => ({ ...prev, images: [...(prev.images || []), ...results] }));
      });
    }
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const toggleMultiColor = (colorName: string) => {
    setMultiColorSelections(prev => {
      const next = { ...prev };
      if (next[colorName]) {
        delete next[colorName];
      } else {
        next[colorName] = 1;
      }
      return next;
    });
  };

  const updateMultiColorQty = (colorName: string, delta: number) => {
    setMultiColorSelections(prev => ({
      ...prev,
      [colorName]: Math.max(1, (prev[colorName] || 0) + delta)
    }));
  };

  const handleAdd = () => {
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;

      const items: OrderItem[] = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName]
      } as OrderItem));

      onAddToCart(items);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const getProductLabel = () => {
    switch(productType) {
      case ProductType.TSHIRT: return 'Футболка';
      case ProductType.HOODIE: return 'Худи';
      case ProductType.CAP: return 'Шапка';
      case ProductType.TANK_TOP: return 'Майка';
      default: return 'Товар';
    }
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {getProductLabel()}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(CapType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, capType: v as CapType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.capType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <div className="mb-4">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                    formData.school === school.name 
                      ? 'bg-indigo-50 border-indigo-500 shadow-md' 
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-12 h-12 mb-2 bg-white rounded-lg p-1 shadow-sm overflow-hidden flex items-center justify-center">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-bold leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-600'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {(productType === ProductType.CAP ? ['Спереди'] : PRINT_PLACES).map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Загрузить изображения</label>
              <div className="flex items-center gap-4">
                <input 
                  type="file" 
                  multiple 
                  onChange={handleImageUpload}
                  className="hidden" 
                  id="image-upload" 
                />
                <label 
                  htmlFor="image-upload" 
                  className="cursor-pointer bg-gray-100 hover:bg-gray-200 py-3 px-6 rounded-xl border-2 border-dashed border-gray-300 text-gray-500 text-sm font-medium flex items-center gap-2"
                >
                  📁 Выбрать файлы
                </label>
                <div className="flex -space-x-2 overflow-hidden">
                  {formData.images?.map((img, idx) => (
                    <img key={idx} src={img} className="inline-block h-8 w-8 rounded-full ring-2 ring-white object-cover" />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
          />
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Цвет {isMultiColorMode ? '(выберите несколько)' : ''}
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => {
                const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
                return (
                  <button
                    key={c.hex}
                    onClick={() => isMultiColorMode ? toggleMultiColor(c.name) : setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all relative ${
                      isSelected ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  >
                    {isMultiColorMode && isSelected && (
                      <span className="absolute -top-2 -right-2 bg-indigo-600 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">✓</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
              <div className="flex gap-2">
                 {['Мальчик', 'Девочка'].map(g => (
                   <button
                     key={g}
                     onClick={() => setFormData({ ...formData, gender: g as any })}
                     className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                       formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                     }`}
                   >
                     {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                   </button>
                 ))}
              </div>
            </div>
          )}

          {productType === ProductType.TSHIRT && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.sleeve}
                onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
              >
                {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          )}

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
            <select 
              className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
              value={formData.size}
              onChange={e => setFormData({ ...formData, size: e.target.value })}
            >
              {productType === ProductType.CAP ? (
                <option>Универсальный</option>
              ) : (
                <>
                  <optgroup label="Дети">
                    {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                     {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </>
              )}
            </select>
          </div>

          {!isMultiColorMode ? (
            <div className="col-span-1 sm:col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >+</button>
              </div>
            </div>
          ) : (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <label className="block text-sm font-bold text-indigo-700 mb-4 uppercase tracking-wider text-xs">Выбранные цвета и количество</label>
               {Object.keys(multiColorSelections).length === 0 ? (
                 <p className="text-gray-400 text-sm italic py-2">Пожалуйста, выберите хотя бы один цвет выше</p>
               ) : (
                 <div className="space-y-3">
                   {Object.entries(multiColorSelections).map(([colorName, qty]) => {
                     const colorHex = COLORS.find(c => c.name === colorName)?.hex || '#ccc';
                     return (
                       <div key={colorName} className="flex items-center justify-between bg-white p-3 rounded-xl shadow-sm">
                         <div className="flex items-center gap-3">
                           <div className="w-6 h-6 rounded-md shadow-inner" style={{ backgroundColor: colorHex }}></div>
                           <span className="text-sm font-bold text-gray-700">{colorName}</span>
                         </div>
                         <div className="flex items-center gap-3">
                            <button 
                              onClick={() => updateMultiColorQty(colorName, -1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >-</button>
                            <span className="w-6 text-center text-sm font-black">{qty}</span>
                            <button 
                              onClick={() => updateMultiColorQty(colorName, 1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >+</button>
                         </div>
                       </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      <div className="mt-10 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          fullWidth
          disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0)}
        >
          {formData.id ? 'Обновить' : 'В корзину'}
        </Button>
      </div>
    </div>
  );
};

import React from 'react';
import { OrderItem } from '../types';
import { Button } from './ui/Button';

interface CartViewProps {
  items: OrderItem[];
  onRemove: (id: string) => void;
  onNext: () => void;
}

export const CartView: React.FC<CartViewProps> = ({ items, onRemove, onNext }) => {
  if (items.length === 0) return null;

  const getItemIcon = (type: string) => {
    switch(type) {
      case 'TSHIRT': return '👕';
      case 'HOODIE': return '🧥';
      case 'CAP': return '🧢';
      case 'TANK_TOP': return '🎽';
      default: return '📦';
    }
  };

  return (
    <div className="mt-12 bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center gap-2">
        🛒 Ваша корзина <span className="bg-indigo-600 text-white text-xs px-2 py-1 rounded-full">{items.length}</span>
      </h2>
      <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
        {items.map((item) => (
          <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl hover:bg-gray-100 transition-colors group">
            <div className="flex gap-4 items-center">
              <div className="w-16 h-16 bg-white rounded-xl shadow-sm flex items-center justify-center text-2xl">
                {getItemIcon(item.type)}
              </div>
              <div>
                <p className="font-bold text-gray-800">{item.subtype} - {item.type === 'TANK_TOP' ? 'Майка' : item.type}</p>
                <p className="text-xs text-gray-500 uppercase font-semibold">
                  {item.color} • {item.size} • x{item.quantity} 
                  {item.school && ` • ${item.school}`}
                  {item.players && ` • Команда (${item.players.length} чел.)`}
                </p>
              </div>
            </div>
            <button 
              onClick={() => onRemove(item.id)}
              className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-2"
            >
              🗑️
            </button>
          </div>
        ))}
      </div>
      <div className="mt-8 pt-6 border-t border-gray-100 flex justify-between items-center">
        <div>
          <p className="text-gray-500 text-sm">Общее количество:</p>
          <p className="text-xl font-bold text-gray-800">
            {items.reduce((acc, item) => acc + (item.subtype === 'Команда' ? (item.players?.length || 0) : item.quantity), 0)} шт.
          </p>
        </div>
        <Button onClick={onNext} variant="primary" size="lg">Оформить заказ →</Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, ProductType } from '../types';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const data = await apiService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error("Dashboard fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const updated = await apiService.updateOrder(orderNumber, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return updated;
    } catch (error) {
      console.error("Dashboard update error:", error);
      throw error;
    }
  };

  const handleSelectOrder = (order: Order) => {
    setSelectedOrder(order);
    if (!order.viewed) {
      updateOrderData(order.orderNumber, { viewed: true });
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const resetFilters = () => {
    setFilterText('');
    setStatusFilter('all');
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getItemIcon = (type: ProductType) => {
    switch(type) {
      case ProductType.TSHIRT: return '👕';
      case ProductType.HOODIE: return '🧥';
      case ProductType.CAP: return '🧢';
      case ProductType.TANK_TOP: return '🎽';
      default: return '📦';
    }
  };

  const getStatusCount = (status: OrderStatus) => orders.filter(o => o.status === status).length;
  const getUnreadCount = (status: OrderStatus) => orders.filter(o => o.status === status && !o.viewed).length;

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <Button onClick={fetchOrders} variant="outline" size="sm" className="w-full md:w-auto">
          🔄 Обновить данные
        </Button>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
        {(Object.keys(STATUS_LABELS) as OrderStatus[]).map((status) => {
          const unread = getUnreadCount(status);
          return (
            <div 
              key={status} 
              onClick={() => setStatusFilter(status)}
              className={`p-5 rounded-2xl cursor-pointer transition-all border-2 relative overflow-hidden ${
                statusFilter === status 
                  ? 'bg-indigo-50 border-indigo-500 shadow-md scale-[1.02]' 
                  : 'bg-white border-gray-100 hover:border-indigo-200'
              }`}
            >
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{STATUS_LABELS[status]}</p>
              <div className="flex items-center justify-between">
                <span className="text-3xl font-black text-gray-800">{getStatusCount(status)}</span>
                <span className={`w-3 h-3 rounded-full ${getStatusColor(status).split(' ')[0]}`}></span>
              </div>
              {unread > 0 && (
                <div className="absolute top-2 right-2 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse"></span>
                  <span className="text-[9px] font-bold text-indigo-600 uppercase">{unread} нов.</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-4 mb-6 bg-gray-50 p-6 rounded-2xl border border-gray-100">
        <div className="flex-1 w-full">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Поиск</label>
          <input 
            type="text" 
            placeholder="Имя, ID или заметки..."
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
        <div className="w-full md:w-64">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Фильтр по статусу</label>
          <select 
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none cursor-pointer text-sm shadow-sm font-medium"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>
        {(statusFilter !== 'all' || filterText) && (
          <button 
            onClick={resetFilters}
            className="text-xs font-bold text-indigo-600 hover:text-indigo-800 px-2 py-3 transition-colors"
          >
            Очистить
          </button>
        )}
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация данных...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Действия</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredOrders.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-gray-400 italic">Заказы не найдены</td>
                </tr>
              ) : (
                filteredOrders.map((order) => (
                  <tr 
                    key={order.orderNumber} 
                    className="hover:bg-indigo-50/50 transition-colors group cursor-pointer"
                    onClick={() => handleSelectOrder(order)}
                  >
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {new Date(order.createdAt).toLocaleDateString()}
                      <div className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {!order.viewed && (
                          <span className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse shadow-sm shadow-indigo-200" title="Не просмотрено"></span>
                        )}
                        <span className="font-mono text-[10px] font-bold text-indigo-500">
                          {order.orderNumber.split('-')[1]}
                        </span>
                        {order.internalNotes && (
                          <span className="inline-block w-2 h-2 rounded-full bg-amber-400 shadow-sm" title="Есть внутренняя заметка"></span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-800">{order.customer.name}</div>
                      <div className="text-[10px] text-gray-400">{order.customer.phone}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex -space-x-2">
                        {order.items.slice(0, 3).map((item, idx) => (
                          <div key={idx} className="w-8 h-8 rounded-full bg-white border-2 border-gray-100 flex items-center justify-center text-sm shadow-sm" title={item.type}>
                            {getItemIcon(item.type)}
                          </div>
                        ))}
                        {order.items.length > 3 && (
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-500">
                            +{order.items.length - 3}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <select 
                        className={`text-xs font-bold rounded-full px-3 py-1 outline-none appearance-none cursor-pointer border-none shadow-sm ${getStatusColor(order.status)}`}
                        value={order.status}
                        onClick={(e) => e.stopPropagation()} 
                        onChange={(e) => updateOrderData(order.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                      >
                        {Object.entries(STATUS_LABELS).map(([key, label]) => (
                          <option key={key} value={key}>{label}</option>
                        ))}
                      </select>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-lg">
                      👁️
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {selectedOrder && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <div>
                <h3 className="text-xl font-bold text-gray-800">Детали заказа {selectedOrder.orderNumber}</h3>
                <p className="text-sm text-gray-500">{new Date(selectedOrder.createdAt).toLocaleString()}</p>
              </div>
              <button onClick={() => setSelectedOrder(null)} className="text-gray-400 hover:text-gray-600 text-2xl transition-colors">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
              <div className="grid md:grid-cols-2 gap-6 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Клиент</h4>
                  <p className="font-bold text-gray-800 text-lg">{selectedOrder.customer.name}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">✉️ {selectedOrder.customer.email}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">📞 {selectedOrder.customer.phone}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Доставка и примечания</h4>
                  <p className="text-sm text-gray-700"><strong>Адрес:</strong> {selectedOrder.customer.address || 'Не указан'}</p>
                  <p className="text-sm text-gray-700 mt-1"><strong>От клиента:</strong> {selectedOrder.customer.comments || 'Нет'}</p>
                </div>
              </div>

              <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-600 uppercase tracking-wider mb-2">📝 Внутренние заметки</h4>
                <textarea 
                  className="w-full p-4 bg-white border border-amber-200 rounded-xl outline-none focus:ring-2 ring-amber-400 text-sm h-24 resize-none shadow-inner"
                  value={editingNotes}
                  onChange={(e) => setEditingNotes(e.target.value)}
                  placeholder="Добавьте рабочую заметку..."
                />
                <div className="mt-2 flex justify-end">
                   <Button 
                    size="sm" 
                    variant="primary" 
                    className="bg-amber-600 hover:bg-amber-700 shadow-sm" 
                    onClick={handleSaveNotes}
                    disabled={isSavingNotes || editingNotes === (selectedOrder.internalNotes || '')}
                  >
                    {isSavingNotes ? 'Сохранение...' : 'Сохранить заметку'}
                  </Button>
                </div>
              </div>

              <div className="space-y-6">
                <h4 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                  📦 Состав заказа <span className="text-sm font-normal text-gray-400">({selectedOrder.items.length} поз.)</span>
                </h4>
                {selectedOrder.items.map((item, idx) => (
                  <div key={idx} className="border border-gray-100 rounded-2xl p-6 hover:border-indigo-200 transition-all bg-white shadow-sm">
                    <div className="flex flex-col md:flex-row gap-6">
                      <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center text-3xl shrink-0">
                        {getItemIcon(item.type)}
                      </div>
                      <div className="flex-1">
                        <div className="flex justify-between items-start mb-4">
                          <div>
                            <h5 className="text-lg font-bold text-gray-800 leading-tight">
                              {item.type === ProductType.TSHIRT ? 'Футболка' : item.type === ProductType.HOODIE ? 'Худи' : item.type === ProductType.CAP ? 'Шапка' : 'Майка'} 
                              <span className="text-indigo-600 ml-1">[{item.subtype}]</span>
                            </h5>
                            <div className="flex flex-wrap gap-2 mt-2">
                              <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">{item.color}</span>
                              <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">Размер: {item.size}</span>
                              <span className="px-2 py-1 bg-indigo-100 rounded-md text-[10px] font-bold text-indigo-700 uppercase">Кол-во: {item.quantity} шт.</span>
                            </div>
                          </div>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm bg-gray-50/50 p-4 rounded-xl border border-gray-100">
                          {item.school && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Школа</p><p className="text-gray-800 font-medium">{item.school}</p></div>)}
                          {item.gender && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Пол</p><p className="text-gray-800 font-medium">{item.gender}</p></div>)}
                          {item.sleeve && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Рукав</p><p className="text-gray-800 font-medium">{item.sleeve}</p></div>)}
                          {item.hoodieType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Тип худи</p><p className="text-gray-800 font-medium">{item.hoodieType}</p></div>)}
                          {item.capType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Модель шапки</p><p className="text-gray-800 font-medium">{item.capType}</p></div>)}
                          {item.printPlaces && item.printPlaces.length > 0 && (
                             <div className="sm:col-span-2">
                               <p className="text-gray-400 text-xs font-bold uppercase mb-1">Места печати</p>
                               <div className="flex flex-wrap gap-1">{item.printPlaces.map(p => (<span key={p} className="bg-white px-2 py-0.5 rounded border border-gray-200 text-xs text-gray-700 font-medium">{p}</span>))}</div>
                             </div>
                          )}
                        </div>
                        {item.players && item.players.length > 0 && (
                          <div className="mt-4">
                            <p className="text-indigo-600 text-xs font-black uppercase mb-2 tracking-widest">📋 Список команды ({item.players.length} чел.)</p>
                            <div className="overflow-hidden border border-gray-100 rounded-xl">
                              <table className="min-w-full divide-y divide-gray-100">
                                <thead className="bg-gray-50"><tr className="text-left text-[10px] font-bold text-gray-500 uppercase"><th className="px-3 py-2">Имя</th><th className="px-3 py-2">№</th><th className="px-3 py-2">Пол</th><th className="px-3 py-2">Размер</th><th className="px-3 py-2">Рукав</th></tr></thead>
                                <tbody className="bg-white divide-y divide-gray-100 text-xs">{item.players.map(player => (<tr key={player.id} className="hover:bg-gray-50 transition-colors"><td className="px-3 py-2 font-medium">{player.name}</td><td className="px-3 py-2 text-indigo-600 font-black">{player.number}</td><td className="px-3 py-2">{player.gender}</td><td className="px-3 py-2 font-bold">{player.size}</td><td className="px-3 py-2 text-gray-500">{player.sleeve}</td></tr>))}</tbody>
                              </table>
                            </div>
                          </div>
                        )}
                        {item.images && item.images.length > 0 && (
                          <div className="mt-4">
                             <p className="text-gray-400 text-xs font-bold uppercase mb-2">Файлы макетов ({item.images.length})</p>
                             <div className="flex flex-wrap gap-2">{item.images.map((img, i) => (<a key={i} href={img} target="_blank" rel="noreferrer" className="block w-20 h-20 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 hover:border-indigo-400 transition-all"><img src={img} alt="layout" className="w-full h-full object-cover" /></a>))}</div>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div className="p-6 border-t border-gray-100 flex justify-between items-center bg-gray-50">
              <div className="flex gap-2">
                <Button onClick={() => setSelectedOrder(null)} variant="outline">Закрыть</Button>
                <Button onClick={() => window.print()} variant="outline" className="hidden sm:inline-flex">🖨️ Печать</Button>
              </div>
              <div className="flex items-center gap-3">
                <span className="text-xs font-bold text-gray-400 uppercase">Статус:</span>
                <select 
                  className={`text-sm font-bold rounded-xl px-4 py-2 outline-none border border-gray-200 shadow-sm transition-all focus:ring-2 ring-indigo-500 ${getStatusColor(selectedOrder.status)}`}
                  value={selectedOrder.status}
                  onChange={(e) => updateOrderData(selectedOrder.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                >
                  {Object.entries(STATUS_LABELS).map(([key, label]) => (<option key={key} value={key}>{label}</option>))}
                </select>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export enum ProductType {
  TSHIRT = 'TSHIRT',
  HOODIE = 'HOODIE',
  CAP = 'CAP',
  TANK_TOP = 'TANK_TOP'
}

export enum OrderSubtype {
  SCHOOL = 'Школа',
  PERSONAL = 'Личный дизайн',
  TEAM = 'Команда'
}

export enum HoodieType {
  ZIP = 'На молнии с капюшоном',
  KANGAROO = 'Кенгуру с капюшоном',
  SWEATER = 'Свитер без капюшона'
}

export enum CapType {
  BASEBALL = 'Бейсболка',
  BEANIE = 'Шапка-бини',
  SNAPBACK = 'Снэпбек'
}

export type OrderStatus = 'New' | 'Processing' | 'Completed' | 'Cancelled';

export interface Player {
  id: string;
  name: string;
  number: string;
  gender: 'Мальчик' | 'Девочка';
  sleeve: string;
  size: string;
}

export interface OrderItem {
  id: string;
  type: ProductType;
  subtype: OrderSubtype;
  school?: string;
  printPlaces: string[];
  images: string[]; // Generic list for backwards compatibility
  printImages?: Record<string, string>; // Mapping: Place -> Image Data
  players?: Player[];
  excelFileName?: string; // Track if players were imported
  hoodieType?: HoodieType;
  capType?: CapType;
  gender?: 'Мальчик' | 'Девочка' | 'Универсальный';
  sleeve?: string;
  size: string;
  color: string;
  quantity: number;
}

export interface CustomerData {
  name: string;
  phone: string;
  email: string;
  address?: string;
  comments?: string;
}

export interface Order {
  orderNumber: string;
  customer: CustomerData;
  items: OrderItem[];
  createdAt: string;
  status: OrderStatus;
  viewed: boolean;
  internalNotes?: string;
}

import React, { useRef } from 'react';
import { Player } from '../types';
import { Button } from './ui/Button';
import { TEAM_SIZES_KIDS, TEAM_SIZES_ADULTS, SLEEVES } from '../constants';

interface PlayerTableProps {
  players: Player[];
  onChange: (players: Player[]) => void;
  onExcelImport?: (fileName: string) => void;
}

export const PlayerTable: React.FC<PlayerTableProps> = ({ players, onChange, onExcelImport }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = () => {
    const newPlayer: Player = {
      id: Math.random().toString(36).substr(2, 9),
      name: '',
      number: '',
      gender: 'Мальчик',
      sleeve: 'Короткий',
      size: 'S'
    };
    onChange([...players, newPlayer]);
  };

  const removePlayer = (id: string) => {
    onChange(players.filter(p => p.id !== id));
  };

  const updatePlayer = (id: string, field: keyof Player, value: string) => {
    onChange(players.map(p => p.id === id ? { ...p, [field]: value } : p));
  };

  const handleExcelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (!content) return;

      // Simple CSV/TSV parsing logic (suitable for Excel exports)
      // Format expected: Name, Number, Gender, Size, Sleeve
      const rows = content.split(/\r?\n/).filter(row => row.trim() !== '');
      const newPlayers: Player[] = rows.slice(1).map(row => {
        const cols = row.split(/[,;\t]/).map(c => c.trim());
        return {
          id: Math.random().toString(36).substr(2, 9),
          name: cols[0] || '',
          number: cols[1] || '',
          gender: (cols[2]?.toLowerCase().includes('дев') ? 'Девочка' : 'Мальчик') as any,
          size: cols[3] || 'S',
          sleeve: cols[4] || 'Короткий'
        };
      });

      onChange([...players, ...newPlayers]);
      if (onExcelImport) onExcelImport(file.name);
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="mt-4 overflow-x-auto bg-white rounded-xl shadow-inner p-4 border border-gray-100">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-bold text-gray-800">Список команды ({players.length})</h3>
        <div className="flex gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleExcelUpload} 
            accept=".csv, .txt, .xlsx, .xls" 
            className="hidden" 
          />
          <Button 
            variant="outline" 
            size="sm" 
            onClick={() => fileInputRef.current?.click()}
            className="text-[10px] py-1 h-8"
          >
            📊 Импорт из Excel/CSV
          </Button>
        </div>
      </div>

      <table className="min-w-full divide-y divide-gray-200">
        <thead>
          <tr className="text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">
            <th className="px-2 py-3">Имя</th>
            <th className="px-2 py-3">Номер</th>
            <th className="px-2 py-3">Пол</th>
            <th className="px-2 py-3">Рукав</th>
            <th className="px-2 py-3">Размер</th>
            <th className="px-2 py-3"></th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {players.map((player) => (
            <tr key={player.id} className="hover:bg-gray-50/50">
              <td className="px-2 py-2">
                <input 
                  type="text" 
                  value={player.name}
                  onChange={(e) => updatePlayer(player.id, 'name', e.target.value)}
                  className="w-full border-b border-transparent focus:border-indigo-400 outline-none p-1 text-sm bg-transparent"
                  placeholder="Имя игрока"
                />
              </td>
              <td className="px-2 py-2">
                <input 
                  type="text" 
                  value={player.number}
                  onChange={(e) => updatePlayer(player.id, 'number', e.target.value)}
                  className="w-12 border-b border-transparent focus:border-indigo-400 outline-none p-1 text-sm text-center bg-transparent font-bold text-indigo-600"
                  placeholder="№"
                />
              </td>
              <td className="px-2 py-2">
                <select 
                   value={player.gender}
                   onChange={(e) => updatePlayer(player.id, 'gender', e.target.value as any)}
                   className="text-xs outline-none bg-transparent border-none cursor-pointer"
                >
                  <option>Мальчик</option>
                  <option>Девочка</option>
                </select>
              </td>
              <td className="px-2 py-2">
                 <select 
                   value={player.sleeve}
                   onChange={(e) => updatePlayer(player.id, 'sleeve', e.target.value)}
                   className="text-xs outline-none bg-transparent border-none cursor-pointer"
                >
                  {player.gender === 'Мальчик' 
                    ? SLEEVES.BOY.map(s => <option key={s} value={s}>{s}</option>)
                    : SLEEVES.GIRL.map(s => <option key={s} value={s}>{s}</option>)
                  }
                </select>
              </td>
              <td className="px-2 py-2">
                <select 
                   value={player.size}
                   onChange={(e) => updatePlayer(player.id, 'size', e.target.value)}
                   className="text-xs font-bold outline-none bg-transparent border-none cursor-pointer"
                >
                  <optgroup label="Дети">
                    {TEAM_SIZES_KIDS.map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                    {TEAM_SIZES_ADULTS.map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </select>
              </td>
              <td className="px-2 py-2 text-right">
                <button 
                  onClick={() => removePlayer(player.id)}
                  className="text-gray-300 hover:text-red-500 transition-colors"
                >
                  ✕
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {players.length === 0 && (
        <div className="py-8 text-center text-gray-400 text-sm italic">
          Добавьте игроков вручную или загрузите файл
        </div>
      )}

      <Button 
        onClick={addPlayer} 
        variant="outline" 
        size="sm" 
        className="mt-6 border-dashed w-full bg-gray-50/50 hover:bg-indigo-50 border-gray-300 text-gray-500 font-bold"
      >
        + Добавить игрока
      </Button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);

  useEffect(() => {
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов' }));
    }

    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleLocationImageUpload = (location: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setFormData(prev => ({
          ...prev,
          printImages: {
            ...(prev.printImages || {}),
            [location]: base64
          }
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLocationImage = (location: string) => {
    setFormData(prev => {
      const newImages = { ...(prev.printImages || {}) };
      delete newImages[location];
      return { ...prev, printImages: newImages };
    });
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const toggleMultiColor = (colorName: string) => {
    setMultiColorSelections(prev => {
      const next = { ...prev };
      if (next[colorName]) {
        delete next[colorName];
      } else {
        next[colorName] = 1;
      }
      return next;
    });
  };

  const updateMultiColorQty = (colorName: string, delta: number) => {
    setMultiColorSelections(prev => ({
      ...prev,
      [colorName]: Math.max(1, (prev[colorName] || 0) + delta)
    }));
  };

  const handleAdd = () => {
    // Extract images list for backward compatibility if needed
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;

      const items: OrderItem[] = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));

      onAddToCart(items);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const getProductLabel = () => {
    switch(productType) {
      case ProductType.TSHIRT: return 'Футболка';
      case ProductType.HOODIE: return 'Худи';
      case ProductType.CAP: return 'Шапка';
      case ProductType.TANK_TOP: return 'Майка';
      default: return 'Товар';
    }
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {getProductLabel()}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(CapType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, capType: v as CapType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.capType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <div className="mb-4">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                    formData.school === school.name 
                      ? 'bg-indigo-50 border-indigo-500 shadow-md' 
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-12 h-12 mb-2 bg-white rounded-lg p-1 shadow-sm overflow-hidden flex items-center justify-center">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-bold leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-600'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {(productType === ProductType.CAP ? ['Спереди'] : PRINT_PLACES).map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            {formData.printPlaces && formData.printPlaces.length > 0 && (
              <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 space-y-4">
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest">Загрузка макетов по местам</label>
                <div className="grid grid-cols-1 gap-3">
                  {formData.printPlaces.map(place => (
                    <div key={place} className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-100 shadow-sm group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} className="w-full h-full object-cover rounded-lg" alt={place} />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-gray-700">{place}</p>
                          <p className="text-[10px] text-gray-400">{formData.printImages?.[place] ? 'Файл выбран' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {formData.printImages?.[place] ? (
                          <button 
                            onClick={() => removeLocationImage(place)}
                            className="text-red-400 hover:text-red-600 p-2 text-sm"
                          >✕</button>
                        ) : (
                          <>
                            <input 
                              type="file" 
                              id={`upload-${place}`} 
                              className="hidden" 
                              onChange={(e) => handleLocationImageUpload(place, e)} 
                              accept="image/*"
                            />
                            <label 
                              htmlFor={`upload-${place}`}
                              className="bg-indigo-600 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg cursor-pointer hover:bg-indigo-700 transition-colors"
                            >
                              Выбрать
                            </label>
                          </>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
            onExcelImport={(fileName) => setFormData(prev => ({ ...prev, excelFileName: fileName }))}
          />
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Цвет {isMultiColorMode ? '(выберите несколько)' : ''}
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => {
                const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
                return (
                  <button
                    key={c.hex}
                    onClick={() => isMultiColorMode ? toggleMultiColor(c.name) : setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all relative ${
                      isSelected ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  >
                    {isMultiColorMode && isSelected && (
                      <span className="absolute -top-2 -right-2 bg-indigo-600 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">✓</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
              <div className="flex gap-2">
                 {['Мальчик', 'Девочка'].map(g => (
                   <button
                     key={g}
                     onClick={() => setFormData({ ...formData, gender: g as any })}
                     className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                       formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                     }`}
                   >
                     {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                   </button>
                 ))}
              </div>
            </div>
          )}

          {productType === ProductType.TSHIRT && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.sleeve}
                onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
              >
                {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          )}

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
            <select 
              className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
              value={formData.size}
              onChange={e => setFormData({ ...formData, size: e.target.value })}
            >
              {productType === ProductType.CAP ? (
                <option>Универсальный</option>
              ) : (
                <>
                  <optgroup label="Дети">
                    {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                     {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </>
              )}
            </select>
          </div>

          {!isMultiColorMode ? (
            <div className="col-span-1 sm:col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >+</button>
              </div>
            </div>
          ) : (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <label className="block text-sm font-bold text-indigo-700 mb-4 uppercase tracking-wider text-xs">Выбранные цвета и количество</label>
               {Object.keys(multiColorSelections).length === 0 ? (
                 <p className="text-gray-400 text-sm italic py-2">Пожалуйста, выберите хотя бы один цвет выше</p>
               ) : (
                 <div className="space-y-3">
                   {Object.entries(multiColorSelections).map(([colorName, qty]) => {
                     const colorHex = COLORS.find(c => c.name === colorName)?.hex || '#ccc';
                     return (
                       <div key={colorName} className="flex items-center justify-between bg-white p-3 rounded-xl shadow-sm">
                         <div className="flex items-center gap-3">
                           <div className="w-6 h-6 rounded-md shadow-inner" style={{ backgroundColor: colorHex }}></div>
                           <span className="text-sm font-bold text-gray-700">{colorName}</span>
                         </div>
                         <div className="flex items-center gap-3">
                            <button 
                              onClick={() => updateMultiColorQty(colorName, -1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >-</button>
                            <span className="w-6 text-center text-sm font-black">{qty}</span>
                            <button 
                              onClick={() => updateMultiColorQty(colorName, 1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >+</button>
                         </div>
                       </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      <div className="mt-10 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          fullWidth
          disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0)}
        >
          {formData.id ? 'Обновить' : 'В корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);

  useEffect(() => {
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: [] }));
    }

    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleLocationImageUpload = (location: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setFormData(prev => ({
          ...prev,
          printImages: {
            ...(prev.printImages || {}),
            [location]: base64
          }
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLocationImage = (location: string) => {
    setFormData(prev => {
      const newImages = { ...(prev.printImages || {}) };
      delete newImages[location];
      return { ...prev, printImages: newImages };
    });
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const toggleMultiColor = (colorName: string) => {
    setMultiColorSelections(prev => {
      const next = { ...prev };
      if (next[colorName]) {
        delete next[colorName];
      } else {
        next[colorName] = 1;
      }
      return next;
    });
  };

  const updateMultiColorQty = (colorName: string, delta: number) => {
    setMultiColorSelections(prev => ({
      ...prev,
      [colorName]: Math.max(1, (prev[colorName] || 0) + delta)
    }));
  };

  const handleAdd = () => {
    // Extract images list for backward compatibility if needed
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;

      const items: OrderItem[] = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));

      onAddToCart(items);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const getProductLabel = () => {
    switch(productType) {
      case ProductType.TSHIRT: return 'Футболка';
      case ProductType.HOODIE: return 'Худи';
      case ProductType.CAP: return 'Шапка';
      case ProductType.TANK_TOP: return 'Майка';
      default: return 'Товар';
    }
  };

  const getAvailablePrintPlaces = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {getProductLabel()}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(CapType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, capType: v as CapType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.capType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <div className="mb-4">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                    formData.school === school.name 
                      ? 'bg-indigo-50 border-indigo-500 shadow-md' 
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-12 h-12 mb-2 bg-white rounded-lg p-1 shadow-sm overflow-hidden flex items-center justify-center">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-bold leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-600'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {getAvailablePrintPlaces().map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            {formData.printPlaces && formData.printPlaces.length > 0 && (
              <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 space-y-4">
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest">Загрузка макетов по местам</label>
                <div className="grid grid-cols-1 gap-3">
                  {formData.printPlaces.map(place => (
                    <div key={place} className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-100 shadow-sm group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} className="w-full h-full object-cover rounded-lg" alt={place} />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-gray-700">{place}</p>
                          <p className="text-[10px] text-gray-400">{formData.printImages?.[place] ? 'Файл выбран' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {formData.printImages?.[place] ? (
                          <button 
                            onClick={() => removeLocationImage(place)}
                            className="text-red-400 hover:text-red-600 p-2 text-sm"
                            type="button"
                          >✕</button>
                        ) : (
                          <>
                            <input 
                              type="file" 
                              id={`upload-${place}`} 
                              className="hidden" 
                              onChange={(e) => handleLocationImageUpload(place, e)} 
                              accept="image/*"
                            />
                            <label 
                              htmlFor={`upload-${place}`}
                              className="bg-indigo-600 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg cursor-pointer hover:bg-indigo-700 transition-colors"
                            >
                              Выбрать
                            </label>
                          </>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
            onExcelImport={(fileName) => setFormData(prev => ({ ...prev, excelFileName: fileName }))}
          />
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Цвет {isMultiColorMode ? '(выберите несколько)' : ''}
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => {
                const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
                return (
                  <button
                    key={c.hex}
                    onClick={() => isMultiColorMode ? toggleMultiColor(c.name) : setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all relative ${
                      isSelected ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  >
                    {isMultiColorMode && isSelected && (
                      <span className="absolute -top-2 -right-2 bg-indigo-600 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">✓</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
              <div className="flex gap-2">
                 {['Мальчик', 'Девочка'].map(g => (
                   <button
                     key={g}
                     onClick={() => setFormData({ ...formData, gender: g as any })}
                     className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                       formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                     }`}
                   >
                     {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                   </button>
                 ))}
              </div>
            </div>
          )}

          {productType === ProductType.TSHIRT && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.sleeve}
                onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
              >
                {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          )}

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
            <select 
              className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
              value={formData.size}
              onChange={e => setFormData({ ...formData, size: e.target.value })}
            >
              {productType === ProductType.CAP ? (
                <option>Универсальный</option>
              ) : (
                <>
                  <optgroup label="Дети">
                    {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                     {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </>
              )}
            </select>
          </div>

          {!isMultiColorMode ? (
            <div className="col-span-1 sm:col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >+</button>
              </div>
            </div>
          ) : (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <label className="block text-sm font-bold text-indigo-700 mb-4 uppercase tracking-wider text-xs">Выбранные цвета и количество</label>
               {Object.keys(multiColorSelections).length === 0 ? (
                 <p className="text-gray-400 text-sm italic py-2">Пожалуйста, выберите хотя бы один цвет выше</p>
               ) : (
                 <div className="space-y-3">
                   {Object.entries(multiColorSelections).map(([colorName, qty]) => {
                     const colorHex = COLORS.find(c => c.name === colorName)?.hex || '#ccc';
                     return (
                       <div key={colorName} className="flex items-center justify-between bg-white p-3 rounded-xl shadow-sm">
                         <div className="flex items-center gap-3">
                           <div className="w-6 h-6 rounded-md shadow-inner" style={{ backgroundColor: colorHex }}></div>
                           <span className="text-sm font-bold text-gray-700">{colorName}</span>
                         </div>
                         <div className="flex items-center gap-3">
                            <button 
                              onClick={() => updateMultiColorQty(colorName, -1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >-</button>
                            <span className="w-6 text-center text-sm font-black">{qty}</span>
                            <button 
                              onClick={() => updateMultiColorQty(colorName, 1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >+</button>
                         </div>
                       </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}
        </div>
      </div>

      <div className="mt-10 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          fullWidth
          disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0)}
        >
          {formData.id ? 'Обновить' : 'В корзину'}
        </Button>
      </div>
    </div>
  );
};

import axios from 'axios';
import { Order, OrderSubtype } from '../types';

const TRELLO_KEY = process.env.TRELLO_KEY;
const TRELLO_TOKEN = process.env.TRELLO_TOKEN;
const TRELLO_LIST_ID = process.env.TRELLO_LIST_ID || 'Egor2_List_ID';

export async function createTrelloCard(order: Order) {
  if (!TRELLO_KEY || !TRELLO_TOKEN) {
    console.warn('Trello API keys missing, skipping card creation');
    return;
  }

  const itemsDetails = order.items.map(item => {
    let detail = `- ${item.quantity}x ${item.type} (${item.subtype}), Цвет: ${item.color}, Размер: ${item.size}`;

    if (item.subtype === OrderSubtype.TEAM && item.players && item.players.length > 0) {
      detail += `\n  **СПИСОК КОМАНДЫ (${item.players.length} чел.):**`;
      item.players.forEach(p => {
        detail += `\n  • ${p.name} | №${p.number} | ${p.size} | ${p.gender} | Рукав: ${p.sleeve}`;
      });
    } else if (item.subtype === OrderSubtype.SCHOOL && item.school) {
      detail += `\n  Школа: ${item.school}`;
    }

    if (item.printPlaces && item.printPlaces.length > 0) {
      detail += `\n  Места печати: ${item.printPlaces.join(', ')}`;
    }

    return detail;
  }).join('\n\n');

  const description = `
**КЛИЕНТ:** ${order.customer.name}
**ТЕЛЕФОН:** ${order.customer.phone}
**EMAIL:** ${order.customer.email}
**АДРЕС:** ${order.customer.address || 'Не указан'}

---
**СОСТАВ ЗАКАЗА:**
${itemsDetails}

---
**КОММЕНТАРИЙ:** ${order.customer.comments || 'Нет'}
**ДАТА:** ${new Date(order.createdAt).toLocaleString()}
  `;

  try {
    await axios.post(`https://api.trello.com/1/cards`, null, {
      params: {
        idList: TRELLO_LIST_ID,
        key: TRELLO_KEY,
        token: TRELLO_TOKEN,
        name: `ЗАКАЗ ${order.orderNumber} - ${order.customer.name}`,
        desc: description,
        pos: 'top'
      }
    });
    console.log('Trello card created successfully');
  } catch (error) {
    console.error('Failed to create Trello card:', error);
  }
}

// Fix: Explicitly import Buffer to resolve 'Cannot find name Buffer' TypeScript error.
import { Buffer } from 'buffer';
import PDFDocument from 'pdfkit';
import { Order, OrderSubtype } from '../types';

export async function generateOrderPDF(order: Order): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    const doc = new PDFDocument({ margin: 50 });
    const chunks: Buffer[] = [];

    doc.on('data', (chunk) => chunks.push(chunk));
    doc.on('end', () => resolve(Buffer.concat(chunks)));
    doc.on('error', (err) => reject(err));

    // Header
    doc.fontSize(20).text('ЗАКАЗ - ' + order.orderNumber, { align: 'center' });
    doc.moveDown();

    // Status
    doc.fontSize(12).text(`Статус: ${order.status}`, { align: 'right' });
    doc.moveDown();

    // Customer Info
    doc.fontSize(14).text('Контактные данные клиента:', { underline: true });
    doc.fontSize(12).text(`Имя: ${order.customer.name}`);
    doc.text(`Телефон: ${order.customer.phone}`);
    doc.text(`Email: ${order.customer.email}`);
    if (order.customer.address) doc.text(`Адрес: ${order.customer.address}`);
    if (order.customer.comments) doc.text(`Комментарий: ${order.customer.comments}`);
    doc.moveDown();

    // Order Items
    doc.fontSize(14).text('Позиции заказа:', { underline: true });
    doc.moveDown(0.5);

    order.items.forEach((item, index) => {
      const displayType = item.type === 'TANK_TOP' ? 'Майка' : 
                          item.type === 'TSHIRT' ? 'Футболка' : 
                          item.type === 'HOODIE' ? 'Худи' : 'Шапка';

      doc.fontSize(12).text(`${index + 1}. ${displayType} [${item.subtype}]`, { bold: true });
      doc.fontSize(10);
      doc.text(`Цвет: ${item.color}`);
      doc.text(`Размер: ${item.size}`);
      doc.text(`Количество: ${item.quantity}`);

      if (item.school) doc.text(`Школа: ${item.school}`);
      if (item.gender && item.subtype !== OrderSubtype.TEAM) doc.text(`Пол: ${item.gender}`);
      if (item.sleeve && item.subtype !== OrderSubtype.TEAM) doc.text(`Рукав: ${item.sleeve}`);
      if (item.hoodieType) doc.text(`Тип худи: ${item.hoodieType}`);
      if (item.capType) doc.text(`Тип шапки: ${item.capType}`);

      if (item.printPlaces && item.printPlaces.length > 0) {
        doc.text(`Места печати: ${item.printPlaces.join(', ')}`);
      }

      if (item.subtype === OrderSubtype.TEAM && item.players && item.players.length > 0) {
        doc.moveDown(0.2);
        doc.fontSize(11).text('СПИСОК ИГРОКОВ КОМАНДЫ:', { bold: true });
        doc.fontSize(10);
        item.players.forEach((p, pIdx) => {
          doc.text(`  ${pIdx + 1}. ${p.name} — №${p.number} — Разм: ${p.size} — ${p.gender} — Рукав: ${p.sleeve}`);
        });
      }

      doc.moveDown();
    });

    doc.fontSize(10).text(`Дата создания: ${new Date(order.createdAt).toLocaleString()}`, { align: 'right' });

    doc.end();
  });
}

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: [] }));
    }

    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleLocationImageUpload = (location: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setFormData(prev => ({
          ...prev,
          printImages: {
            ...(prev.printImages || {}),
            [location]: base64
          }
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLocationImage = (location: string) => {
    setFormData(prev => {
      const newImages = { ...(prev.printImages || {}) };
      delete newImages[location];
      return { ...prev, printImages: newImages };
    });
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const toggleMultiColor = (colorName: string) => {
    setMultiColorSelections(prev => {
      const next = { ...prev };
      if (next[colorName]) {
        delete next[colorName];
      } else {
        next[colorName] = 1;
      }
      return next;
    });
  };

  const updateMultiColorQty = (colorName: string, delta: number) => {
    setMultiColorSelections(prev => ({
      ...prev,
      [colorName]: Math.max(1, (prev[colorName] || 0) + delta)
    }));
  };

  const handleAdd = () => {
    // Extract images list for backward compatibility if needed
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;

      const items: OrderItem[] = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));

      onAddToCart(items);
    } else if (isTeamMode) {
      // For teams, quantity must be equal to number of players
      if (!formData.players || formData.players.length === 0) {
        alert("Пожалуйста, добавьте хотя бы одного игрока в список команды.");
        return;
      }
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        // In team mode, the global size/gender is usually irrelevant, 
        // but we'll store 'Team' as a placeholder
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const getProductLabel = () => {
    switch(productType) {
      case ProductType.TSHIRT: return 'Футболка';
      case ProductType.HOODIE: return 'Худи';
      case ProductType.CAP: return 'Шапка';
      case ProductType.TANK_TOP: return 'Майка';
      default: return 'Товар';
    }
  };

  const getAvailablePrintPlaces = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {getProductLabel()}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(CapType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, capType: v as CapType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.capType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <div className="mb-4">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                    formData.school === school.name 
                      ? 'bg-indigo-50 border-indigo-500 shadow-md' 
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-12 h-12 mb-2 bg-white rounded-lg p-1 shadow-sm overflow-hidden flex items-center justify-center">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-bold leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-600'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {getAvailablePrintPlaces().map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            {formData.printPlaces && formData.printPlaces.length > 0 && (
              <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 space-y-4">
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest">Загрузка макетов по местам</label>
                <div className="grid grid-cols-1 gap-3">
                  {formData.printPlaces.map(place => (
                    <div key={place} className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-100 shadow-sm group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} className="w-full h-full object-cover rounded-lg" alt={place} />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-gray-700">{place}</p>
                          <p className="text-[10px] text-gray-400">{formData.printImages?.[place] ? 'Файл выбран' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {formData.printImages?.[place] ? (
                          <button 
                            onClick={() => removeLocationImage(place)}
                            className="text-red-400 hover:text-red-600 p-2 text-sm"
                            type="button"
                          >✕</button>
                        ) : (
                          <>
                            <input 
                              type="file" 
                              id={`upload-${place}`} 
                              className="hidden" 
                              onChange={(e) => handleLocationImageUpload(place, e)} 
                              accept="image/*"
                            />
                            <label 
                              htmlFor={`upload-${place}`}
                              className="bg-indigo-600 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg cursor-pointer hover:bg-indigo-700 transition-colors"
                            >
                              Выбрать
                            </label>
                          </>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
            onExcelImport={(fileName) => setFormData(prev => ({ ...prev, excelFileName: fileName }))}
          />
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Цвет {isMultiColorMode ? '(выберите несколько)' : ''}
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => {
                const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
                return (
                  <button
                    key={c.hex}
                    onClick={() => isMultiColorMode ? toggleMultiColor(c.name) : setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all relative ${
                      isSelected ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  >
                    {isMultiColorMode && isSelected && (
                      <span className="absolute -top-2 -right-2 bg-indigo-600 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">✓</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && !isTeamMode && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
              <div className="flex gap-2">
                 {['Мальчик', 'Девочка'].map(g => (
                   <button
                     key={g}
                     onClick={() => setFormData({ ...formData, gender: g as any })}
                     className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                       formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                     }`}
                   >
                     {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                   </button>
                 ))}
              </div>
            </div>
          )}

          {productType === ProductType.TSHIRT && !isTeamMode && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.sleeve}
                onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
              >
                {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          )}

          {!isTeamMode && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.size}
                onChange={e => setFormData({ ...formData, size: e.target.value })}
              >
                {productType === ProductType.CAP ? (
                  <option>Универсальный</option>
                ) : (
                  <>
                    <optgroup label="Дети">
                      {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                    <optgroup label="Взрослые">
                       {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                  </>
                )}
              </select>
            </div>
          )}

          {!isMultiColorMode && !isTeamMode ? (
            <div className="col-span-1 sm:col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >+</button>
              </div>
            </div>
          ) : isMultiColorMode ? (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <label className="block text-sm font-bold text-indigo-700 mb-4 uppercase tracking-wider text-xs">Выбранные цвета и количество</label>
               {Object.keys(multiColorSelections).length === 0 ? (
                 <p className="text-gray-400 text-sm italic py-2">Пожалуйста, выберите хотя бы один цвет выше</p>
               ) : (
                 <div className="space-y-3">
                   {Object.entries(multiColorSelections).map(([colorName, qty]) => {
                     const colorHex = COLORS.find(c => c.name === colorName)?.hex || '#ccc';
                     return (
                       <div key={colorName} className="flex items-center justify-between bg-white p-3 rounded-xl shadow-sm">
                         <div className="flex items-center gap-3">
                           <div className="w-6 h-6 rounded-md shadow-inner" style={{ backgroundColor: colorHex }}></div>
                           <span className="text-sm font-bold text-gray-700">{colorName}</span>
                         </div>
                         <div className="flex items-center gap-3">
                            <button 
                              onClick={() => updateMultiColorQty(colorName, -1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >-</button>
                            <span className="w-6 text-center text-sm font-black">{qty}</span>
                            <button 
                              onClick={() => updateMultiColorQty(colorName, 1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >+</button>
                         </div>
                       </div>
                     );
                   })}
                 </div>
               )}
            </div>
          ) : (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <p className="text-indigo-700 text-xs font-bold">Количество и размеры будут взяты из списка команды выше.</p>
               <p className="text-lg font-black text-indigo-800 mt-1">Всего: {formData.players?.length || 0} шт.</p>
            </div>
          )}
        </div>
      </div>

      <div className="mt-10 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          fullWidth
          disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0) || (isTeamMode && (!formData.players || formData.players.length === 0))}
        >
          {formData.id ? 'Обновить' : 'В корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, ProductType, OrderSubtype } from '../types';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const data = await apiService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error("Dashboard fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const updated = await apiService.updateOrder(orderNumber, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return updated;
    } catch (error) {
      console.error("Dashboard update error:", error);
      throw error;
    }
  };

  const handleSelectOrder = (order: Order) => {
    setSelectedOrder(order);
    if (!order.viewed) {
      updateOrderData(order.orderNumber, { viewed: true });
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const resetFilters = () => {
    setFilterText('');
    setStatusFilter('all');
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getItemIcon = (type: ProductType) => {
    switch(type) {
      case ProductType.TSHIRT: return '👕';
      case ProductType.HOODIE: return '🧥';
      case ProductType.CAP: return '🧢';
      case ProductType.TANK_TOP: return '🎽';
      default: return '📦';
    }
  };

  const getStatusCount = (status: OrderStatus) => orders.filter(o => o.status === status).length;
  const getUnreadCount = (status: OrderStatus) => orders.filter(o => o.status === status && !o.viewed).length;

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <Button onClick={fetchOrders} variant="outline" size="sm" className="w-full md:w-auto">
          🔄 Обновить данные
        </Button>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
        {(Object.keys(STATUS_LABELS) as OrderStatus[]).map((status) => {
          const unread = getUnreadCount(status);
          return (
            <div 
              key={status} 
              onClick={() => setStatusFilter(status)}
              className={`p-5 rounded-2xl cursor-pointer transition-all border-2 relative overflow-hidden ${
                statusFilter === status 
                  ? 'bg-indigo-50 border-indigo-500 shadow-md scale-[1.02]' 
                  : 'bg-white border-gray-100 hover:border-indigo-200'
              }`}
            >
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{STATUS_LABELS[status]}</p>
              <div className="flex items-center justify-between">
                <span className="text-3xl font-black text-gray-800">{getStatusCount(status)}</span>
                <span className={`w-3 h-3 rounded-full ${getStatusColor(status).split(' ')[0]}`}></span>
              </div>
              {unread > 0 && (
                <div className="absolute top-2 right-2 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse"></span>
                  <span className="text-[9px] font-bold text-indigo-600 uppercase">{unread} нов.</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-4 mb-6 bg-gray-50 p-6 rounded-2xl border border-gray-100">
        <div className="flex-1 w-full">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Поиск</label>
          <input 
            type="text" 
            placeholder="Имя, ID или заметки..."
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
        <div className="w-full md:w-64">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Фильтр по статусу</label>
          <select 
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none cursor-pointer text-sm shadow-sm font-medium"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>
        {(statusFilter !== 'all' || filterText) && (
          <button 
            onClick={resetFilters}
            className="text-xs font-bold text-indigo-600 hover:text-indigo-800 px-2 py-3 transition-colors"
          >
            Очистить
          </button>
        )}
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация данных...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Действия</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredOrders.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-gray-400 italic">Заказы не найдены</td>
                </tr>
              ) : (
                filteredOrders.map((order) => (
                  <tr 
                    key={order.orderNumber} 
                    className="hover:bg-indigo-50/50 transition-colors group cursor-pointer"
                    onClick={() => handleSelectOrder(order)}
                  >
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {new Date(order.createdAt).toLocaleDateString()}
                      <div className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {!order.viewed && (
                          <span className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse shadow-sm shadow-indigo-200" title="Не просмотрено"></span>
                        )}
                        <span className="font-mono text-[10px] font-bold text-indigo-500">
                          {order.orderNumber.split('-')[1]}
                        </span>
                        {order.internalNotes && (
                          <span className="inline-block w-2 h-2 rounded-full bg-amber-400 shadow-sm" title="Есть внутренняя заметка"></span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-800">{order.customer.name}</div>
                      <div className="text-[10px] text-gray-400">{order.customer.phone}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex -space-x-2">
                        {order.items.slice(0, 3).map((item, idx) => (
                          <div key={idx} className="w-8 h-8 rounded-full bg-white border-2 border-gray-100 flex items-center justify-center text-sm shadow-sm" title={item.type}>
                            {getItemIcon(item.type)}
                          </div>
                        ))}
                        {order.items.length > 3 && (
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-500">
                            +{order.items.length - 3}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <select 
                        className={`text-xs font-bold rounded-full px-3 py-1 outline-none appearance-none cursor-pointer border-none shadow-sm ${getStatusColor(order.status)}`}
                        value={order.status}
                        onClick={(e) => e.stopPropagation()} 
                        onChange={(e) => updateOrderData(order.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                      >
                        {Object.entries(STATUS_LABELS).map(([key, label]) => (
                          <option key={key} value={key}>{label}</option>
                        ))}
                      </select>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-lg">
                      👁️
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {selectedOrder && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <div>
                <h3 className="text-xl font-bold text-gray-800">Детали заказа {selectedOrder.orderNumber}</h3>
                <p className="text-sm text-gray-500">{new Date(selectedOrder.createdAt).toLocaleString()}</p>
              </div>
              <button onClick={() => setSelectedOrder(null)} className="text-gray-400 hover:text-gray-600 text-2xl transition-colors">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
              <div className="grid md:grid-cols-2 gap-6 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Клиент</h4>
                  <p className="font-bold text-gray-800 text-lg">{selectedOrder.customer.name}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">✉️ {selectedOrder.customer.email}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">📞 {selectedOrder.customer.phone}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Доставка и примечания</h4>
                  <p className="text-sm text-gray-700"><strong>Адрес:</strong> {selectedOrder.customer.address || 'Не указан'}</p>
                  <p className="text-sm text-gray-700 mt-1"><strong>От клиента:</strong> {selectedOrder.customer.comments || 'Нет'}</p>
                </div>
              </div>

              <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-600 uppercase tracking-wider mb-2">📝 Внутренние заметки</h4>
                <textarea 
                  className="w-full p-4 bg-white border border-amber-200 rounded-xl outline-none focus:ring-2 ring-amber-400 text-sm h-24 resize-none shadow-inner"
                  value={editingNotes}
                  onChange={(e) => setEditingNotes(e.target.value)}
                  placeholder="Добавьте рабочую заметку..."
                />
                <div className="mt-2 flex justify-end">
                   <Button 
                    size="sm" 
                    variant="primary" 
                    className="bg-amber-600 hover:bg-amber-700 shadow-sm" 
                    onClick={handleSaveNotes}
                    disabled={isSavingNotes || editingNotes === (selectedOrder.internalNotes || '')}
                  >
                    {isSavingNotes ? 'Сохранение...' : 'Сохранить заметку'}
                  </Button>
                </div>
              </div>

              <div className="space-y-6">
                <h4 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                  📦 Состав заказа <span className="text-sm font-normal text-gray-400">({selectedOrder.items.length} поз.)</span>
                </h4>
                {selectedOrder.items.map((item, idx) => {
                  const isTeamItem = item.subtype === OrderSubtype.TEAM;
                  return (
                    <div key={idx} className="border border-gray-100 rounded-2xl p-6 hover:border-indigo-200 transition-all bg-white shadow-sm">
                      <div className="flex flex-col md:flex-row gap-6">
                        <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center text-3xl shrink-0">
                          {getItemIcon(item.type)}
                        </div>
                        <div className="flex-1">
                          <div className="flex justify-between items-start mb-4">
                            <div>
                              <h5 className="text-lg font-bold text-gray-800 leading-tight">
                                {item.type === ProductType.TSHIRT ? 'Футболка' : item.type === ProductType.HOODIE ? 'Худи' : item.type === ProductType.CAP ? 'Шапка' : 'Майка'} 
                                <span className="text-indigo-600 ml-1">[{item.subtype}]</span>
                              </h5>
                              <div className="flex flex-wrap gap-2 mt-2">
                                <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">{item.color}</span>
                                {!isTeamItem && <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">Размер: {item.size}</span>}
                                <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${isTeamItem ? 'bg-purple-100 text-purple-700' : 'bg-indigo-100 text-indigo-700'}`}>
                                  {isTeamItem ? `Состав: ${item.players?.length || item.quantity} чел.` : `Кол-во: ${item.quantity} шт.`}
                                </span>
                              </div>
                            </div>
                          </div>
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm bg-gray-50/50 p-4 rounded-xl border border-gray-100">
                            {item.school && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Школа</p><p className="text-gray-800 font-medium">{item.school}</p></div>)}
                            {item.gender && !isTeamItem && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Пол</p><p className="text-gray-800 font-medium">{item.gender}</p></div>)}
                            {item.sleeve && !isTeamItem && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Рукав</p><p className="text-gray-800 font-medium">{item.sleeve}</p></div>)}
                            {item.hoodieType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Тип худи</p><p className="text-gray-800 font-medium">{item.hoodieType}</p></div>)}
                            {item.capType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Модель шапки</p><p className="text-gray-800 font-medium">{item.capType}</p></div>)}
                            {item.printPlaces && item.printPlaces.length > 0 && (
                               <div className="sm:col-span-2">
                                 <p className="text-gray-400 text-xs font-bold uppercase mb-1">Места печати</p>
                                 <div className="flex flex-wrap gap-1">{item.printPlaces.map(p => (<span key={p} className="bg-white px-2 py-0.5 rounded border border-gray-200 text-xs text-gray-700 font-medium">{p}</span>))}</div>
                               </div>
                            )}
                          </div>

                          {/* Player Roster - Critical for Team Orders */}
                          {item.players && item.players.length > 0 ? (
                            <div className="mt-4 animate-in slide-in-from-top-2 duration-300">
                              <p className="text-indigo-600 text-xs font-black uppercase mb-2 tracking-widest flex items-center gap-2">
                                <span>📋 Список команды</span>
                                <span className="bg-indigo-100 px-2 py-0.5 rounded-full text-indigo-700">{item.players.length} чел.</span>
                              </p>
                              <div className="overflow-hidden border border-gray-100 rounded-xl shadow-inner">
                                <table className="min-w-full divide-y divide-gray-100">
                                  <thead className="bg-gray-50"><tr className="text-left text-[10px] font-bold text-gray-500 uppercase"><th className="px-3 py-2">Имя</th><th className="px-3 py-2 text-center">№</th><th className="px-3 py-2">Пол</th><th className="px-3 py-2">Разм.</th><th className="px-3 py-2">Рукав</th></tr></thead>
                                  <tbody className="bg-white divide-y divide-gray-100 text-xs">
                                    {item.players.map((player, pIdx) => (
                                      <tr key={player.id || pIdx} className="hover:bg-gray-50 transition-colors">
                                        <td className="px-3 py-2 font-bold text-gray-800">{player.name}</td>
                                        <td className="px-3 py-2 text-center text-indigo-600 font-black">{player.number}</td>
                                        <td className="px-3 py-2">{player.gender}</td>
                                        <td className="px-3 py-2 font-black bg-indigo-50/30">{player.size}</td>
                                        <td className="px-3 py-2 text-gray-500">{player.sleeve}</td>
                                      </tr>
                                    ))}
                                  </tbody>
                                </table>
                              </div>
                            </div>
                          ) : isTeamItem && (
                            <div className="mt-4 p-4 bg-red-50 rounded-xl border border-red-100 text-red-500 text-sm italic">
                              ⚠️ Внимание: Данные о составе команды отсутствуют в заказе.
                            </div>
                          )}

                          {item.images && item.images.length > 0 && (
                            <div className="mt-4">
                               <p className="text-gray-400 text-xs font-bold uppercase mb-2">Файлы макетов ({item.images.length})</p>
                               <div className="flex flex-wrap gap-2">{item.images.map((img, i) => (<a key={i} href={img} target="_blank" rel="noreferrer" className="block w-20 h-20 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 hover:border-indigo-400 transition-all shadow-sm"><img src={img} alt="layout" className="w-full h-full object-cover" /></a>))}</div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div className="p-6 border-t border-gray-100 flex justify-between items-center bg-gray-50">
              <div className="flex gap-2">
                <Button onClick={() => setSelectedOrder(null)} variant="outline">Закрыть</Button>
                <Button onClick={() => window.print()} variant="outline" className="hidden sm:inline-flex">🖨️ Печать</Button>
              </div>
              <div className="flex items-center gap-3">
                <span className="text-xs font-bold text-gray-400 uppercase">Статус:</span>
                <select 
                  className={`text-sm font-bold rounded-xl px-4 py-2 outline-none border border-gray-200 shadow-sm transition-all focus:ring-2 ring-indigo-500 ${getStatusColor(selectedOrder.status)}`}
                  value={selectedOrder.status}
                  onChange={(e) => updateOrderData(selectedOrder.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                >
                  {Object.entries(STATUS_LABELS).map(([key, label]) => (<option key={key} value={key}>{label}</option>))}
                </select>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, ProductType, OrderSubtype } from '../types';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const data = await apiService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error("Dashboard fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const updated = await apiService.updateOrder(orderNumber, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return updated;
    } catch (error) {
      console.error("Dashboard update error:", error);
      throw error;
    }
  };

  const handleSelectOrder = (order: Order) => {
    setSelectedOrder(order);
    if (!order.viewed) {
      updateOrderData(order.orderNumber, { viewed: true });
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const resetFilters = () => {
    setFilterText('');
    setStatusFilter('all');
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getItemIcon = (type: ProductType) => {
    switch(type) {
      case ProductType.TSHIRT: return '👕';
      case ProductType.HOODIE: return '🧥';
      case ProductType.CAP: return '🧢';
      case ProductType.TANK_TOP: return '🎽';
      default: return '📦';
    }
  };

  const getStatusCount = (status: OrderStatus) => orders.filter(o => o.status === status).length;
  const getUnreadCount = (status: OrderStatus) => orders.filter(o => o.status === status && !o.viewed).length;

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <Button onClick={fetchOrders} variant="outline" size="sm" className="w-full md:w-auto">
          🔄 Обновить данные
        </Button>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
        {(Object.keys(STATUS_LABELS) as OrderStatus[]).map((status) => {
          const unread = getUnreadCount(status);
          return (
            <div 
              key={status} 
              onClick={() => setStatusFilter(status)}
              className={`p-5 rounded-2xl cursor-pointer transition-all border-2 relative overflow-hidden ${
                statusFilter === status 
                  ? 'bg-indigo-50 border-indigo-500 shadow-md scale-[1.02]' 
                  : 'bg-white border-gray-100 hover:border-indigo-200'
              }`}
            >
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{STATUS_LABELS[status]}</p>
              <div className="flex items-center justify-between">
                <span className="text-3xl font-black text-gray-800">{getStatusCount(status)}</span>
                <span className={`w-3 h-3 rounded-full ${getStatusColor(status).split(' ')[0]}`}></span>
              </div>
              {unread > 0 && (
                <div className="absolute top-2 right-2 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse"></span>
                  <span className="text-[9px] font-bold text-indigo-600 uppercase">{unread} нов.</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-4 mb-6 bg-gray-50 p-6 rounded-2xl border border-gray-100">
        <div className="flex-1 w-full">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Поиск</label>
          <input 
            type="text" 
            placeholder="Имя, ID или заметки..."
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
        <div className="w-full md:w-64">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Фильтр по статусу</label>
          <select 
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none cursor-pointer text-sm shadow-sm font-medium"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>
        {(statusFilter !== 'all' || filterText) && (
          <button 
            onClick={resetFilters}
            className="text-xs font-bold text-indigo-600 hover:text-indigo-800 px-2 py-3 transition-colors"
          >
            Очистить
          </button>
        )}
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация данных...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Действия</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredOrders.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-gray-400 italic">Заказы не найдены</td>
                </tr>
              ) : (
                filteredOrders.map((order) => (
                  <tr 
                    key={order.orderNumber} 
                    className="hover:bg-indigo-50/50 transition-colors group cursor-pointer"
                    onClick={() => handleSelectOrder(order)}
                  >
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {new Date(order.createdAt).toLocaleDateString()}
                      <div className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {!order.viewed && (
                          <span className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse shadow-sm shadow-indigo-200" title="Не просмотрено"></span>
                        )}
                        <span className="font-mono text-[10px] font-bold text-indigo-500">
                          {order.orderNumber.split('-')[1]}
                        </span>
                        {order.internalNotes && (
                          <span className="inline-block w-2 h-2 rounded-full bg-amber-400 shadow-sm" title="Есть внутренняя заметка"></span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-800">{order.customer.name}</div>
                      <div className="text-[10px] text-gray-400">{order.customer.phone}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex -space-x-2">
                        {order.items.slice(0, 3).map((item, idx) => (
                          <div key={idx} className="w-8 h-8 rounded-full bg-white border-2 border-gray-100 flex items-center justify-center text-sm shadow-sm" title={item.type}>
                            {getItemIcon(item.type)}
                          </div>
                        ))}
                        {order.items.length > 3 && (
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-500">
                            +{order.items.length - 3}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <select 
                        className={`text-xs font-bold rounded-full px-3 py-1 outline-none appearance-none cursor-pointer border-none shadow-sm ${getStatusColor(order.status)}`}
                        value={order.status}
                        onClick={(e) => e.stopPropagation()} 
                        onChange={(e) => updateOrderData(order.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                      >
                        {Object.entries(STATUS_LABELS).map(([key, label]) => (
                          <option key={key} value={key}>{label}</option>
                        ))}
                      </select>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-lg">
                      👁️
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {selectedOrder && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <div>
                <h3 className="text-xl font-bold text-gray-800">Детали заказа {selectedOrder.orderNumber}</h3>
                <p className="text-sm text-gray-500">{new Date(selectedOrder.createdAt).toLocaleString()}</p>
              </div>
              <button onClick={() => setSelectedOrder(null)} className="text-gray-400 hover:text-gray-600 text-2xl transition-colors">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
              <div className="grid md:grid-cols-2 gap-6 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Клиент</h4>
                  <p className="font-bold text-gray-800 text-lg">{selectedOrder.customer.name}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">✉️ {selectedOrder.customer.email}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">📞 {selectedOrder.customer.phone}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Доставка и примечания</h4>
                  <p className="text-sm text-gray-700"><strong>Адрес:</strong> {selectedOrder.customer.address || 'Не указан'}</p>
                  <p className="text-sm text-gray-700 mt-1"><strong>От клиента:</strong> {selectedOrder.customer.comments || 'Нет'}</p>
                </div>
              </div>

              <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-600 uppercase tracking-wider mb-2">📝 Внутренние заметки</h4>
                <textarea 
                  className="w-full p-4 bg-white border border-amber-200 rounded-xl outline-none focus:ring-2 ring-amber-400 text-sm h-24 resize-none shadow-inner"
                  value={editingNotes}
                  onChange={(e) => setEditingNotes(e.target.value)}
                  placeholder="Добавьте рабочую заметку..."
                />
                <div className="mt-2 flex justify-end">
                   <Button 
                    size="sm" 
                    variant="primary" 
                    className="bg-amber-600 hover:bg-amber-700 shadow-sm" 
                    onClick={handleSaveNotes}
                    disabled={isSavingNotes || editingNotes === (selectedOrder.internalNotes || '')}
                  >
                    {isSavingNotes ? 'Сохранение...' : 'Сохранить заметку'}
                  </Button>
                </div>
              </div>

              <div className="space-y-6">
                <h4 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                  📦 Состав заказа <span className="text-sm font-normal text-gray-400">({selectedOrder.items.length} поз.)</span>
                </h4>
                {selectedOrder.items.map((item, idx) => {
                  const isTeamItem = item.subtype === OrderSubtype.TEAM;
                  // Ensure players is an array even if missing in old data
                  const playersList = Array.isArray(item.players) ? item.players : [];

                  return (
                    <div key={idx} className="border border-gray-100 rounded-2xl p-6 hover:border-indigo-200 transition-all bg-white shadow-sm">
                      <div className="flex flex-col md:flex-row gap-6">
                        <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center text-3xl shrink-0">
