                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div className="p-6 border-t border-gray-100 flex justify-between items-center bg-gray-50">
              <div className="flex gap-2">
                <Button onClick={() => setSelectedOrder(null)} variant="outline">Закрыть</Button>
                <Button onClick={() => window.print()} variant="outline" className="hidden sm:inline-flex">🖨️ Печать</Button>
              </div>
              <div className="flex items-center gap-3">
                <span className="text-xs font-bold text-gray-400 uppercase">Статус:</span>
                <select 
                  className={`text-sm font-bold rounded-xl px-4 py-2 outline-none border border-gray-200 shadow-sm transition-all focus:ring-2 ring-indigo-500 ${getStatusColor(selectedOrder.status)}`}
                  value={selectedOrder.status}
                  onChange={(e) => updateOrderData(selectedOrder.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                >
                  {Object.entries(STATUS_LABELS).map(([key, label]) => (<option key={key} value={key}>{label}</option>))}
                </select>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, ProductType, OrderSubtype } from '../types';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  // Bulk selection state
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const data = await apiService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error("Dashboard fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const updated = await apiService.updateOrder(orderNumber, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return updated;
    } catch (error) {
      console.error("Dashboard update error:", error);
      throw error;
    }
  };

  const handleBulkStatusUpdate = async (newStatus: OrderStatus) => {
    if (selectedOrderIds.size === 0) return;
    setIsBulkUpdating(true);

    try {
      const promises = Array.from(selectedOrderIds).map(id => 
        apiService.updateOrder(id, { status: newStatus, viewed: true })
      );

      await Promise.all(promises);

      setOrders(prev => prev.map(o => 
        selectedOrderIds.has(o.orderNumber) ? { ...o, status: newStatus, viewed: true } : o
      ));

      setSelectedOrderIds(new Set());
      alert(`Обновлено заказов: ${selectedOrderIds.size}`);
    } catch (error) {
      console.error("Bulk update error:", error);
      alert("Некоторые заказы не удалось обновить.");
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const toggleOrderSelection = (id: string, event?: React.MouseEvent) => {
    if (event) event.stopPropagation();
    setSelectedOrderIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const handleSelectAll = (visibleOrders: Order[]) => {
    if (selectedOrderIds.size === visibleOrders.length && visibleOrders.length > 0) {
      setSelectedOrderIds(new Set());
    } else {
      setSelectedOrderIds(new Set(visibleOrders.map(o => o.orderNumber)));
    }
  };

  const handleSelectOrder = (order: Order) => {
    setSelectedOrder(order);
    if (!order.viewed) {
      updateOrderData(order.orderNumber, { viewed: true });
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const resetFilters = () => {
    setFilterText('');
    setStatusFilter('all');
    setSelectedOrderIds(new Set());
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getItemIcon = (type: ProductType) => {
    switch(type) {
      case ProductType.TSHIRT: return '👕';
      case ProductType.HOODIE: return '🧥';
      case ProductType.CAP: return '🧢';
      case ProductType.TANK_TOP: return '🎽';
      default: return '📦';
    }
  };

  const getStatusCount = (status: OrderStatus) => orders.filter(o => o.status === status).length;
  const getUnreadCount = (status: OrderStatus) => orders.filter(o => o.status === status && !o.viewed).length;

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500 relative">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <Button onClick={fetchOrders} variant="outline" size="sm" className="w-full md:w-auto">
          🔄 Обновить данные
        </Button>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
        {(Object.keys(STATUS_LABELS) as OrderStatus[]).map((status) => {
          const unread = getUnreadCount(status);
          return (
            <div 
              key={status} 
              onClick={() => setStatusFilter(status)}
              className={`p-5 rounded-2xl cursor-pointer transition-all border-2 relative overflow-hidden ${
                statusFilter === status 
                  ? 'bg-indigo-50 border-indigo-500 shadow-md scale-[1.02]' 
                  : 'bg-white border-gray-100 hover:border-indigo-200'
              }`}
            >
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{STATUS_LABELS[status]}</p>
              <div className="flex items-center justify-between">
                <span className="text-3xl font-black text-gray-800">{getStatusCount(status)}</span>
                <span className={`w-3 h-3 rounded-full ${getStatusColor(status).split(' ')[0]}`}></span>
              </div>
              {unread > 0 && (
                <div className="absolute top-2 right-2 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse"></span>
                  <span className="text-[9px] font-bold text-indigo-600 uppercase">{unread} нов.</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-4 mb-6 bg-gray-50 p-6 rounded-2xl border border-gray-100">
        <div className="flex-1 w-full">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Поиск</label>
          <input 
            type="text" 
            placeholder="Имя, ID или заметки..."
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
        <div className="w-full md:w-64">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Фильтр по статусу</label>
          <select 
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none cursor-pointer text-sm shadow-sm font-medium"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>
        {(statusFilter !== 'all' || filterText) && (
          <button 
            onClick={resetFilters}
            className="text-xs font-bold text-indigo-600 hover:text-indigo-800 px-2 py-3 transition-colors"
          >
            Очистить
          </button>
        )}
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация данных...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-4 text-left">
                  <input 
                    type="checkbox" 
                    className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                    checked={filteredOrders.length > 0 && selectedOrderIds.size === filteredOrders.length}
                    onChange={() => handleSelectAll(filteredOrders)}
                  />
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Действия</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredOrders.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-gray-400 italic">Заказы не найдены</td>
                </tr>
              ) : (
                filteredOrders.map((order) => (
                  <tr 
                    key={order.orderNumber} 
                    className={`transition-colors group cursor-pointer ${selectedOrderIds.has(order.orderNumber) ? 'bg-indigo-50' : 'hover:bg-indigo-50/50'}`}
                    onClick={() => handleSelectOrder(order)}
                  >
                    <td className="px-4 py-4 whitespace-nowrap" onClick={(e) => e.stopPropagation()}>
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                        checked={selectedOrderIds.has(order.orderNumber)}
                        onChange={() => toggleOrderSelection(order.orderNumber)}
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {new Date(order.createdAt).toLocaleDateString()}
                      <div className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {!order.viewed && (
                          <span className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse shadow-sm shadow-indigo-200" title="Не просмотрено"></span>
                        )}
                        <span className="font-mono text-[10px] font-bold text-indigo-500">
                          {order.orderNumber.split('-')[1]}
                        </span>
                        {order.internalNotes && (
                          <span className="inline-block w-2 h-2 rounded-full bg-amber-400 shadow-sm" title="Есть внутренняя заметка"></span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-800">{order.customer.name}</div>
                      <div className="text-[10px] text-gray-400">{order.customer.phone}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex -space-x-2">
                        {order.items.slice(0, 3).map((item, idx) => (
                          <div key={idx} className="w-8 h-8 rounded-full bg-white border-2 border-gray-100 flex items-center justify-center text-sm shadow-sm" title={item.type}>
                            {getItemIcon(item.type)}
                          </div>
                        ))}
                        {order.items.length > 3 && (
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-500">
                            +{order.items.length - 3}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <select 
                        className={`text-xs font-bold rounded-full px-3 py-1 outline-none appearance-none cursor-pointer border-none shadow-sm ${getStatusColor(order.status)}`}
                        value={order.status}
                        onClick={(e) => e.stopPropagation()} 
                        onChange={(e) => updateOrderData(order.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                      >
                        {Object.entries(STATUS_LABELS).map(([key, label]) => (
                          <option key={key} value={key}>{label}</option>
                        ))}
                      </select>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-lg">
                      👁️
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* Floating Bulk Actions Bar */}
      {selectedOrderIds.size > 0 && (
        <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 bg-gray-900 text-white rounded-2xl px-6 py-4 shadow-2xl flex items-center gap-6 z-[60] animate-in slide-in-from-bottom-4 duration-300 border border-gray-700">
          <div className="flex items-center gap-3 pr-6 border-r border-gray-700">
            <span className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center font-bold text-sm">
              {selectedOrderIds.size}
            </span>
            <span className="text-sm font-medium text-gray-300">выбрано</span>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => handleBulkStatusUpdate('Processing')}
              disabled={isBulkUpdating}
              className="px-4 py-2 bg-yellow-500 hover:bg-yellow-600 text-black text-xs font-bold rounded-xl transition-colors disabled:opacity-50"
            >
              В работу
            </button>
            <button 
              onClick={() => handleBulkStatusUpdate('Completed')}
              disabled={isBulkUpdating}
              className="px-4 py-2 bg-green-500 hover:bg-green-600 text-white text-xs font-bold rounded-xl transition-colors disabled:opacity-50"
            >
              Завершить
            </button>
            <button 
              onClick={() => handleBulkStatusUpdate('Cancelled')}
              disabled={isBulkUpdating}
              className="px-4 py-2 bg-red-500 hover:bg-red-600 text-white text-xs font-bold rounded-xl transition-colors disabled:opacity-50"
            >
              Отменить
            </button>
          </div>

          <button 
            onClick={() => setSelectedOrderIds(new Set())}
            className="text-gray-400 hover:text-white transition-colors"
            title="Отменить выбор"
          >
            ✕
          </button>
        </div>
      )}

      {selectedOrder && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <div>
                <h3 className="text-xl font-bold text-gray-800">Детали заказа {selectedOrder.orderNumber}</h3>
                <p className="text-sm text-gray-500">{new Date(selectedOrder.createdAt).toLocaleString()}</p>
              </div>
              <button onClick={() => setSelectedOrder(null)} className="text-gray-400 hover:text-gray-600 text-2xl transition-colors">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
              <div className="grid md:grid-cols-2 gap-6 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Клиент</h4>
                  <p className="font-bold text-gray-800 text-lg">{selectedOrder.customer.name}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">✉️ {selectedOrder.customer.email}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">📞 {selectedOrder.customer.phone}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Доставка и примечания</h4>
                  <p className="text-sm text-gray-700"><strong>Адрес:</strong> {selectedOrder.customer.address || 'Не указан'}</p>
                  <p className="text-sm text-gray-700 mt-1"><strong>От клиента:</strong> {selectedOrder.customer.comments || 'Нет'}</p>
                </div>
              </div>

              <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-600 uppercase tracking-wider mb-2">📝 Внутренние заметки</h4>
                <textarea 
                  className="w-full p-4 bg-white border border-amber-200 rounded-xl outline-none focus:ring-2 ring-amber-400 text-sm h-24 resize-none shadow-inner"
                  value={editingNotes}
                  onChange={(e) => setEditingNotes(e.target.value)}
                  placeholder="Добавьте рабочую заметку..."
                />
                <div className="mt-2 flex justify-end">
                   <Button 
                    size="sm" 
                    variant="primary" 
                    className="bg-amber-600 hover:bg-amber-700 shadow-sm" 
                    onClick={handleSaveNotes}
                    disabled={isSavingNotes || editingNotes === (selectedOrder.internalNotes || '')}
                  >
                    {isSavingNotes ? 'Сохранение...' : 'Сохранить заметку'}
                  </Button>
                </div>
              </div>

              <div className="space-y-6">
                <h4 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                  📦 Состав заказа <span className="text-sm font-normal text-gray-400">({selectedOrder.items.length} поз.)</span>
                </h4>
                {selectedOrder.items.map((item, idx) => {
                  const isTeamItem = item.subtype === OrderSubtype.TEAM;
                  // Ensure players is an array even if missing in old data
                  const playersList = Array.isArray(item.players) ? item.players : [];

                  return (
                    <div key={idx} className="border border-gray-100 rounded-2xl p-6 hover:border-indigo-200 transition-all bg-white shadow-sm">
                      <div className="flex flex-col md:flex-row gap-6">
                        <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center text-3xl shrink-0">
                          {getItemIcon(item.type)}
                        </div>
                        <div className="flex-1">
                          <div className="flex justify-between items-start mb-4">
                            <div>
                              <h5 className="text-lg font-bold text-gray-800 leading-tight">
                                {item.type === ProductType.TSHIRT ? 'Футболка' : item.type === ProductType.HOODIE ? 'Худи' : item.type === ProductType.CAP ? 'Шапка' : 'Майка'} 
                                <span className="text-indigo-600 ml-1">[{item.subtype}]</span>
                              </h5>
                              <div className="flex flex-wrap gap-2 mt-2">
                                <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">{item.color}</span>
                                {!isTeamItem && <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">Размер: {item.size}</span>}
                                <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${isTeamItem ? 'bg-purple-100 text-purple-700' : 'bg-indigo-100 text-indigo-700'}`}>
                                  {isTeamItem ? `Состав: ${playersList.length || item.quantity} чел.` : `Кол-во: ${item.quantity} шт.`}
                                </span>
                              </div>
                            </div>
                          </div>
                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm bg-gray-50/50 p-4 rounded-xl border border-gray-100">
                            {item.school && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Школа</p><p className="text-gray-800 font-medium">{item.school}</p></div>)}
                            {item.gender && !isTeamItem && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Пол</p><p className="text-gray-800 font-medium">{item.gender}</p></div>)}
                            {item.sleeve && !isTeamItem && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Рукав</p><p className="text-gray-800 font-medium">{item.sleeve}</p></div>)}
                            {item.hoodieType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Тип худи</p><p className="text-gray-800 font-medium">{item.hoodieType}</p></div>)}
                            {item.capType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Модель шапки</p><p className="text-gray-800 font-medium">{item.capType}</p></div>)}
                            {item.printPlaces && item.printPlaces.length > 0 && (
                               <div className="sm:col-span-2">
                                 <p className="text-gray-400 text-xs font-bold uppercase mb-1">Места печати</p>
                                 <div className="flex flex-wrap gap-1">{item.printPlaces.map(p => (<span key={p} className="bg-white px-2 py-0.5 rounded border border-gray-200 text-xs text-gray-700 font-medium">{p}</span>))}</div>
                               </div>
                            )}
                          </div>

                          {/* Player Roster - Enhanced Rendering */}
                          {isTeamItem && (
                            <div className="mt-6 border-t pt-4 animate-in slide-in-from-top-2 duration-300">
                              <p className="text-indigo-600 text-[10px] font-black uppercase mb-3 tracking-widest flex items-center gap-2">
                                <span>📋 СПИСОК КОМАНДЫ ДЛЯ ПЕЧАТИ</span>
                                <span className="bg-indigo-600 text-white px-2 py-0.5 rounded-full text-[9px]">{playersList.length} ИГРОКОВ</span>
                              </p>

                              {playersList.length > 0 ? (
                                <div className="overflow-hidden border border-indigo-100 rounded-xl shadow-sm">
                                  <table className="min-w-full divide-y divide-indigo-50">
                                    <thead className="bg-indigo-50/50">
                                      <tr className="text-left text-[9px] font-black text-indigo-400 uppercase">
                                        <th className="px-3 py-2">Имя</th>
                                        <th className="px-3 py-2 text-center">Номер</th>
                                        <th className="px-3 py-2">Пол</th>
                                        <th className="px-3 py-2 text-center">Размер</th>
                                        <th className="px-3 py-2">Рукав</th>
                                      </tr>
                                    </thead>
                                    <tbody className="bg-white divide-y divide-gray-50 text-[11px]">
                                      {playersList.map((player, pIdx) => (
                                        <tr key={player.id || pIdx} className="hover:bg-indigo-50/20 transition-colors">
                                          <td className="px-3 py-2 font-bold text-gray-800">{player.name || '—'}</td>
                                          <td className="px-3 py-2 text-center text-indigo-600 font-black">{player.number || '—'}</td>
                                          <td className="px-3 py-2 text-gray-500">{player.gender}</td>
                                          <td className="px-3 py-2 text-center font-black bg-indigo-50/30 text-indigo-700">{player.size}</td>
                                          <td className="px-3 py-2 text-gray-400">{player.sleeve}</td>
                                        </tr>
                                      ))}
                                    </tbody>
                                  </table>
                                </div>
                              ) : (
                                <div className="p-6 bg-red-50 rounded-xl border border-red-100 flex flex-col items-center gap-2 text-center">
                                  <span className="text-2xl">⚠️</span>
                                  <p className="text-red-600 font-bold text-sm">Данные об игроках отсутствуют!</p>
                                  <p className="text-red-400 text-xs">Проверьте корректность заполнения формы или целостность базы данных.</p>
                                </div>
                              )}
                            </div>
                          )}

                          {item.images && item.images.length > 0 && (
                            <div className="mt-4">
                               <p className="text-gray-400 text-[10px] font-black uppercase mb-2 tracking-widest">Файлы макетов ({item.images.length})</p>
                               <div className="flex flex-wrap gap-2">{item.images.map((img, i) => (<a key={i} href={img} target="_blank" rel="noreferrer" className="block w-20 h-20 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 hover:border-indigo-400 transition-all shadow-sm"><img src={img} alt="layout" className="w-full h-full object-cover" /></a>))}</div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div className="p-6 border-t border-gray-100 flex justify-between items-center bg-gray-50">
              <div className="flex gap-2">
                <Button onClick={() => setSelectedOrder(null)} variant="outline">Закрыть</Button>
                <Button onClick={() => window.print()} variant="outline" className="hidden sm:inline-flex">🖨️ Печать</Button>
              </div>
              <div className="flex items-center gap-3">
                <span className="text-xs font-bold text-gray-400 uppercase">Статус:</span>
                <select 
                  className={`text-sm font-bold rounded-xl px-4 py-2 outline-none border border-gray-200 shadow-sm transition-all focus:ring-2 ring-indigo-500 ${getStatusColor(selectedOrder.status)}`}
                  value={selectedOrder.status}
                  onChange={(e) => updateOrderData(selectedOrder.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                >
                  {Object.entries(STATUS_LABELS).map(([key, label]) => (<option key={key} value={key}>{label}</option>))}
                </select>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: [] }));
    }

    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const handleLocationImageUpload = (location: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setFormData(prev => ({
          ...prev,
          printImages: {
            ...(prev.printImages || {}),
            [location]: base64
          }
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLocationImage = (location: string) => {
    setFormData(prev => {
      const newImages = { ...(prev.printImages || {}) };
      delete newImages[location];
      return { ...prev, printImages: newImages };
    });
  };

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const toggleMultiColor = (colorName: string) => {
    setMultiColorSelections(prev => {
      const next = { ...prev };
      if (next[colorName]) {
        delete next[colorName];
      } else {
        next[colorName] = 1;
      }
      return next;
    });
  };

  const updateMultiColorQty = (colorName: string, delta: number) => {
    setMultiColorSelections(prev => ({
      ...prev,
      [colorName]: Math.max(1, (prev[colorName] || 0) + delta)
    }));
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || []);

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;

      const items: OrderItem[] = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));

      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;

      const items: OrderItem[] = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));

      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) {
        alert("Пожалуйста, добавьте хотя бы одного игрока в список команды.");
        return;
      }
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const getProductLabel = () => {
    switch(productType) {
      case ProductType.TSHIRT: return 'Футболка';
      case ProductType.HOODIE: return 'Худи';
      case ProductType.CAP: return 'Шапка';
      case ProductType.TANK_TOP: return 'Майка';
      default: return 'Товар';
    }
  };

  const getAvailablePrintPlaces = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  return (
    <div className="bg-white rounded-3xl p-8 shadow-xl max-w-2xl mx-auto border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">
            Настройка: {getProductLabel()}
          </h2>
          <p className="text-sm text-indigo-600 font-medium">{initialSubtype}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">✕</button>
      </div>

      {tips && (
        <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-400 p-4 rounded-r-lg">
          <p className="text-xs font-bold text-indigo-700 uppercase mb-1 flex items-center gap-2">
             <span className="text-lg">✨</span> AI Совет по дизайну
          </p>
          <p className="text-sm text-indigo-900 whitespace-pre-wrap italic">{tips}</p>
        </div>
      )}

      <div className="space-y-6">
        {productType === ProductType.HOODIE && (
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Тип худи</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(HoodieType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, hoodieType: v as HoodieType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.hoodieType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
           <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Модель шапки</label>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
              {Object.values(CapType).map(v => (
                <button
                  key={v}
                  onClick={() => setFormData({ ...formData, capType: v as CapType })}
                  className={`p-3 text-center rounded-xl border text-xs transition-all ${
                    formData.capType === v ? 'bg-indigo-50 border-indigo-500 text-indigo-700 font-bold' : 'bg-gray-50 border-gray-100 text-gray-600'
                  }`}
                >
                  {v}
                </button>
              ))}
            </div>
          </div>
        )}

        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-bold text-gray-700 mb-2">Выберите школу</label>
            <div className="mb-4">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                    formData.school === school.name 
                      ? 'bg-indigo-50 border-indigo-500 shadow-md' 
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-12 h-12 mb-2 bg-white rounded-lg p-1 shadow-sm overflow-hidden flex items-center justify-center">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-bold leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-600'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {(initialSubtype === OrderSubtype.PERSONAL || initialSubtype === OrderSubtype.TEAM || productType === ProductType.CAP) && (
          <div className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Места печати</label>
              <div className="flex flex-wrap gap-2">
                {getAvailablePrintPlaces().map(p => (
                  <button
                    key={p}
                    onClick={() => togglePrintPlace(p)}
                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${
                      formData.printPlaces?.includes(p) ? 'bg-indigo-100 border-indigo-600 text-indigo-700' : 'bg-white border-gray-300 text-gray-500'
                    }`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            {formData.printPlaces && formData.printPlaces.length > 0 && (
              <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 space-y-4">
                <label className="block text-xs font-black text-gray-400 uppercase tracking-widest">Загрузка макетов по местам</label>
                <div className="grid grid-cols-1 gap-3">
                  {formData.printPlaces.map(place => (
                    <div key={place} className="flex items-center justify-between bg-white p-3 rounded-xl border border-gray-100 shadow-sm group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center text-indigo-600">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} className="w-full h-full object-cover rounded-lg" alt={place} />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-gray-700">{place}</p>
                          <p className="text-[10px] text-gray-400">{formData.printImages?.[place] ? 'Файл выбран' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        {formData.printImages?.[place] ? (
                          <button 
                            onClick={() => removeLocationImage(place)}
                            className="text-red-400 hover:text-red-600 p-2 text-sm"
                            type="button"
                          >✕</button>
                        ) : (
                          <>
                            <input 
                              type="file" 
                              id={`upload-${place}`} 
                              className="hidden" 
                              onChange={(e) => handleLocationImageUpload(place, e)} 
                              accept="image/*"
                            />
                            <label 
                              htmlFor={`upload-${place}`}
                              className="bg-indigo-600 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg cursor-pointer hover:bg-indigo-700 transition-colors"
                            >
                              Выбрать
                            </label>
                          </>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {initialSubtype === OrderSubtype.TEAM && (
          <PlayerTable 
            players={formData.players || []} 
            onChange={(players) => setFormData({ ...formData, players })} 
            onExcelImport={(fileName) => setFormData(prev => ({ ...prev, excelFileName: fileName }))}
          />
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">
              Цвет {isMultiColorMode ? '(выберите несколько)' : ''}
            </label>
            <div className="flex flex-wrap gap-2">
              {COLORS.map(c => {
                const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
                return (
                  <button
                    key={c.hex}
                    onClick={() => isMultiColorMode ? toggleMultiColor(c.name) : setFormData({ ...formData, color: c.name })}
                    className={`w-8 h-8 rounded-lg border-2 shadow-sm transition-all relative ${
                      isSelected ? 'ring-2 ring-offset-2 ring-indigo-500 scale-110' : 'border-white'
                    }`}
                    style={{ backgroundColor: c.hex }}
                    title={c.name}
                  >
                    {isMultiColorMode && isSelected && (
                      <span className="absolute -top-2 -right-2 bg-indigo-600 text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">✓</span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && !isTeamMode && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Пол</label>
              <div className="flex gap-2">
                 {['Мальчик', 'Девочка'].map(g => (
                   <button
                     key={g}
                     onClick={() => setFormData({ ...formData, gender: g as any })}
                     className={`flex-1 py-2 text-xs font-bold rounded-xl transition-all ${
                       formData.gender === g ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'
                     }`}
                   >
                     {g === 'Мальчик' ? '👨 М' : '👩 Д'}
                   </button>
                 ))}
              </div>
            </div>
          )}

          {productType === ProductType.TSHIRT && !isTeamMode && !isMultiSizeMode && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Рукав</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.sleeve}
                onChange={e => setFormData({ ...formData, sleeve: e.target.value })}
              >
                {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          )}

          {!isTeamMode && !isMultiSizeMode && (
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Размер</label>
              <select 
                className="w-full p-2 bg-gray-50 border border-gray-200 rounded-xl outline-none text-sm font-medium shadow-sm"
                value={formData.size}
                onChange={e => setFormData({ ...formData, size: e.target.value })}
              >
                {productType === ProductType.CAP ? (
                  <option>Универсальный</option>
                ) : (
                  <>
                    <optgroup label="Дети">
                      {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_KIDS : PERSONAL_SIZES_KIDS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                    <optgroup label="Взрослые">
                       {(initialSubtype === OrderSubtype.SCHOOL ? SCHOOL_SIZES_ADULTS : PERSONAL_SIZES_ADULTS).map(s => <option key={s} value={s}>{s}</option>)}
                    </optgroup>
                  </>
                )}
              </select>
            </div>
          )}

          {!isMultiColorMode && !isTeamMode && !isMultiSizeMode && (
            <div className="col-span-1 sm:col-span-2">
              <label className="block text-sm font-bold text-gray-700 mb-2">Количество</label>
              <div className="flex items-center gap-4">
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: Math.max(1, (prev.quantity || 1) - 1) }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >-</button>
                <span className="text-xl font-bold w-12 text-center">{formData.quantity}</span>
                <button 
                   onClick={() => setFormData(prev => ({ ...prev, quantity: (prev.quantity || 1) + 1 }))}
                   className="w-10 h-10 rounded-xl bg-gray-100 flex items-center justify-center text-xl font-bold hover:bg-gray-200 transition-colors"
                >+</button>
              </div>
            </div>
          )}

          {isMultiColorMode && (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <label className="block text-sm font-bold text-indigo-700 mb-4 uppercase tracking-wider text-xs">Выбранные цвета и количество</label>
               {Object.keys(multiColorSelections).length === 0 ? (
                 <p className="text-gray-400 text-sm italic py-2">Пожалуйста, выберите хотя бы один цвет выше</p>
               ) : (
                 <div className="space-y-3">
                   {Object.entries(multiColorSelections).map(([colorName, qty]) => {
                     const colorHex = COLORS.find(c => c.name === colorName)?.hex || '#ccc';
                     return (
                       <div key={colorName} className="flex items-center justify-between bg-white p-3 rounded-xl shadow-sm">
                         <div className="flex items-center gap-3">
                           <div className="w-6 h-6 rounded-md shadow-inner" style={{ backgroundColor: colorHex }}></div>
                           <span className="text-sm font-bold text-gray-700">{colorName}</span>
                         </div>
                         <div className="flex items-center gap-3">
                            <button 
                              onClick={() => updateMultiColorQty(colorName, -1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >-</button>
                            <span className="w-6 text-center text-sm font-black">{qty}</span>
                            <button 
                              onClick={() => updateMultiColorQty(colorName, 1)}
                              className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-gray-600 hover:bg-indigo-100 hover:text-indigo-600 transition-all"
                            >+</button>
                         </div>
                       </div>
                     );
                   })}
                 </div>
               )}
            </div>
          )}

          {isMultiSizeMode && (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <div className="flex justify-between items-center mb-6">
                  <label className="block text-sm font-black text-indigo-700 uppercase tracking-widest">Размеры и количество</label>
                  <span className="text-xs font-bold text-indigo-400">Итого: {totalMultiSizeQty} шт.</span>
               </div>

               <div className="space-y-6">
                 <div>
                    <p className="text-[10px] font-bold text-gray-400 uppercase mb-3">Детские</p>
                    <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                       {PERSONAL_SIZES_KIDS.map(size => {
                         const qty = multiSizeSelections[size] || 0;
                         return (
                           <div key={size} className="flex flex-col items-center">
                              <span className="text-[10px] font-bold text-gray-500 mb-1">{size}</span>
                              <div className={`flex flex-col items-center border rounded-lg overflow-hidden ${qty > 0 ? 'border-indigo-500 bg-white' : 'border-gray-200 bg-gray-50'}`}>
                                <button onClick={() => updateMultiSizeQty(size, 1)} className="p-1 hover:text-indigo-600">▲</button>
                                <span className={`text-xs font-black py-0.5 ${qty > 0 ? 'text-indigo-700' : 'text-gray-400'}`}>{qty}</span>
                                <button onClick={() => updateMultiSizeQty(size, -1)} className="p-1 hover:text-red-600">▼</button>
                              </div>
                           </div>
                         );
                       })}
                    </div>
                 </div>

                 <div>
                    <p className="text-[10px] font-bold text-gray-400 uppercase mb-3">Взрослые</p>
                    <div className="grid grid-cols-4 sm:grid-cols-6 gap-2">
                       {PERSONAL_SIZES_ADULTS.map(size => {
                         const qty = multiSizeSelections[size] || 0;
                         return (
                           <div key={size} className="flex flex-col items-center">
                              <span className="text-[10px] font-bold text-gray-500 mb-1">{size}</span>
                              <div className={`flex flex-col items-center border rounded-lg overflow-hidden ${qty > 0 ? 'border-indigo-500 bg-white' : 'border-gray-200 bg-gray-50'}`}>
                                <button onClick={() => updateMultiSizeQty(size, 1)} className="p-1 hover:text-indigo-600">▲</button>
                                <span className={`text-xs font-black py-0.5 ${qty > 0 ? 'text-indigo-700' : 'text-gray-400'}`}>{qty}</span>
                                <button onClick={() => updateMultiSizeQty(size, -1)} className="p-1 hover:text-red-600">▼</button>
                              </div>
                           </div>
                         );
                       })}
                    </div>
                 </div>
               </div>
            </div>
          )}

          {isTeamMode && (
            <div className="col-span-1 sm:col-span-2 bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100 animate-in fade-in duration-300">
               <p className="text-indigo-700 text-xs font-bold">Количество и размеры будут взяты из списка команды выше.</p>
               <p className="text-lg font-black text-indigo-800 mt-1">Всего: {formData.players?.length || 0} шт.</p>
            </div>
          )}
        </div>
      </div>

      <div className="mt-10 flex gap-4">
        <Button onClick={onCancel} variant="outline" fullWidth>Отмена</Button>
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          fullWidth
          disabled={
            (initialSubtype === OrderSubtype.SCHOOL && !formData.school) || 
            (isMultiColorMode && Object.keys(multiColorSelections).length === 0) || 
            (isMultiSizeMode && totalMultiSizeQty === 0) ||
            (isTeamMode && (!formData.players || formData.players.length === 0))
          }
        >
          {formData.id ? 'Обновить' : 'В корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: [] }));
    }

    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || []);

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) return alert("Добавьте игроков!");
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">
            {initialSubtype}
          </h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : 'Продукт'}</p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button
                  key={g}
                  onClick={() => setFormData({ ...formData, gender: g as any })}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.gender === g 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {g === 'Мальчик' ? 'Мальчики' : 'Девочки'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {productType === ProductType.TSHIRT && !isTeamMode && !isMultiSizeMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex gap-3">
              {(formData.gender === 'Мальчик' ? SLEEVES.BOY : SLEEVES.GIRL).map(s => (
                <button
                  key={s}
                  onClick={() => setFormData({ ...formData, sleeve: s })}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.sleeve === s 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : 
               (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])
              ).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button
                    key={size}
                    onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })}
                    onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }}
                    className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${
                      isSelected 
                        ? 'bg-indigo-600 text-white shadow-lg scale-105' 
                        : 'bg-gray-50 text-gray-400 hover:bg-gray-100'
                    }`}
                  >
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && (
                      <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                        {multiSizeSelections[size]}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Цвет изделия</label>
          <div className="grid grid-cols-5 gap-3">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button
                  key={c.hex}
                  onClick={() => setFormData({ ...formData, color: c.name })}
                  className={`aspect-square rounded-[24px] transition-all relative group flex items-center justify-center ${
                    isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'
                  }`}
                  style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}
                >
                  {isSelected && (
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>
                      <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* Команда (если выбрана) */}
        {isTeamMode && (
          <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} />
        )}

        {/* Места печати */}
        <div className="pt-8 border-t border-gray-50">
           <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Места печати</label>
           <div className="flex gap-2">
             {PRINT_PLACES.map(p => (
               <button
                 key={p}
                 onClick={() => togglePrintPlace(p)}
                 className={`px-5 h-11 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                   formData.printPlaces?.includes(p) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-200 text-gray-400 hover:border-indigo-200'
                 }`}
               >
                 {p}
               </button>
             ))}
           </div>
        </div>
      </div>

      <div className="mt-14 flex flex-col items-center">
        {isMultiSizeMode && (
          <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">
            Итого к заказу: <span className="text-indigo-600 ml-2">{totalMultiSizeQty} шт.</span>
          </p>
        )}
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          size="lg" 
          fullWidth
          className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200"
          disabled={(isMultiSizeMode && totalMultiSizeQty === 0) || (isTeamMode && !formData.players?.length)}
        >
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

