  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];

    if (initialSubtype === OrderSubtype.SCHOOL) {
        // Для школы всегда печать спереди
        defaultPrintPlaces = ['Спереди'];
    }

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces }));
    }

    getDesignFeedback(productType, initialSubtype).then(setTips);
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => ({
      ...prev,
      printPlaces: prev.printPlaces?.includes(place)
        ? prev.printPlaces.filter(p => p !== place)
        : [...(prev.printPlaces || []), place]
    }));
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || []);

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) return alert("Добавьте игроков!");
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  const totalQty = isMultiSizeMode 
    ? totalMultiSizeQty 
    : (isMultiColorMode ? Object.values(multiColorSelections).reduce((a, b) => a + b, 0) : formData.quantity);

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">
