            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 animate-in fade-in slide-in-from-bottom-2 duration-400">
               {Object.entries(multiColorSelections).map(([cName, qty]) => {
                 const colorObj = COLORS.find(c => c.name === cName);
                 return (
                   <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex items-center gap-3">
