export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];

    if (initialSubtype === OrderSubtype.SCHOOL) {
        defaultPrintPlaces = ['Спереди'];
    }

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces }));
    }

    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving
        ? prev.printPlaces?.filter(p => p !== place)
        : [...(prev.printPlaces || []), place];

      const newPrintImages = { ...prev.printImages };
      if (isRemoving) {
        delete newPrintImages[place];
      }

      return {
        ...prev,
        printPlaces: newPlaces,
        printImages: newPrintImages
      };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printImages: {
          ...(prev.printImages || {}),
          [place]: base64
        }
      }));
    };
    reader.readAsDataURL(file);
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) return alert("Добавьте игроков!");
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  const currentColorHex = COLORS.find(c => c.name === formData.color)?.hex || '#FFFFFF';

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">
            {initialSubtype}
          </h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {/* DESIGN TIPS BANNER */}
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6 animate-in slide-in-from-top-2 duration-500">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => (
                 <p key={i}>{line.trim()}</p>
               ))}
             </div>
          </div>
        )}

        {/* ВИЗУАЛИЗАЦИЯ ДЛЯ ЛИЧНОГО ДИЗАЙНА */}
        {initialSubtype === OrderSubtype.PERSONAL && (
          <div className="space-y-8">
            <div>
              <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Настройте места печати кликом</label>
              <ProductVisualizer 
                type={productType} 
                selectedPlaces={formData.printPlaces || []} 
                onToggle={togglePrintPlace}
                colorHex={currentColorHex}
                hasImage={(place) => !!formData.printImages?.[place]}
              />
            </div>

            {/* ЗАГРУЗКА ФАЙЛОВ ДЛЯ ВЫБРАННЫХ ЗОН */}
            {(formData.printPlaces || []).length > 0 && (
              <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {(formData.printPlaces || []).map(place => (
                    <div key={place} className="bg-gray-50 p-4 rounded-3xl border border-gray-100 flex items-center justify-between group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center shadow-sm border border-gray-100 text-lg">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} alt="preview" className="w-full h-full object-cover rounded-xl" />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-[10px] font-black text-gray-900 uppercase tracking-tight">{place}</p>
                          <p className="text-[9px] text-gray-400">{formData.printImages?.[place] ? 'Файл загружен' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <input 
                        type="file" 
                        accept="image/*"
                        className="hidden" 
                        ref={el => { fileInputRefs.current[place] = el; }}
                        onChange={(e) => handleFileUpload(place, e)}
                      />
                      <button 
                        onClick={() => fileInputRefs.current[place]?.click()}
                        className={`px-3 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${
                          formData.printImages?.[place] ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md hover:scale-105'
                        }`}
                      >
                        {formData.printImages?.[place] ? 'Заменить' : 'Загрузить'}
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ШКОЛЫ - ВИЗУАЛЬНЫЙ ВЫБОР */}
        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${
                    formData.school === school.name 
                      ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' 
                      : 'border-gray-50 bg-gray-50 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button
                  key={g}
                  onClick={() => setFormData({ ...formData, gender: g as any })}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.gender === g 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {g === 'Мальчик' ? 'Мальчики' : 'Девочки'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : 
               (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])
              ).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button
                    key={size}
                    onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })}
                    onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }}
                    className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${
                      isSelected 
                        ? 'bg-indigo-600 text-white shadow-lg scale-105' 
                        : 'bg-gray-50 text-gray-400 hover:bg-gray-100'
                    }`}
                  >
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && (
                      <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                        {multiSizeSelections[size]}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">
            Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}
          </label>
          <div className="grid grid-cols-5 gap-3 mb-8">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button
                  key={c.hex}
                  onClick={() => {
                    if (isMultiColorMode) {
                      setMultiColorSelections(prev => {
                        const next = { ...prev };
                        if (next[c.name]) { /* Manage in list below */ } 
                        else next[c.name] = 1;
                        return next;
                      });
                    } else {
                      setFormData({ ...formData, color: c.name });
                    }
                  }}
                  className={`aspect-square rounded-[24px] transition-all relative group flex items-center justify-center ${
                    isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'
                  }`}
                  style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}
                >
                  {isSelected && (
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>
                      {isMultiColorMode ? (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>
                          {multiColorSelections[c.name]}
                        </span>
                      ) : (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>
                      )}
                    </div>
                  )}
                </button>
              );
            })}
          </div>

          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 animate-in fade-in slide-in-from-bottom-2 duration-400">
               {Object.entries(multiColorSelections).map(([cName, qty]) => {
                 const colorObj = COLORS.find(c => c.name === cName);
                 return (
                   <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex items-center gap-3">
                        <div className="w-5 h-5 rounded-full border border-gray-200 shadow-inner" style={{ backgroundColor: colorObj?.hex }}></div>
                        <span className="text-[13px] font-black text-gray-700 uppercase tracking-tight">{cName}</span>
                      </div>
                      <div className="flex items-center bg-white/80 rounded-xl p-1 border border-gray-100 gap-4">
                         <button onClick={() => setMultiColorSelections(prev => {
                             const next = { ...prev };
                             if (qty <= 1) delete next[cName];
                             else next[cName] = qty - 1;
                             return next;
                           })} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">−</button>
                         <span className="text-sm font-black text-gray-900 min-w-[20px] text-center">{qty}</span>
                         <button onClick={() => setMultiColorSelections(prev => ({...prev, [cName]: qty + 1}))} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">+</button>
                      </div>
                   </div>
                 );
               })}
            </div>
          )}
        </div>

        {/* Команда (если выбрана) */}
        {isTeamMode && (
          <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} />
        )}

        {/* Места печати (текстовый список для остальных категорий) */}
        {initialSubtype !== OrderSubtype.SCHOOL && initialSubtype !== OrderSubtype.PERSONAL && (
          <div className="pt-8 border-t border-gray-50">
             <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Места печати</label>
             <div className="flex gap-2">
               {PRINT_PLACES.map(p => (
                 <button
                   key={p}
                   onClick={() => togglePrintPlace(p)}
                   className={`px-5 h-11 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                     formData.printPlaces?.includes(p) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-200 text-gray-400 hover:border-indigo-200'
                   }`}
                 >
                   {p}
                 </button>
               ))}
             </div>
          </div>
        )}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && (
          <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">
            Итого к заказу: <span className="text-indigo-600 ml-2 font-black text-lg">
              {isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.
            </span>
          </p>
        )}
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          size="lg" 
          fullWidth
          className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200"
          disabled={
            (initialSubtype === OrderSubtype.SCHOOL && !formData.school) ||
            (isMultiSizeMode && totalMultiSizeQty === 0) || 
            (isMultiColorMode && Object.keys(multiColorSelections).length === 0) ||
            (isTeamMode && !formData.players?.length) ||
            (initialSubtype === OrderSubtype.PERSONAL && (
              (formData.printPlaces?.length === 0) || 
              (formData.printPlaces?.some(p => !formData.printImages?.[p]))
            ))
          }
        >
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

// Вспомогательный компонент для визуализации изделия
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');

  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            {/* Front Print Area */}
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && (
               <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">
                 {hasImage('Спереди') ? 'ИМИДЖ ✓' : 'ПЕРЕД'}
               </text>
            )}

            {/* Sleeves */}
            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            {isSelected('Правый рукав') && <text x="25" y="70" textAnchor="middle" className="text-[6px] font-black pointer-events-none fill-indigo-600">РП</text>}

            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
            {isSelected('Левый рукав') && <text x="175" y="70" textAnchor="middle" className="text-[6px] font-black pointer-events-none fill-indigo-600">РЛ</text>}
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <path d="M10,140 Q100,170 190,140" fill="none" stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
          className="cursor-pointer transition-all hover:fill-indigo-50"
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      <div className="absolute top-4 left-4 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest text-indigo-500 border border-indigo-100 z-10">
        Интерактивный макет
      </div>

      {type === ProductType.CAP ? renderCap() : renderTshirt()}

      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button 
            onClick={() => setView('front')}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Спереди
          </button>
          <button 
            onClick={() => setView('back')}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Сзади
          </button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];

    if (initialSubtype === OrderSubtype.SCHOOL) {
        defaultPrintPlaces = ['Спереди'];
    }

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces }));
    }

    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving
        ? prev.printPlaces?.filter(p => p !== place)
        : [...(prev.printPlaces || []), place];

      const newPrintImages = { ...prev.printImages };
      if (isRemoving) {
        delete newPrintImages[place];
      }

      return {
        ...prev,
        printPlaces: newPlaces,
        printImages: newPrintImages
      };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printImages: {
          ...(prev.printImages || {}),
          [place]: base64
        }
      }));
    };
    reader.readAsDataURL(file);
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) return alert("Добавьте игроков!");
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  const currentColorHex = COLORS.find(c => c.name === formData.color)?.hex || '#FFFFFF';

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">
            {initialSubtype}
          </h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {/* DESIGN TIPS BANNER */}
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6 animate-in slide-in-from-top-2 duration-500">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => (
                 <p key={i}>{line.trim()}</p>
               ))}
             </div>
          </div>
        )}

        {/* ВИЗУАЛИЗАЦИЯ ДЛЯ ЛИЧНОГО ДИЗАЙНА */}
        {initialSubtype === OrderSubtype.PERSONAL && (
          <div className="space-y-8">
            <div>
              <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Настройте места печати кликом</label>
              <ProductVisualizer 
                type={productType} 
                selectedPlaces={formData.printPlaces || []} 
                onToggle={togglePrintPlace}
                colorHex={currentColorHex}
                hasImage={(place) => !!formData.printImages?.[place]}
              />
            </div>

            {/* ЗАГРУЗКА ФАЙЛОВ ДЛЯ ВЫБРАННЫХ ЗОН */}
            {(formData.printPlaces || []).length > 0 && (
              <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {(formData.printPlaces || []).map(place => (
                    <div key={place} className="bg-gray-50 p-4 rounded-3xl border border-gray-100 flex items-center justify-between group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center shadow-sm border border-gray-100 text-lg">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} alt="preview" className="w-full h-full object-cover rounded-xl" />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-[10px] font-black text-gray-900 uppercase tracking-tight">{place}</p>
                          <p className="text-[9px] text-gray-400">{formData.printImages?.[place] ? 'Файл загружен' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <input 
                        type="file" 
                        accept="image/*"
                        className="hidden" 
                        ref={el => { fileInputRefs.current[place] = el; }}
                        onChange={(e) => handleFileUpload(place, e)}
                      />
                      <button 
                        onClick={() => fileInputRefs.current[place]?.click()}
                        className={`px-3 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${
                          formData.printImages?.[place] ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md hover:scale-105'
                        }`}
                      >
                        {formData.printImages?.[place] ? 'Заменить' : 'Загрузить'}
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ШКОЛЫ - ВИЗУАЛЬНЫЙ ВЫБОР */}
        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${
                    formData.school === school.name 
                      ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' 
                      : 'border-gray-50 bg-gray-50 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button
                  key={g}
                  onClick={() => {
                    const newGender = g as 'Мальчик' | 'Девочка';
                    const availableSleeves = newGender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY;
                    const newSleeve = availableSleeves.includes(formData.sleeve || '') ? formData.sleeve : availableSleeves[0];
                    setFormData({ ...formData, gender: newGender, sleeve: newSleeve });
                  }}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.gender === g 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {g === 'Мальчик' ? 'Мальчики' : 'Девочки'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА (НОВОЕ) */}
        {(productType === ProductType.TSHIRT || productType === ProductType.HOODIE) && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY).map(s => (
                <button
                  key={s}
                  onClick={() => setFormData({ ...formData, sleeve: s })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.sleeve === s 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : 
               (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])
              ).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button
                    key={size}
                    onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })}
                    onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }}
                    className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${
                      isSelected 
                        ? 'bg-indigo-600 text-white shadow-lg scale-105' 
                        : 'bg-gray-50 text-gray-400 hover:bg-gray-100'
                    }`}
                  >
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && (
                      <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                        {multiSizeSelections[size]}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">
            Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}
          </label>
          <div className="grid grid-cols-5 gap-3 mb-8">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button
                  key={c.hex}
                  onClick={() => {
                    if (isMultiColorMode) {
                      setMultiColorSelections(prev => {
                        const next = { ...prev };
                        if (next[c.name]) { /* Manage in list below */ } 
                        else next[c.name] = 1;
                        return next;
                      });
                    } else {
                      setFormData({ ...formData, color: c.name });
                    }
                  }}
                  className={`aspect-square rounded-[24px] transition-all relative group flex items-center justify-center ${
                    isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'
                  }`}
                  style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}
                >
                  {isSelected && (
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>
                      {isMultiColorMode ? (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>
                          {multiColorSelections[c.name]}
                        </span>
                      ) : (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>
                      )}
                    </div>
                  )}
                </button>
              );
            })}
          </div>

          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 animate-in fade-in slide-in-from-bottom-2 duration-400">
               {Object.entries(multiColorSelections).map(([cName, qty]) => {
                 const colorObj = COLORS.find(c => c.name === cName);
                 return (
                   <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex items-center gap-3">
                        <div className="w-5 h-5 rounded-full border border-gray-200 shadow-inner" style={{ backgroundColor: colorObj?.hex }}></div>
                        <span className="text-[13px] font-black text-gray-700 uppercase tracking-tight">{cName}</span>
                      </div>
                      <div className="flex items-center bg-white/80 rounded-xl p-1 border border-gray-100 gap-4">
                         <button onClick={() => setMultiColorSelections(prev => {
                             const next = { ...prev };
                             if (qty <= 1) delete next[cName];
                             else next[cName] = qty - 1;
                             return next;
                           })} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">−</button>
                         <span className="text-sm font-black text-gray-900 min-w-[20px] text-center">{qty}</span>
                         <button onClick={() => setMultiColorSelections(prev => ({...prev, [cName]: qty + 1}))} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">+</button>
                      </div>
                   </div>
                 );
               })}
            </div>
          )}
        </div>

        {/* Команда (если выбрана) */}
        {isTeamMode && (
          <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} />
        )}

        {/* Места печати (текстовый список для остальных категорий) */}
        {initialSubtype !== OrderSubtype.SCHOOL && initialSubtype !== OrderSubtype.PERSONAL && (
          <div className="pt-8 border-t border-gray-50">
             <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Места печати</label>
             <div className="flex gap-2">
               {PRINT_PLACES.map(p => (
                 <button
                   key={p}
                   onClick={() => togglePrintPlace(p)}
                   className={`px-5 h-11 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                     formData.printPlaces?.includes(p) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-200 text-gray-400 hover:border-indigo-200'
                   }`}
                 >
                   {p}
                 </button>
               ))}
             </div>
          </div>
        )}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && (
          <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">
            Итого к заказу: <span className="text-indigo-600 ml-2 font-black text-lg">
              {isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.
            </span>
          </p>
        )}
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          size="lg" 
          fullWidth
          className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200"
          disabled={
            (initialSubtype === OrderSubtype.SCHOOL && !formData.school) ||
            (isMultiSizeMode && totalMultiSizeQty === 0) || 
            (isMultiColorMode && Object.keys(multiColorSelections).length === 0) ||
            (isTeamMode && !formData.players?.length) ||
            (initialSubtype === OrderSubtype.PERSONAL && (
              (formData.printPlaces?.length === 0) || 
              (formData.printPlaces?.some(p => !formData.printImages?.[p]))
            ))
          }
        >
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

// Вспомогательный компонент для визуализации изделия
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');

  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && (
               <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">
                 {hasImage('Спереди') ? 'ИМИДЖ ✓' : 'ПЕРЕД'}
               </text>
            )}

            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            {isSelected('Правый рукав') && <text x="25" y="70" textAnchor="middle" className="text-[6px] font-black pointer-events-none fill-indigo-600">РП</text>}

            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
            {isSelected('Левый рукав') && <text x="175" y="70" textAnchor="middle" className="text-[6px] font-black pointer-events-none fill-indigo-600">РЛ</text>}
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <path d="M10,140 Q100,170 190,140" fill="none" stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
          className="cursor-pointer transition-all hover:fill-indigo-50"
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      <div className="absolute top-4 left-4 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest text-indigo-500 border border-indigo-100 z-10">
        Интерактивный макет
      </div>

      {type === ProductType.CAP ? renderCap() : renderTshirt()}

      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button 
            onClick={() => setView('front')}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Спереди
          </button>
          <button 
            onClick={() => setView('back')}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Сзади
          </button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];

    if (initialSubtype === OrderSubtype.SCHOOL) {
        defaultPrintPlaces = ['Спереди'];
    }

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ 
          ...prev, 
          capType: CapType.BASEBALL, 
          printPlaces: ['Спереди'] 
        }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ 
          ...prev, 
          hoodieType: HoodieType.KANGAROO, 
          printPlaces: defaultPrintPlaces,
          sleeve: 'Длинный' // Для худи стандартно длинный
        }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }

    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving
        ? prev.printPlaces?.filter(p => p !== place)
        : [...(prev.printPlaces || []), place];

      const newPrintImages = { ...prev.printImages };
      if (isRemoving) {
        delete newPrintImages[place];
      }

      return {
        ...prev,
        printPlaces: newPlaces,
        printImages: newPrintImages
      };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printImages: {
          ...(prev.printImages || {}),
          [place]: base64
        }
      }));
    };
    reader.readAsDataURL(file);
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) return alert("Добавьте игроков!");
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  const currentColorHex = COLORS.find(c => c.name === formData.color)?.hex || '#FFFFFF';

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">
            {initialSubtype}
          </h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {/* DESIGN TIPS BANNER */}
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6 animate-in slide-in-from-top-2 duration-500">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => (
                 <p key={i}>{line.trim()}</p>
               ))}
             </div>
          </div>
        )}

        {/* МОДЕЛЬ ИЗДЕЛИЯ (ДЛЯ ХУДИ И КЕПОК) */}
        {productType === ProductType.HOODIE && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель худи</label>
            <div className="flex flex-wrap gap-2">
              {[HoodieType.KANGAROO, HoodieType.ZIP, HoodieType.SWEATER].map(t => (
                <button
                  key={t}
                  onClick={() => setFormData({ ...formData, hoodieType: t })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.hoodieType === t 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {t === HoodieType.KANGAROO ? 'Кенгуру' : t === HoodieType.ZIP ? 'На молнии' : 'Свитшот'}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель кепки</label>
            <div className="flex flex-wrap gap-2">
              {[CapType.BASEBALL, CapType.SNAPBACK, CapType.BEANIE].map(t => (
                <button
                  key={t}
                  onClick={() => setFormData({ ...formData, capType: t })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.capType === t 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {t === CapType.BASEBALL ? 'Бейсболка' : t === CapType.SNAPBACK ? 'Снэпбек' : 'Бини'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ВИЗУАЛИЗАЦИЯ ДЛЯ ЛИЧНОГО ДИЗАЙНА */}
        {initialSubtype === OrderSubtype.PERSONAL && (
          <div className="space-y-8">
            <div>
              <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Настройте места печати кликом</label>
              <ProductVisualizer 
                type={productType} 
                selectedPlaces={formData.printPlaces || []} 
                onToggle={togglePrintPlace}
                colorHex={currentColorHex}
                hasImage={(place) => !!formData.printImages?.[place]}
              />
            </div>

            {(formData.printPlaces || []).length > 0 && (
              <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {(formData.printPlaces || []).map(place => (
                    <div key={place} className="bg-gray-50 p-4 rounded-3xl border border-gray-100 flex items-center justify-between group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center shadow-sm border border-gray-100 text-lg">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} alt="preview" className="w-full h-full object-cover rounded-xl" />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-[10px] font-black text-gray-900 uppercase tracking-tight">{place}</p>
                          <p className="text-[9px] text-gray-400">{formData.printImages?.[place] ? 'Файл загружен' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <input 
                        type="file" 
                        accept="image/*"
                        className="hidden" 
                        ref={el => { fileInputRefs.current[place] = el; }}
                        onChange={(e) => handleFileUpload(place, e)}
                      />
                      <button 
                        onClick={() => fileInputRefs.current[place]?.click()}
                        className={`px-3 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${
                          formData.printImages?.[place] ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md hover:scale-105'
                        }`}
                      >
                        {formData.printImages?.[place] ? 'Заменить' : 'Загрузить'}
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ШКОЛЫ - ВИЗУАЛЬНЫЙ ВЫБОР */}
        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${
                    formData.school === school.name 
                      ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' 
                      : 'border-gray-50 bg-gray-50 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button
                  key={g}
                  onClick={() => {
                    const newGender = g as 'Мальчик' | 'Девочка';
                    const availableSleeves = newGender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY;
                    const newSleeve = availableSleeves.includes(formData.sleeve || '') ? formData.sleeve : availableSleeves[0];
                    setFormData({ ...formData, gender: newGender, sleeve: newSleeve });
                  }}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.gender === g 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {g === 'Мальчик' ? 'Мальчики' : 'Девочки'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {(productType === ProductType.TSHIRT || productType === ProductType.HOODIE) && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY).map(s => (
                <button
                  key={s}
                  onClick={() => setFormData({ ...formData, sleeve: s })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.sleeve === s 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : 
               (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])
              ).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button
                    key={size}
                    onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })}
                    onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }}
                    className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${
                      isSelected 
                        ? 'bg-indigo-600 text-white shadow-lg scale-105' 
                        : 'bg-gray-50 text-gray-400 hover:bg-gray-100'
                    }`}
                  >
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && (
                      <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                        {multiSizeSelections[size]}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">
            Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}
          </label>
          <div className="grid grid-cols-5 gap-3 mb-8">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button
                  key={c.hex}
                  onClick={() => {
                    if (isMultiColorMode) {
                      setMultiColorSelections(prev => {
                        const next = { ...prev };
                        if (next[c.name]) { /* Manage in list below */ } 
                        else next[c.name] = 1;
                        return next;
                      });
                    } else {
                      setFormData({ ...formData, color: c.name });
                    }
                  }}
                  className={`aspect-square rounded-[24px] transition-all relative group flex items-center justify-center ${
                    isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'
                  }`}
                  style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}
                >
                  {isSelected && (
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>
                      {isMultiColorMode ? (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>
                          {multiColorSelections[c.name]}
                        </span>
                      ) : (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>
                      )}
                    </div>
                  )}
                </button>
              );
            })}
          </div>

          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 animate-in fade-in slide-in-from-bottom-2 duration-400">
               {Object.entries(multiColorSelections).map(([cName, qty]) => {
                 const colorObj = COLORS.find(c => c.name === cName);
                 return (
                   <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex items-center gap-3">
                        <div className="w-5 h-5 rounded-full border border-gray-200 shadow-inner" style={{ backgroundColor: colorObj?.hex }}></div>
                        <span className="text-[13px] font-black text-gray-700 uppercase tracking-tight">{cName}</span>
                      </div>
                      <div className="flex items-center bg-white/80 rounded-xl p-1 border border-gray-100 gap-4">
                         <button onClick={() => setMultiColorSelections(prev => {
                             const next = { ...prev };
                             if (qty <= 1) delete next[cName];
                             else next[cName] = qty - 1;
                             return next;
                           })} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">−</button>
                         <span className="text-sm font-black text-gray-900 min-w-[20px] text-center">{qty}</span>
                         <button onClick={() => setMultiColorSelections(prev => ({...prev, [cName]: qty + 1}))} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">+</button>
                      </div>
                   </div>
                 );
               })}
            </div>
          )}
        </div>

        {isTeamMode && (
          <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} />
        )}

        {initialSubtype !== OrderSubtype.SCHOOL && initialSubtype !== OrderSubtype.PERSONAL && (
          <div className="pt-8 border-t border-gray-50">
             <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Места печати</label>
             <div className="flex gap-2">
               {PRINT_PLACES.map(p => (
                 <button
                   key={p}
                   onClick={() => togglePrintPlace(p)}
                   className={`px-5 h-11 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                     formData.printPlaces?.includes(p) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-200 text-gray-400 hover:border-indigo-200'
                   }`}
                 >
                   {p}
                 </button>
               ))}
             </div>
          </div>
        )}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && (
          <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">
            Итого к заказу: <span className="text-indigo-600 ml-2 font-black text-lg">
              {isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.
            </span>
          </p>
        )}
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          size="lg" 
          fullWidth
          className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200"
          disabled={
            (initialSubtype === OrderSubtype.SCHOOL && !formData.school) ||
            (isMultiSizeMode && totalMultiSizeQty === 0) || 
            (isMultiColorMode && Object.keys(multiColorSelections).length === 0) ||
            (isTeamMode && !formData.players?.length) ||
            (initialSubtype === OrderSubtype.PERSONAL && (
              (formData.printPlaces?.length === 0) || 
              (formData.printPlaces?.some(p => !formData.printImages?.[p]))
            ))
          }
        >
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

// Вспомогательный компонент для визуализации изделия
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');

  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && (
               <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">
                 {hasImage('Спереди') ? 'ИМИДЖ ✓' : 'ПЕРЕД'}
               </text>
            )}

            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            {isSelected('Правый рукав') && <text x="25" y="70" textAnchor="middle" className="text-[6px] font-black pointer-events-none fill-indigo-600">РП</text>}

            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
            {isSelected('Левый рукав') && <text x="175" y="70" textAnchor="middle" className="text-[6px] font-black pointer-events-none fill-indigo-600">РЛ</text>}
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <path d="M10,140 Q100,170 190,140" fill="none" stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
          className="cursor-pointer transition-all hover:fill-indigo-50"
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      <div className="absolute top-4 left-4 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest text-indigo-500 border border-indigo-100 z-10">
        Интерактивный макет
      </div>

      {type === ProductType.CAP ? renderCap() : renderTshirt()}

      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button 
            onClick={() => setView('front')}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Спереди
          </button>
          <button 
            onClick={() => setView('back')}
            className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}
          >
            Сзади
          </button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];

    if (initialSubtype === OrderSubtype.SCHOOL) {
        defaultPrintPlaces = ['Спереди'];
    }

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ 
          ...prev, 
          capType: CapType.BASEBALL, 
          printPlaces: ['Спереди'] 
        }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ 
          ...prev, 
          hoodieType: HoodieType.KANGAROO, 
          printPlaces: defaultPrintPlaces,
          sleeve: 'Длинный',
          gender: 'Универсальный'
        }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }

    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving
        ? prev.printPlaces?.filter(p => p !== place)
        : [...(prev.printPlaces || []), place];

      const newPrintImages = { ...prev.printImages };
      if (isRemoving) {
        delete newPrintImages[place];
      }

      return {
        ...prev,
        printPlaces: newPlaces,
        printImages: newPrintImages
      };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printImages: {
          ...(prev.printImages || {}),
          [place]: base64
        }
      }));
    };
    reader.readAsDataURL(file);
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) {
        delete updated[sizeName];
      } else {
        updated[sizeName] = next;
      }
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});

    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        color: colorName,
        quantity: multiColorSelections[colorName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        size: sizeName,
        quantity: multiSizeSelections[sizeName],
        images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isTeamMode) {
      if (!formData.players || formData.players.length === 0) return alert("Добавьте игроков!");
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        quantity: formData.players.length,
        images: allImages,
        size: 'Team',
        gender: 'Универсальный'
      } as OrderItem);
    } else {
      onAddToCart({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        type: productType,
        subtype: initialSubtype,
        images: allImages
      } as OrderItem);
    }
  };

  const filteredSchools = SCHOOL_LIST.filter(s => 
    s.name.toLowerCase().includes(schoolSearch.toLowerCase())
  );

  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((a, b) => a + b, 0);

  const currentColorHex = COLORS.find(c => c.name === formData.color)?.hex || '#FFFFFF';

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">
            {initialSubtype}
          </h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {/* DESIGN TIPS BANNER */}
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6 animate-in slide-in-from-top-2 duration-500">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => (
                 <p key={i}>{line.trim()}</p>
               ))}
             </div>
          </div>
        )}

        {/* МОДЕЛЬ ИЗДЕЛИЯ (ДЛЯ ХУДИ И КЕПОК) */}
        {productType === ProductType.HOODIE && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель худи</label>
            <div className="flex flex-wrap gap-2">
              {[HoodieType.KANGAROO, HoodieType.ZIP, HoodieType.SWEATER].map(t => (
                <button
                  key={t}
                  onClick={() => setFormData({ ...formData, hoodieType: t })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.hoodieType === t 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {t === HoodieType.KANGAROO ? 'Кенгуру' : t === HoodieType.ZIP ? 'На молнии' : 'Свитшот'}
                </button>
              ))}
            </div>
          </div>
        )}

        {productType === ProductType.CAP && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель кепки</label>
            <div className="flex flex-wrap gap-2">
              {[CapType.BASEBALL, CapType.SNAPBACK, CapType.BEANIE].map(t => (
                <button
                  key={t}
                  onClick={() => setFormData({ ...formData, capType: t })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.capType === t 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {t === CapType.BASEBALL ? 'Бейсболка' : t === CapType.SNAPBACK ? 'Снэпбек' : 'Бини'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ВИЗУАЛИЗАЦИЯ ДЛЯ ЛИЧНОГО ДИЗАЙНА */}
        {initialSubtype === OrderSubtype.PERSONAL && (
          <div className="space-y-8">
            <div>
              <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Настройте места печати кликом</label>
              <ProductVisualizer 
                type={productType} 
                selectedPlaces={formData.printPlaces || []} 
                onToggle={togglePrintPlace}
                colorHex={currentColorHex}
                hasImage={(place) => !!formData.printImages?.[place]}
              />
            </div>

            {(formData.printPlaces || []).length > 0 && (
              <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {(formData.printPlaces || []).map(place => (
                    <div key={place} className="bg-gray-50 p-4 rounded-3xl border border-gray-100 flex items-center justify-between group">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center shadow-sm border border-gray-100 text-lg">
                          {formData.printImages?.[place] ? (
                            <img src={formData.printImages[place]} alt="preview" className="w-full h-full object-cover rounded-xl" />
                          ) : '🖼️'}
                        </div>
                        <div>
                          <p className="text-[10px] font-black text-gray-900 uppercase tracking-tight">{place}</p>
                          <p className="text-[9px] text-gray-400">{formData.printImages?.[place] ? 'Файл загружен' : 'Ожидание файла...'}</p>
                        </div>
                      </div>
                      <input 
                        type="file" 
                        accept="image/*"
                        className="hidden" 
                        ref={el => { fileInputRefs.current[place] = el; }}
                        onChange={(e) => handleFileUpload(place, e)}
                      />
                      <button 
                        onClick={() => fileInputRefs.current[place]?.click()}
                        className={`px-3 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${
                          formData.printImages?.[place] ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md hover:scale-105'
                        }`}
                      >
                        {formData.printImages?.[place] ? 'Заменить' : 'Загрузить'}
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* ШКОЛЫ - ВИЗУАЛЬНЫЙ ВЫБОР */}
        {initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input 
                type="text" 
                placeholder="Поиск по названию школы..." 
                className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium"
                value={schoolSearch}
                onChange={(e) => setSchoolSearch(e.target.value)}
              />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {filteredSchools.map(school => (
                <div 
                  key={school.id}
                  onClick={() => setFormData({ ...formData, school: school.name })}
                  className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${
                    formData.school === school.name 
                      ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' 
                      : 'border-gray-50 bg-gray-50 hover:border-indigo-200'
                  }`}
                >
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden">
                    <img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" />
                  </div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>
                    {school.name}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && productType !== ProductType.HOODIE && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button
                  key={g}
                  onClick={() => {
                    const newGender = g as 'Мальчик' | 'Девочка';
                    const availableSleeves = newGender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY;
                    const newSleeve = availableSleeves.includes(formData.sleeve || '') ? formData.sleeve : availableSleeves[0];
                    setFormData({ ...formData, gender: newGender, sleeve: newSleeve });
                  }}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.gender === g 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {g === 'Мальчик' ? 'Мальчики' : 'Девочки'}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {productType === ProductType.TSHIRT && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY).map(s => (
                <button
                  key={s}
                  onClick={() => setFormData({ ...formData, sleeve: s })}
                  className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase tracking-widest border-2 transition-all flex items-center justify-center ${
                    formData.sleeve === s 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : 
               (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])
              ).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button
                    key={size}
                    onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })}
                    onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }}
                    className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${
                      isSelected 
                        ? 'bg-indigo-600 text-white shadow-lg scale-105' 
                        : 'bg-gray-50 text-gray-400 hover:bg-gray-100'
                    }`}
                  >
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && (
                      <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                        {multiSizeSelections[size]}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">
            Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}
          </label>
          <div className="grid grid-cols-5 gap-3 mb-8">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button
                  key={c.hex}
                  onClick={() => {
                    if (isMultiColorMode) {
                      setMultiColorSelections(prev => {
                        const next = { ...prev };
                        if (next[c.name]) { /* Manage in list below */ } 
                        else next[c.name] = 1;
                        return next;
                      });
                    } else {
                      setFormData({ ...formData, color: c.name });
                    }
                  }}
                  className={`aspect-square rounded-[24px] transition-all relative group flex items-center justify-center ${
                    isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'
                  }`}
                  style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}
                >
                  {isSelected && (
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>
                      {isMultiColorMode ? (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>
                          {multiColorSelections[c.name]}
                        </span>
                      ) : (
                        <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>
                      )}
                    </div>
                  )}
                </button>
              );
            })}
          </div>

          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 animate-in fade-in slide-in-from-bottom-2 duration-400">
               {Object.entries(multiColorSelections).map(([cName, qty]) => {
                 const colorObj = COLORS.find(c => c.name === cName);
                 return (
                   <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex items-center gap-3">
                        <div className="w-5 h-5 rounded-full border border-gray-200 shadow-inner" style={{ backgroundColor: colorObj?.hex }}></div>
                        <span className="text-[13px] font-black text-gray-700 uppercase tracking-tight">{cName}</span>
                      </div>
                      <div className="flex items-center bg-white/80 rounded-xl p-1 border border-gray-100 gap-4">
                         <button onClick={() => setMultiColorSelections(prev => {
                             const next = { ...prev };
                             if (qty <= 1) delete next[cName];
                             else next[cName] = qty - 1;
                             return next;
                           })} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">−</button>
                         <span className="text-sm font-black text-gray-900 min-w-[20px] text-center">{qty}</span>
                         <button onClick={() => setMultiColorSelections(prev => ({...prev, [cName]: qty + 1}))} className="w-8 h-8 flex items-center justify-center bg-white border border-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 hover:border-indigo-200 transition-all font-bold text-lg">+</button>
                      </div>
                   </div>
                 );
               })}
            </div>
          )}
        </div>

        {isTeamMode && (
          <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} />
        )}

        {initialSubtype !== OrderSubtype.SCHOOL && initialSubtype !== OrderSubtype.PERSONAL && (
          <div className="pt-8 border-t border-gray-50">
             <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Места печати</label>
             <div className="flex gap-2">
               {PRINT_PLACES.map(p => (
                 <button
                   key={p}
                   onClick={() => togglePrintPlace(p)}
                   className={`px-5 h-11 rounded-full text-[10px] font-black uppercase tracking-wider transition-all border ${
                     formData.printPlaces?.includes(p) ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-gray-200 text-gray-400 hover:border-indigo-200'
                   }`}
                 >
                   {p}
                 </button>
               ))}
             </div>
          </div>
        )}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && (
          <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">
            Итого к заказу: <span className="text-indigo-600 ml-2 font-black text-lg">
              {isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.
            </span>
          </p>
        )}
        <Button 
          onClick={handleAdd} 
          variant="primary" 
          size="lg" 
          fullWidth
          className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200"
          disabled={
            (initialSubtype === OrderSubtype.SCHOOL && !formData.school) ||
            (isMultiSizeMode && totalMultiSizeQty === 0) || 
            (isMultiColorMode && Object.keys(multiColorSelections).length === 0) ||
            (isTeamMode && !formData.players?.length) ||
            (initialSubtype === OrderSubtype.PERSONAL && (
              (formData.printPlaces?.length === 0) || 
              (formData.printPlaces?.some(p => !formData.printImages?.[p]))
            ))
          }
        >
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

// Вспомогательный компонент для визуализации изделия (используется только для Школ и Команд)
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');
  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">ПЕРЕД</text>}

            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      {type === ProductType.CAP ? renderCap() : renderTshirt()}
      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button onClick={() => setView('front')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Спереди</button>
          <button onClick={() => setView('back')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Сзади</button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];
    if (initialSubtype === OrderSubtype.SCHOOL) defaultPrintPlaces = ['Спереди'];

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces, sleeve: 'Длинный', gender: 'Универсальный' }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }
    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving ? prev.printPlaces?.filter(p => p !== place) : [...(prev.printPlaces || []), place];
      const newPrintImages = { ...prev.printImages };
      if (isRemoving) delete newPrintImages[place];
      return { ...prev, printPlaces: newPlaces, printImages: newPrintImages };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printPlaces: prev.printPlaces?.includes(place) ? prev.printPlaces : [...(prev.printPlaces || []), place],
        printImages: { ...(prev.printImages || {}), [place]: base64 }
      }));
    };
    reader.readAsDataURL(file);
  };

  const removePrintImage = (place: string) => {
    setFormData(prev => {
      const newImages = { ...prev.printImages };
      delete newImages[place];
      return {
        ...prev,
        printPlaces: prev.printPlaces?.filter(p => p !== place),
        printImages: newImages
      };
    });
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) delete updated[sizeName];
      else updated[sizeName] = next;
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, color: colorName,
        quantity: multiColorSelections[colorName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, size: sizeName,
        quantity: multiSizeSelections[sizeName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else {
      onAddToCart({ ...formData, id: Math.random().toString(36).substr(2, 9), type: productType, subtype: initialSubtype, images: allImages } as OrderItem);
    }
  };

  // Определяем доступные зоны печати для Личного дизайна
  const getAvailablePrintZones = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">{initialSubtype}</h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => <p key={i}>{line.trim()}</p>)}
             </div>
          </div>
        )}

        {/* МОДЕЛЬ ИЗДЕЛИЯ */}
        {(productType === ProductType.HOODIE || productType === ProductType.CAP) && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель {productType === ProductType.CAP ? 'кепки' : 'худи'}</label>
            <div className="flex flex-wrap gap-2">
              {productType === ProductType.HOODIE ? 
                [HoodieType.KANGAROO, HoodieType.ZIP, HoodieType.SWEATER].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, hoodieType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.hoodieType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === HoodieType.KANGAROO ? 'Кенгуру' : t === HoodieType.ZIP ? 'На молнии' : 'Свитшот'}</button>
                )) :
                [CapType.BASEBALL, CapType.SNAPBACK, CapType.BEANIE].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, capType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.capType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === CapType.BASEBALL ? 'Бейсболка' : t === CapType.SNAPBACK ? 'Снэпбек' : 'Бини'}</button>
                ))
              }
            </div>
          </div>
        )}

        {/* ЛИЧНЫЙ ДИЗАЙН: ЗОНЫ ПЕЧАТИ (БЕЗ МАКЕТА) */}
        {initialSubtype === OrderSubtype.PERSONAL ? (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон печати</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {getAvailablePrintZones().map(place => {
                const hasImage = !!formData.printImages?.[place];
                return (
                  <div key={place} className={`bg-gray-50 p-5 rounded-[32px] border-2 transition-all group flex flex-col items-center text-center ${hasImage ? 'border-indigo-500 bg-indigo-50 shadow-lg' : 'border-gray-100 hover:border-indigo-200'}`}>
                    <div className="w-full flex justify-between items-start mb-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest ${hasImage ? 'text-indigo-600' : 'text-gray-400'}`}>{place}</span>
                       {hasImage && <button onClick={() => removePrintImage(place)} className="text-red-400 hover:text-red-600 text-xs font-bold uppercase tracking-widest">Удалить</button>}
                    </div>

                    <div className="w-24 h-24 mb-6 bg-white rounded-[24px] shadow-inner border border-gray-100 flex items-center justify-center overflow-hidden relative group-hover:scale-105 transition-transform">
                       {hasImage ? (
                         <img src={formData.printImages?.[place]} alt={place} className="w-full h-full object-cover" />
                       ) : (
                         <span className="text-3xl opacity-30">🖼️</span>
                       )}
                    </div>

                    <input type="file" accept="image/*" className="hidden" ref={el => { fileInputRefs.current[place] = el; }} onChange={(e) => handleFileUpload(place, e)} />
                    <button 
                      onClick={() => fileInputRefs.current[place]?.click()}
                      className={`w-full py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${hasImage ? 'bg-white text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md'}`}
                    >
                      {hasImage ? 'Заменить файл' : 'Загрузить макет'}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        ) : initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input type="text" placeholder="Поиск по названию школы..." className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium" value={schoolSearch} onChange={(e) => setSchoolSearch(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {SCHOOL_LIST.filter(s => s.name.toLowerCase().includes(schoolSearch.toLowerCase())).map(school => (
                <div key={school.id} onClick={() => setFormData({ ...formData, school: school.name })} className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${formData.school === school.name ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' : 'border-gray-50 bg-gray-50 hover:border-indigo-200'}`}>
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden"><img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" /></div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>{school.name}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && productType !== ProductType.HOODIE && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button key={g} onClick={() => setFormData({ ...formData, gender: g as any })} className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${formData.gender === g ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{g === 'Мальчик' ? 'Мальчики' : 'Девочки'}</button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {productType === ProductType.TSHIRT && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY).map(s => (
                <button key={s} onClick={() => setFormData({ ...formData, sleeve: s })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.sleeve === s ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'}`}>{s}</button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button key={size} onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })} onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }} className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${isSelected ? 'bg-indigo-600 text-white shadow-lg scale-105' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}>
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">{multiSizeSelections[size]}</span>}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}</label>
          <div className="grid grid-cols-5 gap-3">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button key={c.hex} onClick={() => isMultiColorMode ? setMultiColorSelections(p => ({...p, [c.name]: p[c.name] ? p[c.name] : 1})) : setFormData({ ...formData, color: c.name })} className={`aspect-square rounded-[24px] transition-all relative flex items-center justify-center ${isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'}`} style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}>
                  {isSelected && <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>{isMultiColorMode ? <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>{multiColorSelections[c.name]}</span> : <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>}</div>}
                </button>
              );
            })}
          </div>
          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-6">
               {Object.entries(multiColorSelections).map(([cName, qty]) => (
                 <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm">
                    <span className="text-[13px] font-black text-gray-700 uppercase">{cName}</span>
                    <div className="flex items-center bg-white/80 rounded-xl p-1 gap-4">
                       <button onClick={() => setMultiColorSelections(p => { const n = {...p}; if(qty <= 1) delete n[cName]; else n[cName] = qty-1; return n; })} className="w-8 h-8 flex items-center justify-center font-bold text-lg">−</button>
                       <span className="text-sm font-black">{qty}</span>
                       <button onClick={() => setMultiColorSelections(p => ({...p, [cName]: qty+1}))} className="w-8 h-8 flex items-center justify-center font-bold text-lg">+</button>
                    </div>
                 </div>
               ))}
            </div>
          )}
        </div>

        {isTeamMode && <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} />}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">Итого: <span className="text-indigo-600 font-black text-lg">{isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.</span></p>}
        <Button onClick={handleAdd} variant="primary" size="lg" fullWidth className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200" disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiSizeMode && totalMultiSizeQty === 0) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0) || (isTeamMode && !formData.players?.length) || (initialSubtype === OrderSubtype.PERSONAL && formData.printPlaces?.length === 0)}>
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

// Вспомогательный компонент для визуализации изделия (используется только для Школ и Команд)
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');
  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">ПЕРЕД</text>}

            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      {type === ProductType.CAP ? renderCap() : renderTshirt()}
      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button onClick={() => setView('front')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Спереди</button>
          <button onClick={() => setView('back')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Сзади</button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий'
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  // Fix: Calculate total quantity for multi-size mode to resolve compilation errors.
  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((acc, qty) => acc + qty, 0);

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];
    if (initialSubtype === OrderSubtype.SCHOOL) defaultPrintPlaces = ['Спереди'];

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces, sleeve: 'Длинный', gender: 'Универсальный' }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }
    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving ? prev.printPlaces?.filter(p => p !== place) : [...(prev.printPlaces || []), place];
      const newPrintImages = { ...prev.printImages };
      if (isRemoving) delete newPrintImages[place];
      return { ...prev, printPlaces: newPlaces, printImages: newPrintImages };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printPlaces: prev.printPlaces?.includes(place) ? prev.printPlaces : [...(prev.printPlaces || []), place],
        printImages: { ...(prev.printImages || {}), [place]: base64 }
      }));
    };
    reader.readAsDataURL(file);
  };

  const removePrintImage = (place: string) => {
    setFormData(prev => {
      const newImages = { ...prev.printImages };
      delete newImages[place];
      return {
        ...prev,
        printPlaces: prev.printPlaces?.filter(p => p !== place),
        printImages: newImages
      };
    });
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) delete updated[sizeName];
      else updated[sizeName] = next;
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, color: colorName,
        quantity: multiColorSelections[colorName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, size: sizeName,
        quantity: multiSizeSelections[sizeName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else {
      onAddToCart({ ...formData, id: Math.random().toString(36).substr(2, 9), type: productType, subtype: initialSubtype, images: allImages } as OrderItem);
    }
  };

  // Определяем доступные зоны печати для Личного дизайна
  const getAvailablePrintZones = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">{initialSubtype}</h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

