// Fix: Explicitly import Buffer to resolve 'Cannot find name Buffer' TypeScript error.
import { Buffer } from 'buffer';
import PDFDocument from 'pdfkit';
import { Order, OrderSubtype } from '../types';

export async function generateOrderPDF(order: Order): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    const doc = new PDFDocument({ margin: 50 });
    const chunks: Buffer[] = [];

    doc.on('data', (chunk) => chunks.push(chunk));
    doc.on('end', () => resolve(Buffer.concat(chunks)));
    doc.on('error', (err) => reject(err));

    // Header
    doc.fontSize(20).text('ЗАКАЗ - ' + order.orderNumber, { align: 'center' });
    doc.moveDown();

    // Status
    doc.fontSize(12).text(`Статус: ${order.status}`, { align: 'right' });
    doc.moveDown();

    // Customer Info
    doc.fontSize(14).text('Контактные данные клиента:', { underline: true });
    doc.fontSize(12).text(`Имя: ${order.customer.name}`);
    doc.text(`Телефон: ${order.customer.phone}`);
    doc.text(`Email: ${order.customer.email}`);
    if (order.customer.address) doc.text(`Адрес: ${order.customer.address}`);
    if (order.customer.comments) doc.text(`Комментарий: ${order.customer.comments}`);
    doc.moveDown();

    // Order Items
    doc.fontSize(14).text('Позиции заказа:', { underline: true });
    doc.moveDown(0.5);

    order.items.forEach((item, index) => {
      const displayType = item.type === 'TANK_TOP' ? 'Майка' : 
                          item.type === 'TSHIRT' ? 'Футболка' : 
                          item.type === 'HOODIE' ? 'Худи' : 'Шапка';

      doc.fontSize(12).text(`${index + 1}. ${displayType} [${item.subtype}]`, { bold: true });
      doc.fontSize(10);
      doc.text(`Цвет: ${item.color}`);
      if (item.fabric) doc.text(`Ткань: ${item.fabric}`);
      doc.text(`Размер: ${item.size}`);
      doc.text(`Количество: ${item.quantity}`);

      if (item.school) doc.text(`Школа: ${item.school}`);
      if (item.gender && item.subtype !== OrderSubtype.TEAM) doc.text(`Пол: ${item.gender}`);
      if (item.sleeve && item.subtype !== OrderSubtype.TEAM) doc.text(`Рукав: ${item.sleeve}`);
      if (item.hoodieType) doc.text(`Тип худи: ${item.hoodieType}`);
      if (item.capType) doc.text(`Тип шапки: ${item.capType}`);

      if (item.printPlaces && item.printPlaces.length > 0) {
        doc.text(`Места печати: ${item.printPlaces.join(', ')}`);
      }

      if (item.subtype === OrderSubtype.TEAM && item.players && item.players.length > 0) {
        doc.moveDown(0.2);
        doc.fontSize(11).text('СПИСОК ИГРОКОВ КОМАНДЫ:', { bold: true });
        doc.fontSize(10);
        item.players.forEach((p, pIdx) => {
          doc.text(`  ${pIdx + 1}. ${p.name} — №${p.number} — Разм: ${p.size} — ${p.gender} — Рукав: ${p.sleeve}`);
        });
      }

      doc.moveDown();
    });

    doc.fontSize(10).text(`Дата создания: ${new Date(order.createdAt).toLocaleString()}`, { align: 'right' });

    doc.end();
  });
}

import axios from 'axios';
import { Order, OrderSubtype } from '../types';

const TRELLO_KEY = process.env.TRELLO_KEY;
const TRELLO_TOKEN = process.env.TRELLO_TOKEN;
const TRELLO_LIST_ID = process.env.TRELLO_LIST_ID || 'Egor2_List_ID';

export async function createTrelloCard(order: Order) {
  if (!TRELLO_KEY || !TRELLO_TOKEN) {
    console.warn('Trello API keys missing, skipping card creation');
    return;
  }

  const itemsDetails = order.items.map(item => {
    let detail = `- ${item.quantity}x ${item.type} (${item.subtype}), Цвет: ${item.color}, Размер: ${item.size}`;

    if (item.fabric) detail += `, Ткань: ${item.fabric}`;

    if (item.subtype === OrderSubtype.TEAM && item.players && item.players.length > 0) {
      detail += `\n  **СПИСОК КОМАНДЫ (${item.players.length} чел.):**`;
      item.players.forEach(p => {
        detail += `\n  • ${p.name} | №${p.number} | ${p.size} | ${p.gender} | Рукав: ${p.sleeve}`;
      });
    } else if (item.subtype === OrderSubtype.SCHOOL && item.school) {
      detail += `\n  Школа: ${item.school}`;
    }

    if (item.printPlaces && item.printPlaces.length > 0) {
      detail += `\n  Места печати: ${item.printPlaces.join(', ')}`;
    }

    return detail;
  }).join('\n\n');

  const description = `
**КЛИЕНТ:** ${order.customer.name}
**ТЕЛЕФОН:** ${order.customer.phone}
**EMAIL:** ${order.customer.email}
**АДРЕС:** ${order.customer.address || 'Не указан'}

---
**СОСТАВ ЗАКАЗА:**
${itemsDetails}

---
**КОММЕНТАРИЙ:** ${order.customer.comments || 'Нет'}
**ДАТА:** ${new Date(order.createdAt).toLocaleString()}
  `;

  try {
    await axios.post(`https://api.trello.com/1/cards`, null, {
      params: {
        idList: TRELLO_LIST_ID,
        key: TRELLO_KEY,
        token: TRELLO_TOKEN,
        name: `ЗАКАЗ ${order.orderNumber} - ${order.customer.name}`,
        desc: description,
        pos: 'top'
      }
    });
    console.log('Trello card created successfully');
  } catch (error) {
    console.error('Failed to create Trello card:', error);
  }
}

import React, { useRef } from 'react';
import { Player, ProductType } from '../types';
import { Button } from './ui/Button';
import { TEAM_SIZES_KIDS, TEAM_SIZES_ADULTS } from '../constants';

interface PlayerTableProps {
  players: Player[];
  onChange: (players: Player[]) => void;
  onExcelImport?: (fileName: string) => void;
  productType?: ProductType;
}

export const PlayerTable: React.FC<PlayerTableProps> = ({ players, onChange, onExcelImport, productType }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const addPlayer = () => {
    const newPlayer: Player = {
      id: Math.random().toString(36).substr(2, 9),
      name: '',
      number: '',
      gender: 'Мальчик',
      sleeve: 'Короткий',
      size: 'S'
    };
    onChange([...players, newPlayer]);
  };

  const removePlayer = (id: string) => {
    onChange(players.filter(p => p.id !== id));
  };

  const updatePlayer = (id: string, field: keyof Player, value: string) => {
    onChange(players.map(p => p.id === id ? { ...p, [field]: value } : p));
  };

  // Помощник для нормализации размера (из "large" в "L", из "s" в "S")
  const normalizeSize = (raw: string): string => {
    if (!raw) return 'S';
    let clean = raw.trim().toUpperCase();

    // Маппинг полных названий на английском
    if (clean === 'LARGE') return 'L';
    if (clean === 'MEDIUM') return 'M';
    if (clean === 'SMALL') return 'S';
    if (clean === 'EXTRA LARGE' || clean === 'EXTRALARGE') return 'XL';

    // Если размер уже сокращен (S, M, L, XL), возвращаем его
    const allowedSizes = [...TEAM_SIZES_KIDS, ...TEAM_SIZES_ADULTS];
    if (allowedSizes.includes(clean)) return clean;

    // Проверка числовых размеров (например, 10, 12)
    if (TEAM_SIZES_KIDS.includes(clean)) return clean;

    return clean.length > 3 ? 'S' : clean; // Если что-то совсем странное, ставим S
  };

  const handleExcelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();

    // Читаем как текст. По умолчанию браузер пробует UTF-8.
    // Если в файле иврит/кириллица в старой кодировке Excel (ANSI), ромбики останутся.
    // Мы можем использовать TextDecoder для более надежного чтения.
    reader.onload = (event) => {
      const arrayBuffer = event.target?.result as ArrayBuffer;
      const decoder = new TextDecoder('utf-8'); // По умолчанию UTF-8
      let content = decoder.decode(arrayBuffer);

      // Проверка на корректность декодирования (ищем "битые" символы)
      if (content.includes('')) {
        // Если UTF-8 не подошел, пробуем Windows-1255 (иврит) или Windows-1251 (кириллица)
        // Для универсальности в вебе часто используют 'windows-1252' или 'windows-1255'
        const altDecoder = new TextDecoder('windows-1255'); 
        content = altDecoder.decode(arrayBuffer);
      }

      if (!content) return;

      const rows = content.split(/\r?\n/).filter(row => row.trim() !== '');

      // Пропускаем заголовок, если он есть (проверяем по слову "Имя", "Name", "שם")
      const firstRow = rows[0].toLowerCase();
      const hasHeader = firstRow.includes('имя') || firstRow.includes('name') || firstRow.includes('שם') || firstRow.includes('מספר') || firstRow.includes('מידה');
      const dataRows = hasHeader ? rows.slice(1) : rows;

      const newPlayers: Player[] = dataRows.map(row => {
        // Разделяем по запятой, точке с запятой или табуляции
        const cols = row.split(/[,;\t]/).map(c => c.trim().replace(/^["']|["']$/g, ''));

        // Маппинг согласно скриншоту пользователя:
        // A (0): Имя
        // B (1): Номер
        // C (2): Размер
        return {
          id: Math.random().toString(36).substr(2, 9),
          name: cols[0] || '',
          number: cols[1] || '',
          gender: 'Мальчик',
          size: normalizeSize(cols[2] || 'S'),
          sleeve: 'Короткий'
        };
      });

      onChange([...players, ...newPlayers]);
      if (onExcelImport) onExcelImport(file.name);
    };

    reader.readAsArrayBuffer(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="mt-4 overflow-x-auto bg-white rounded-3xl shadow-inner p-6 border border-gray-100">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h3 className="text-lg font-black text-gray-800 uppercase tracking-tight">Список команды</h3>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Всего участников: {players.length}</p>
        </div>
        <div className="flex gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleExcelUpload} 
            accept=".csv, .txt" 
            className="hidden" 
          />
          <Button 
            variant="outline" 
            size="sm" 
            onClick={() => fileInputRef.current?.click()}
            className="text-[9px] py-2 h-9 rounded-xl font-black uppercase tracking-widest"
          >
            📊 Импорт из Excel
          </Button>
        </div>
      </div>

      <table className="min-w-full divide-y divide-gray-100">
        <thead>
          <tr className="text-left text-[9px] font-black text-gray-400 uppercase tracking-[0.2em]">
            <th className="px-3 py-4">Имя / Фамилия</th>
            <th className="px-3 py-4 text-center">Номер</th>
            <th className="px-3 py-4 text-center">Размер</th>
            <th className="px-3 py-4"></th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-50">
          {players.map((player) => (
            <tr key={player.id} className="hover:bg-indigo-50/30 transition-colors group">
              <td className="px-3 py-3">
                <input 
                  type="text" 
                  value={player.name}
                  onChange={(e) => updatePlayer(player.id, 'name', e.target.value)}
                  className="w-full border-b border-transparent focus:border-indigo-400 outline-none p-1 text-sm bg-transparent font-medium text-gray-800"
                  placeholder="Введите имя..."
                />
              </td>
              <td className="px-3 py-3 text-center">
                <input 
                  type="text" 
                  value={player.number}
                  onChange={(e) => updatePlayer(player.id, 'number', e.target.value)}
                  className="w-12 border-b border-transparent focus:border-indigo-400 outline-none p-1 text-sm text-center bg-transparent font-black text-indigo-600"
                  placeholder="00"
                />
              </td>
              <td className="px-3 py-3 text-center">
                <select 
                   value={player.size}
                   onChange={(e) => updatePlayer(player.id, 'size', e.target.value)}
                   className="text-xs font-black outline-none bg-indigo-50/50 rounded-lg px-2 py-1 cursor-pointer hover:bg-indigo-100 transition-colors text-indigo-700"
                >
                  <optgroup label="Дети">
                    {TEAM_SIZES_KIDS.map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                  <optgroup label="Взрослые">
                    {TEAM_SIZES_ADULTS.map(s => <option key={s} value={s}>{s}</option>)}
                  </optgroup>
                </select>
              </td>
              <td className="px-3 py-3 text-right">
                <button 
                  onClick={() => removePlayer(player.id)}
                  className="text-gray-300 hover:text-red-500 transition-colors p-2"
                >
                  ✕
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {players.length === 0 && (
        <div className="py-12 text-center text-gray-300 text-[11px] font-bold uppercase tracking-widest italic bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-100 mt-4">
          Добавьте игроков или загрузите файл
        </div>
      )}

      <Button 
        onClick={addPlayer} 
        variant="outline" 
        size="sm" 
        className="mt-6 border-dashed w-full h-12 bg-white hover:bg-indigo-50 border-gray-200 text-gray-400 hover:text-indigo-600 font-black text-[10px] uppercase tracking-widest transition-all"
      >
        + Добавить игрока в список
      </Button>
    </div>
  );
};

