export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий',
    fabric: FABRICS[0]
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  // Fix: Calculate total quantity for multi-size mode to resolve compilation errors.
  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((acc, qty) => acc + qty, 0);

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];
    if (initialSubtype === OrderSubtype.SCHOOL) defaultPrintPlaces = ['Спереди'];

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces, sleeve: 'Длинный', gender: 'Универсальный' }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }
    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving ? prev.printPlaces?.filter(p => p !== place) : [...(prev.printPlaces || []), place];
      const newPrintImages = { ...prev.printImages };
      if (isRemoving) delete newPrintImages[place];
      return { ...prev, printPlaces: newPlaces, printImages: newPrintImages };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printPlaces: prev.printPlaces?.includes(place) ? prev.printPlaces : [...(prev.printPlaces || []), place],
        printImages: { ...(prev.printImages || {}), [place]: base64 }
      }));
    };
    reader.readAsDataURL(file);
  };

  const removePrintImage = (place: string) => {
    setFormData(prev => {
      const newImages = { ...prev.printImages };
      delete newImages[place];
      return {
        ...prev,
        printPlaces: prev.printPlaces?.filter(p => p !== place),
        printImages: newImages
      };
    });
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) delete updated[sizeName];
      else updated[sizeName] = next;
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, color: colorName,
        quantity: multiColorSelections[colorName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, size: sizeName,
        quantity: multiSizeSelections[sizeName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else {
      onAddToCart({ ...formData, id: Math.random().toString(36).substr(2, 9), type: productType, subtype: initialSubtype, images: allImages } as OrderItem);
    }
  };

  // Определяем доступные зоны печати для Личного дизайна
  const getAvailablePrintZones = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">{initialSubtype}</h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => <p key={i}>{line.trim()}</p>)}
             </div>
          </div>
        )}

        {/* МОДЕЛЬ ИЗДЕЛИЯ */}
        {(productType === ProductType.HOODIE || productType === ProductType.CAP) && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель {productType === ProductType.CAP ? 'кепки' : 'худи'}</label>
            <div className="flex flex-wrap gap-2">
              {productType === ProductType.HOODIE ? 
                [HoodieType.KANGAROO, HoodieType.ZIP, HoodieType.SWEATER].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, hoodieType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.hoodieType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === HoodieType.KANGAROO ? 'Кенгуру' : t === HoodieType.ZIP ? 'На молнии' : 'Свитшот'}</button>
                )) :
                [CapType.BASEBALL, CapType.SNAPBACK, CapType.BEANIE].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, capType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.capType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === CapType.BASEBALL ? 'Бейсболка' : t === CapType.SNAPBACK ? 'Снэпбек' : 'Бини'}</button>
                ))
              }
            </div>
          </div>
        )}

        {/* ВЫБОР ТКАНИ (ТОЛЬКО ДЛЯ КОМАНДНЫХ ФУТБОЛОК) */}
        {isTeamMode && productType === ProductType.TSHIRT && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выбор ткани</label>
            <div className="flex gap-3">
              {FABRICS.map(f => (
                <button
                  key={f}
                  onClick={() => setFormData({ ...formData, fabric: f })}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${
                    formData.fabric === f 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {f}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ЛИЧНЫЙ ДИЗАЙН: ЗОНЫ ПЕЧАТИ (БЕЗ МАКЕТА) */}
        {initialSubtype === OrderSubtype.PERSONAL ? (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон печати</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {getAvailablePrintZones().map(place => {
                const hasImage = !!formData.printImages?.[place];
                return (
                  <div key={place} className={`bg-gray-50 p-5 rounded-[32px] border-2 transition-all group flex flex-col items-center text-center ${hasImage ? 'border-indigo-500 bg-indigo-50 shadow-lg' : 'border-gray-100 hover:border-indigo-200'}`}>
                    <div className="w-full flex justify-between items-start mb-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest ${hasImage ? 'text-indigo-600' : 'text-gray-400'}`}>{place}</span>
                       {hasImage && <button onClick={() => removePrintImage(place)} className="text-red-400 hover:text-red-600 text-xs font-bold uppercase tracking-widest">Удалить</button>}
                    </div>

                    <div className="w-24 h-24 mb-6 bg-white rounded-[24px] shadow-inner border border-gray-100 flex items-center justify-center overflow-hidden relative group-hover:scale-105 transition-transform">
                       {hasImage ? (
                         <img src={formData.printImages?.[place]} alt={place} className="w-full h-full object-cover" />
                       ) : (
                         <span className="text-3xl opacity-30">🖼️</span>
                       )}
                    </div>

                    <input type="file" accept="image/*" className="hidden" ref={el => { fileInputRefs.current[place] = el; }} onChange={(e) => handleFileUpload(place, e)} />
                    <button 
                      onClick={() => fileInputRefs.current[place]?.click()}
                      className={`w-full py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${hasImage ? 'bg-white text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md'}`}
                    >
                      {hasImage ? 'Заменить файл' : 'Загрузить макет'}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        ) : initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input type="text" placeholder="Поиск по названию школы..." className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium" value={schoolSearch} onChange={(e) => setSchoolSearch(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {SCHOOL_LIST.filter(s => s.name.toLowerCase().includes(schoolSearch.toLowerCase())).map(school => (
                <div key={school.id} onClick={() => setFormData({ ...formData, school: school.name })} className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${formData.school === school.name ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' : 'border-gray-50 bg-gray-50 hover:border-indigo-200'}`}>
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden"><img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" /></div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>{school.name}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО */}
        {productType !== ProductType.CAP && productType !== ProductType.TANK_TOP && productType !== ProductType.HOODIE && !isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button key={g} onClick={() => setFormData({ ...formData, gender: g as any })} className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${formData.gender === g ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{g === 'Мальчик' ? 'Мальчики' : 'Девочки'}</button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {productType === ProductType.TSHIRT && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY).map(s => (
                <button key={s} onClick={() => setFormData({ ...formData, sleeve: s })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.sleeve === s ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'}`}>{s}</button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button key={size} onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })} onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }} className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${isSelected ? 'bg-indigo-600 text-white shadow-lg scale-105' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}>
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">{multiSizeSelections[size]}</span>}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}</label>
          <div className="grid grid-cols-5 gap-3">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button key={c.hex} onClick={() => isMultiColorMode ? setMultiColorSelections(p => ({...p, [c.name]: p[c.name] ? p[c.name] : 1})) : setFormData({ ...formData, color: c.name })} className={`aspect-square rounded-[24px] transition-all relative flex items-center justify-center ${isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'}`} style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}>
                  {isSelected && <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>{isMultiColorMode ? <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>{multiColorSelections[c.name]}</span> : <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>}</div>}
                </button>
              );
            })}
          </div>
          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-6">
               {Object.entries(multiColorSelections).map(([cName, qty]) => (
                 <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm">
                    <span className="text-[13px] font-black text-gray-700 uppercase">{cName}</span>
                    <div className="flex items-center bg-white/80 rounded-xl p-1 gap-4">
                       <button onClick={() => setMultiColorSelections(p => { const n = {...p}; if(qty <= 1) delete n[cName]; else n[cName] = qty-1; return n; })} className="w-8 h-8 flex items-center justify-center font-bold text-lg">−</button>
                       <span className="text-sm font-black">{qty}</span>
                       <button onClick={() => setMultiColorSelections(p => ({...p, [cName]: qty+1}))} className="w-8 h-8 flex items-center justify-center font-bold text-lg">+</button>
                    </div>
                 </div>
               ))}
            </div>
          )}
        </div>

        {isTeamMode && <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} productType={productType} />}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">Итого: <span className="text-indigo-600 font-black text-lg">{isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.</span></p>}
        <Button onClick={handleAdd} variant="primary" size="lg" fullWidth className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200" disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiSizeMode && totalMultiSizeQty === 0) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0) || (isTeamMode && !formData.players?.length) || (initialSubtype === OrderSubtype.PERSONAL && formData.printPlaces?.length === 0)}>
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

const FABRICS = ['100% хлопок', 'DryFit'];

// Вспомогательный компонент для визуализации изделия (используется только для Школ и Команд)
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');
  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">ПЕРЕД</text>}

            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      {type === ProductType.CAP ? renderCap() : renderTshirt()}
      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button onClick={() => setView('front')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Спереди</button>
          <button onClick={() => setView('back')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Сзади</button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий',
    fabric: FABRICS[0]
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  // Fix: Calculate total quantity for multi-size mode to resolve compilation errors.
  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((acc, qty) => acc + qty, 0);

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];
    if (initialSubtype === OrderSubtype.SCHOOL) defaultPrintPlaces = ['Спереди'];

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces, sleeve: 'Длинный', gender: 'Универсальный' }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else if (initialSubtype === OrderSubtype.PERSONAL && productType === ProductType.TSHIRT) {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий', gender: 'Универсальный' }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }
    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving ? prev.printPlaces?.filter(p => p !== place) : [...(prev.printPlaces || []), place];
      const newPrintImages = { ...prev.printImages };
      if (isRemoving) delete newPrintImages[place];
      return { ...prev, printPlaces: newPlaces, printImages: newPrintImages };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printPlaces: prev.printPlaces?.includes(place) ? prev.printPlaces : [...(prev.printPlaces || []), place],
        printImages: { ...(prev.printImages || {}), [place]: base64 }
      }));
    };
    reader.readAsDataURL(file);
  };

  const removePrintImage = (place: string) => {
    setFormData(prev => {
      const newImages = { ...prev.printImages };
      delete newImages[place];
      return {
        ...prev,
        printPlaces: prev.printPlaces?.filter(p => p !== place),
        printImages: newImages
      };
    });
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) delete updated[sizeName];
      else updated[sizeName] = next;
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, color: colorName,
        quantity: multiColorSelections[colorName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, size: sizeName,
        quantity: multiSizeSelections[sizeName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else {
      onAddToCart({ ...formData, id: Math.random().toString(36).substr(2, 9), type: productType, subtype: initialSubtype, images: allImages } as OrderItem);
    }
  };

  // Определяем доступные зоны печати для Личного дизайна
  const getAvailablePrintZones = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">{initialSubtype}</h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => <p key={i}>{line.trim()}</p>)}
             </div>
          </div>
        )}

        {/* МОДЕЛЬ ИЗДЕЛИЯ */}
        {(productType === ProductType.HOODIE || productType === ProductType.CAP) && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель {productType === ProductType.CAP ? 'кепки' : 'худи'}</label>
            <div className="flex flex-wrap gap-2">
              {productType === ProductType.HOODIE ? 
                [HoodieType.KANGAROO, HoodieType.ZIP, HoodieType.SWEATER].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, hoodieType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.hoodieType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === HoodieType.KANGAROO ? 'Кенгуру' : t === HoodieType.ZIP ? 'На молнии' : 'Свитшот'}</button>
                )) :
                [CapType.BASEBALL, CapType.SNAPBACK, CapType.BEANIE].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, capType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.capType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === CapType.BASEBALL ? 'Бейсболка' : t === CapType.SNAPBACK ? 'Снэпбек' : 'Бини'}</button>
                ))
              }
            </div>
          </div>
        )}

        {/* ВЫБОР ТКАНИ (ТОЛЬКО ДЛЯ КОМАНДНЫХ ФУТБОЛОК) */}
        {isTeamMode && productType === ProductType.TSHIRT && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выбор ткани</label>
            <div className="flex gap-3">
              {FABRICS.map(f => (
                <button
                  key={f}
                  onClick={() => setFormData({ ...formData, fabric: f })}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${
                    formData.fabric === f 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {f}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ЛИЧНЫЙ ДИЗАЙН: ЗОНЫ ПЕЧАТИ (БЕЗ МАКЕТА) */}
        {initialSubtype === OrderSubtype.PERSONAL ? (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон печати</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {getAvailablePrintZones().map(place => {
                const hasImage = !!formData.printImages?.[place];
                return (
                  <div key={place} className={`bg-gray-50 p-5 rounded-[32px] border-2 transition-all group flex flex-col items-center text-center ${hasImage ? 'border-indigo-500 bg-indigo-50 shadow-lg' : 'border-gray-100 hover:border-indigo-200'}`}>
                    <div className="w-full flex justify-between items-start mb-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest ${hasImage ? 'text-indigo-600' : 'text-gray-400'}`}>{place}</span>
                       {hasImage && <button onClick={() => removePrintImage(place)} className="text-red-400 hover:text-red-600 text-xs font-bold uppercase tracking-widest">Удалить</button>}
                    </div>

                    <div className="w-24 h-24 mb-6 bg-white rounded-[24px] shadow-inner border border-gray-100 flex items-center justify-center overflow-hidden relative group-hover:scale-105 transition-transform">
                       {hasImage ? (
                         <img src={formData.printImages?.[place]} alt={place} className="w-full h-full object-cover" />
                       ) : (
                         <span className="text-3xl opacity-30">🖼️</span>
                       )}
                    </div>

                    <input type="file" accept="image/*" className="hidden" ref={el => { fileInputRefs.current[place] = el; }} onChange={(e) => handleFileUpload(place, e)} />
                    <button 
                      onClick={() => fileInputRefs.current[place]?.click()}
                      className={`w-full py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${hasImage ? 'bg-white text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md'}`}
                    >
                      {hasImage ? 'Заменить файл' : 'Загрузить макет'}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        ) : initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input type="text" placeholder="Поиск по названию школы..." className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium" value={schoolSearch} onChange={(e) => setSchoolSearch(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {SCHOOL_LIST.filter(s => s.name.toLowerCase().includes(schoolSearch.toLowerCase())).map(school => (
                <div key={school.id} onClick={() => setFormData({ ...formData, school: school.name })} className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${formData.school === school.name ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' : 'border-gray-50 bg-gray-50 hover:border-indigo-200'}`}>
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden"><img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" /></div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>{school.name}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО (СКРЫВАЕМ ДЛЯ ЛИЧНОГО ДИЗАЙНА) */}
        {productType !== ProductType.CAP && 
         productType !== ProductType.TANK_TOP && 
         productType !== ProductType.HOODIE && 
         !isTeamMode && 
         initialSubtype !== OrderSubtype.PERSONAL && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button key={g} onClick={() => setFormData({ ...formData, gender: g as any })} className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${formData.gender === g ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{g === 'Мальчик' ? 'Мальчики' : 'Девочки'}</button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {productType === ProductType.TSHIRT && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(initialSubtype === OrderSubtype.PERSONAL 
                ? SLEEVES.BOY 
                : (formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY)
              ).map(s => (
                <button key={s} onClick={() => setFormData({ ...formData, sleeve: s })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.sleeve === s ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'}`}>{s}</button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button key={size} onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })} onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }} className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${isSelected ? 'bg-indigo-600 text-white shadow-lg scale-105' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}>
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">{multiSizeSelections[size]}</span>}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}</label>
          <div className="grid grid-cols-5 gap-3">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button key={c.hex} onClick={() => isMultiColorMode ? setMultiColorSelections(p => ({...p, [c.name]: p[c.name] ? p[c.name] : 1})) : setFormData({ ...formData, color: c.name })} className={`aspect-square rounded-[24px] transition-all relative flex items-center justify-center ${isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'}`} style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}>
                  {isSelected && <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>{isMultiColorMode ? <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>{multiColorSelections[c.name]}</span> : <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>}</div>}
                </button>
              );
            })}
          </div>
          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-6">
               {Object.entries(multiColorSelections).map(([cName, qty]) => (
                 <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm">
                    <span className="text-[13px] font-black text-gray-700 uppercase">{cName}</span>
                    <div className="flex items-center bg-white/80 rounded-xl p-1 gap-4">
                       <button onClick={() => setMultiColorSelections(p => { const n = {...p}; if(qty <= 1) delete n[cName]; else n[cName] = qty-1; return n; })} className="w-8 h-8 flex items-center justify-center font-bold text-lg">−</button>
                       <span className="text-sm font-black">{qty}</span>
                       <button onClick={() => setMultiColorSelections(p => ({...p, [cName]: qty+1}))} className="w-8 h-8 flex items-center justify-center font-bold text-lg">+</button>
                    </div>
                 </div>
               ))}
            </div>
          )}
        </div>

        {isTeamMode && <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} productType={productType} />}
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">Итого: <span className="text-indigo-600 font-black text-lg">{isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.</span></p>}
        <Button onClick={handleAdd} variant="primary" size="lg" fullWidth className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200" disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiSizeMode && totalMultiSizeQty === 0) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0) || (isTeamMode && !formData.players?.length) || (initialSubtype === OrderSubtype.PERSONAL && formData.printPlaces?.length === 0)}>
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

export enum ProductType {
  TSHIRT = 'TSHIRT',
  HOODIE = 'HOODIE',
  CAP = 'CAP',
  TANK_TOP = 'TANK_TOP'
}

export enum OrderSubtype {
  SCHOOL = 'Школа',
  PERSONAL = 'Личный дизайн',
  TEAM = 'Команда'
}

export enum HoodieType {
  ZIP = 'На молнии с капюшоном',
  KANGAROO = 'Кенгуру с капюшоном',
  SWEATER = 'Свитер без капюшона'
}

export enum CapType {
  BASEBALL = 'Бейсболка',
  BEANIE = 'Шапка-бини',
  SNAPBACK = 'Снэпбек'
}

export type OrderStatus = 'New' | 'Processing' | 'Completed' | 'Cancelled';

export interface Player {
  id: string;
  name: string;
  number: string;
  gender: 'Мальчик' | 'Девочка';
  sleeve: string;
  size: string;
}

export interface OrderItem {
  id: string;
  type: ProductType;
  subtype: OrderSubtype;
  school?: string;
  printPlaces: string[];
  images: string[]; // Generic list for backwards compatibility
  printImages?: Record<string, string>; // Mapping: Place -> Image Data
  players?: Player[];
  hoodieType?: HoodieType;
  capType?: CapType;
  gender?: 'Мальчик' | 'Девочка' | 'Универсальный';
  sleeve?: string;
  size: string;
  color: string;
  quantity: number;
  fabric?: string;
  wishes?: string;
}

export interface CustomerData {
  name: string;
  phone: string;
  email: string;
  address?: string;
  comments?: string;
}

export interface Order {
  orderNumber: string;
  customer: CustomerData;
  items: OrderItem[];
  createdAt: string;
  status: OrderStatus;
  viewed: boolean;
  internalNotes?: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  ProductType, OrderSubtype, OrderItem, HoodieType, CapType,
} from '../types';
import { 
  COLORS, SCHOOL_LIST, PRINT_PLACES, SLEEVES,
  SCHOOL_SIZES_KIDS, SCHOOL_SIZES_ADULTS,
  PERSONAL_SIZES_KIDS, PERSONAL_SIZES_ADULTS
} from '../constants';
import { Button } from './ui/Button';
import { PlayerTable } from './PlayerTable';
import { getDesignFeedback } from '../services/geminiService';

interface OrderFormProps {
  productType: ProductType;
  initialSubtype: OrderSubtype;
  onAddToCart: (item: OrderItem | OrderItem[]) => void;
  onCancel: () => void;
}

const FABRICS = ['100% хлопок', 'DryFit'];

// Вспомогательный компонент для визуализации изделия (используется только для Школ и Команд)
const ProductVisualizer: React.FC<{
  type: ProductType;
  selectedPlaces: string[];
  onToggle: (place: string) => void;
  colorHex: string;
  hasImage: (place: string) => boolean;
}> = ({ type, selectedPlaces, onToggle, colorHex, hasImage }) => {
  const [view, setView] = useState<'front' | 'back'>('front');
  const isSelected = (place: string) => selectedPlaces.includes(place);

  const renderTshirt = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path 
          d="M40,40 L60,20 L140,20 L160,40 L190,50 L170,90 L150,80 L150,180 L50,180 L50,80 L30,90 L10,50 Z" 
          fill={colorHex} 
          stroke="#e5e7eb" 
          strokeWidth="1"
        />
        {view === 'front' ? (
          <>
            <rect 
              x="70" y="50" width="60" height="80" 
              rx="4" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Спереди') ? '3' : '1'}
              strokeDasharray={isSelected('Спереди') ? '0' : '4 2'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Спереди')}
            />
            {isSelected('Спереди') && <text x="100" y="95" textAnchor="middle" className="text-[8px] font-black pointer-events-none fill-indigo-600 uppercase tracking-tighter">ПЕРЕД</text>}

            <path 
              d="M10,50 L30,90 L50,80 L40,40 Z" 
              fill={isSelected('Правый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Правый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Правый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Правый рукав')}
            />
            <path 
              d="M190,50 L170,90 L150,80 L160,40 Z" 
              fill={isSelected('Левый рукав') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
              stroke={isSelected('Левый рукав') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
              strokeWidth={isSelected('Левый рукав') ? '2' : '1'}
              className="cursor-pointer transition-all hover:fill-indigo-50"
              onClick={() => onToggle('Левый рукав')}
            />
          </>
        ) : (
          <rect 
            x="70" y="50" width="60" height="100" 
            rx="4" fill={isSelected('Сзади') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
            stroke={isSelected('Сзади') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
            strokeWidth={isSelected('Сзади') ? '3' : '1'}
            strokeDasharray={isSelected('Сзади') ? '0' : '4 2'}
            className="cursor-pointer transition-all hover:fill-indigo-50"
            onClick={() => onToggle('Сзади')}
          />
        )}
      </svg>
    </div>
  );

  const renderCap = () => (
    <div className="relative w-64 h-64 mx-auto animate-in fade-in duration-500">
      <svg viewBox="0 0 200 200" className="w-full h-full drop-shadow-xl">
        <path d="M20,120 Q20,40 100,40 Q180,40 180,120 L190,140 L10,140 Z" fill={colorHex} stroke="#e5e7eb" strokeWidth="1" />
        <rect 
          x="60" y="60" width="80" height="50" 
          rx="8" fill={isSelected('Спереди') ? 'rgba(79, 70, 229, 0.1)' : 'transparent'}
          stroke={isSelected('Спереди') ? '#4f46e5' : 'rgba(0,0,0,0.05)'}
          strokeWidth={isSelected('Спереди') ? '3' : '1'}
          onClick={() => onToggle('Спереди')}
        />
      </svg>
    </div>
  );

  return (
    <div className="bg-gray-50 rounded-[32px] p-8 relative overflow-hidden group">
      {type === ProductType.CAP ? renderCap() : renderTshirt()}
      {type !== ProductType.CAP && (
        <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
          <button onClick={() => setView('front')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'front' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Спереди</button>
          <button onClick={() => setView('back')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${view === 'back' ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100'}`}>Сзади</button>
        </div>
      )}
    </div>
  );
};

export const OrderForm: React.FC<OrderFormProps> = ({ productType, initialSubtype, onAddToCart, onCancel }) => {
  const [formData, setFormData] = useState<Partial<OrderItem>>({
    quantity: 1,
    color: COLORS[0].name,
    printPlaces: [],
    images: [],
    printImages: {},
    players: [],
    gender: 'Мальчик',
    size: 'M',
    sleeve: 'Короткий',
    fabric: FABRICS[0],
    wishes: ''
  });

  const [multiColorSelections, setMultiColorSelections] = useState<Record<string, number>>({});
  const [multiSizeSelections, setMultiSizeSelections] = useState<Record<string, number>>({});
  const [tips, setTips] = useState<string | null>(null);
  const [schoolSearch, setSchoolSearch] = useState('');
  const fileInputRefs = useRef<Record<string, HTMLInputElement | null>>({});

  const isMultiColorMode = initialSubtype === OrderSubtype.SCHOOL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isMultiSizeMode = initialSubtype === OrderSubtype.PERSONAL && (productType === ProductType.TSHIRT || productType === ProductType.HOODIE);
  const isTeamMode = initialSubtype === OrderSubtype.TEAM;

  // Fix: Calculate total quantity for multi-size mode to resolve compilation errors.
  const totalMultiSizeQty = Object.values(multiSizeSelections).reduce((acc, qty) => acc + qty, 0);

  useEffect(() => {
    let defaultPrintPlaces: string[] = [];
    if (initialSubtype === OrderSubtype.SCHOOL) defaultPrintPlaces = ['Спереди'];

    if (productType === ProductType.CAP) {
        setFormData(prev => ({ ...prev, capType: CapType.BASEBALL, printPlaces: ['Спереди'] }));
    } else if (productType === ProductType.HOODIE) {
        setFormData(prev => ({ ...prev, hoodieType: HoodieType.KANGAROO, printPlaces: defaultPrintPlaces, sleeve: 'Длинный', gender: 'Универсальный' }));
    } else if (productType === ProductType.TANK_TOP) {
        setFormData(prev => ({ ...prev, sleeve: 'Без рукавов', printPlaces: defaultPrintPlaces }));
    } else if (initialSubtype === OrderSubtype.PERSONAL && productType === ProductType.TSHIRT) {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий', gender: 'Универсальный' }));
    } else {
        setFormData(prev => ({ ...prev, printPlaces: defaultPrintPlaces, sleeve: 'Короткий' }));
    }
    getDesignFeedback(productType, initialSubtype).then(res => setTips(res || null));
  }, [productType, initialSubtype]);

  const togglePrintPlace = (place: string) => {
    setFormData(prev => {
      const isRemoving = prev.printPlaces?.includes(place);
      const newPlaces = isRemoving ? prev.printPlaces?.filter(p => p !== place) : [...(prev.printPlaces || []), place];
      const newPrintImages = { ...prev.printImages };
      if (isRemoving) delete newPrintImages[place];
      return { ...prev, printPlaces: newPlaces, printImages: newPrintImages };
    });
  };

  const handleFileUpload = (place: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      setFormData(prev => ({
        ...prev,
        printPlaces: prev.printPlaces?.includes(place) ? prev.printPlaces : [...(prev.printPlaces || []), place],
        printImages: { ...(prev.printImages || {}), [place]: base64 }
      }));
    };
    reader.readAsDataURL(file);
  };

  const removePrintImage = (place: string) => {
    setFormData(prev => {
      const newImages = { ...prev.printImages };
      delete newImages[place];
      return {
        ...prev,
        printPlaces: prev.printPlaces?.filter(p => p !== place),
        printImages: newImages
      };
    });
  };

  const updateMultiSizeQty = (sizeName: string, delta: number) => {
    setMultiSizeSelections(prev => {
      const current = prev[sizeName] || 0;
      const next = Math.max(0, current + delta);
      const updated = { ...prev };
      if (next === 0) delete updated[sizeName];
      else updated[sizeName] = next;
      return updated;
    });
  };

  const handleAdd = () => {
    const allImages = Object.values(formData.printImages || {});
    if (isMultiColorMode) {
      const colors = Object.keys(multiColorSelections);
      if (colors.length === 0) return;
      const items = colors.map(colorName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, color: colorName,
        quantity: multiColorSelections[colorName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else if (isMultiSizeMode) {
      const sizes = Object.keys(multiSizeSelections);
      if (sizes.length === 0) return;
      const items = sizes.map(sizeName => ({
        ...formData, id: Math.random().toString(36).substr(2, 9),
        type: productType, subtype: initialSubtype, size: sizeName,
        quantity: multiSizeSelections[sizeName], images: allImages
      } as OrderItem));
      onAddToCart(items);
    } else {
      onAddToCart({ ...formData, id: Math.random().toString(36).substr(2, 9), type: productType, subtype: initialSubtype, images: allImages } as OrderItem);
    }
  };

  // Определяем доступные зоны печати для Личного дизайна
  const getAvailablePrintZones = () => {
    if (productType === ProductType.CAP) return ['Спереди'];
    if (productType === ProductType.TANK_TOP) return ['Спереди', 'Сзади'];
    return PRINT_PLACES;
  };

  return (
    <div className="bg-white rounded-[40px] p-10 shadow-2xl max-w-3xl mx-auto border border-gray-50">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight uppercase">{initialSubtype}</h2>
          <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">
            {productType === ProductType.TSHIRT ? 'Футболка' : productType === ProductType.HOODIE ? 'Худи' : productType === ProductType.CAP ? 'Шапка' : 'Майка'}
          </p>
        </div>
        <button onClick={onCancel} className="w-10 h-10 flex items-center justify-center bg-gray-50 rounded-full text-gray-400 hover:text-gray-900 transition-colors">✕</button>
      </div>

      <div className="space-y-10">
        {tips && (
          <div className="bg-indigo-50 border border-indigo-100 rounded-3xl p-6">
             <div className="flex items-center gap-2 mb-3">
               <span className="text-lg">✨</span>
               <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em]">Советы по дизайну</h4>
             </div>
             <div className="text-xs text-indigo-900/80 leading-relaxed font-medium space-y-1">
               {tips.split('\n').map((line, i) => <p key={i}>{line.trim()}</p>)}
             </div>
          </div>
        )}

        {/* МОДЕЛЬ ИЗДЕЛИЯ */}
        {(productType === ProductType.HOODIE || productType === ProductType.CAP) && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Модель {productType === ProductType.CAP ? 'кепки' : 'худи'}</label>
            <div className="flex flex-wrap gap-2">
              {productType === ProductType.HOODIE ? 
                [HoodieType.KANGAROO, HoodieType.ZIP, HoodieType.SWEATER].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, hoodieType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.hoodieType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === HoodieType.KANGAROO ? 'Кенгуру' : t === HoodieType.ZIP ? 'На молнии' : 'Свитшот'}</button>
                )) :
                [CapType.BASEBALL, CapType.SNAPBACK, CapType.BEANIE].map(t => (
                  <button key={t} onClick={() => setFormData({ ...formData, capType: t })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.capType === t ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{t === CapType.BASEBALL ? 'Бейсболка' : t === CapType.SNAPBACK ? 'Снэпбек' : 'Бини'}</button>
                ))
              }
            </div>
          </div>
        )}

        {/* ВЫБОР ТКАНИ (ТОЛЬКО ДЛЯ КОМАНДНЫХ ФУТБОЛОК) */}
        {isTeamMode && productType === ProductType.TSHIRT && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выбор ткани</label>
            <div className="flex gap-3">
              {FABRICS.map(f => (
                <button
                  key={f}
                  onClick={() => setFormData({ ...formData, fabric: f })}
                  className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${
                    formData.fabric === f 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' 
                      : 'border-gray-50 bg-gray-50 text-gray-300'
                  }`}
                >
                  {f}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* ЛИЧНЫЙ ДИЗАЙН: ЗОНЫ ПЕЧАТИ (БЕЗ МАКЕТА) */}
        {initialSubtype === OrderSubtype.PERSONAL ? (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Загрузите макеты для зон печати</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {getAvailablePrintZones().map(place => {
                const hasImage = !!formData.printImages?.[place];
                return (
                  <div key={place} className={`bg-gray-50 p-5 rounded-[32px] border-2 transition-all group flex flex-col items-center text-center ${hasImage ? 'border-indigo-500 bg-indigo-50 shadow-lg' : 'border-gray-100 hover:border-indigo-200'}`}>
                    <div className="w-full flex justify-between items-start mb-4">
                       <span className={`text-[10px] font-black uppercase tracking-widest ${hasImage ? 'text-indigo-600' : 'text-gray-400'}`}>{place}</span>
                       {hasImage && <button onClick={() => removePrintImage(place)} className="text-red-400 hover:text-red-600 text-xs font-bold uppercase tracking-widest">Удалить</button>}
                    </div>

                    <div className="w-24 h-24 mb-6 bg-white rounded-[24px] shadow-inner border border-gray-100 flex items-center justify-center overflow-hidden relative group-hover:scale-105 transition-transform">
                       {hasImage ? (
                         <img src={formData.printImages?.[place]} alt={place} className="w-full h-full object-cover" />
                       ) : (
                         <span className="text-3xl opacity-30">🖼️</span>
                       )}
                    </div>

                    <input type="file" accept="image/*" className="hidden" ref={el => { fileInputRefs.current[place] = el; }} onChange={(e) => handleFileUpload(place, e)} />
                    <button 
                      onClick={() => fileInputRefs.current[place]?.click()}
                      className={`w-full py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${hasImage ? 'bg-white text-indigo-600 border border-indigo-100' : 'bg-indigo-600 text-white shadow-md'}`}
                    >
                      {hasImage ? 'Заменить файл' : 'Загрузить макет'}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        ) : initialSubtype === OrderSubtype.SCHOOL && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Выберите школу</label>
            <div className="mb-6">
              <input type="text" placeholder="Поиск по названию школы..." className="w-full h-14 px-6 bg-gray-50 border border-transparent rounded-2xl outline-none focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium" value={schoolSearch} onChange={(e) => setSchoolSearch(e.target.value)} />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
              {SCHOOL_LIST.filter(s => s.name.toLowerCase().includes(schoolSearch.toLowerCase())).map(school => (
                <div key={school.id} onClick={() => setFormData({ ...formData, school: school.name })} className={`cursor-pointer group flex flex-col items-center p-4 rounded-[28px] border-2 transition-all ${formData.school === school.name ? 'border-indigo-500 bg-indigo-50 shadow-lg scale-[1.02]' : 'border-gray-50 bg-gray-50 hover:border-indigo-200'}`}>
                  <div className="w-16 h-16 mb-3 bg-white rounded-2xl p-2 shadow-sm flex items-center justify-center overflow-hidden"><img src={school.logo} alt={school.name} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform" /></div>
                  <span className={`text-[10px] text-center font-black uppercase tracking-tighter leading-tight ${formData.school === school.name ? 'text-indigo-700' : 'text-gray-400'}`}>{school.name}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ДЛЯ КОГО (СКРЫВАЕМ ДЛЯ ЛИЧНОГО ДИЗАЙНА) */}
        {productType !== ProductType.CAP && 
         productType !== ProductType.TANK_TOP && 
         productType !== ProductType.HOODIE && 
         !isTeamMode && 
         initialSubtype !== OrderSubtype.PERSONAL && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Для кого</label>
            <div className="flex gap-3">
              {['Мальчик', 'Девочка'].map(g => (
                <button key={g} onClick={() => setFormData({ ...formData, gender: g as any })} className={`flex-1 h-14 rounded-2xl font-black text-[12px] uppercase border-2 transition-all ${formData.gender === g ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300'}`}>{g === 'Мальчик' ? 'Мальчики' : 'Девочки'}</button>
              ))}
            </div>
          </div>
        )}

        {/* ДЛИНА РУКАВА */}
        {productType === ProductType.TSHIRT && !isTeamMode && (
          <div className="animate-in slide-in-from-left-4 duration-400">
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Длина рукава</label>
            <div className="flex flex-wrap gap-2">
              {(initialSubtype === OrderSubtype.PERSONAL 
                ? SLEEVES.BOY 
                : (formData.gender === 'Девочка' ? SLEEVES.GIRL : SLEEVES.BOY)
              ).map(s => (
                <button key={s} onClick={() => setFormData({ ...formData, sleeve: s })} className={`px-6 h-12 rounded-2xl font-black text-[11px] uppercase border-2 transition-all ${formData.sleeve === s ? 'border-indigo-600 bg-indigo-50 text-indigo-700 shadow-sm' : 'border-gray-50 bg-gray-50 text-gray-300 hover:border-gray-200'}`}>{s}</button>
              ))}
            </div>
          </div>
        )}

        {/* РАЗМЕРЫ */}
        {!isTeamMode && (
          <div>
            <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Размеры</label>
            <div className="flex flex-wrap gap-2">
              {(isMultiSizeMode ? [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS] : (initialSubtype === OrderSubtype.SCHOOL ? [...SCHOOL_SIZES_KIDS, ...SCHOOL_SIZES_ADULTS] : [...PERSONAL_SIZES_KIDS, ...PERSONAL_SIZES_ADULTS])).map(size => {
                const isSelected = isMultiSizeMode ? (multiSizeSelections[size] || 0) > 0 : formData.size === size;
                return (
                  <button key={size} onClick={() => isMultiSizeMode ? updateMultiSizeQty(size, 1) : setFormData({ ...formData, size })} onContextMenu={(e) => { e.preventDefault(); if(isMultiSizeMode) updateMultiSizeQty(size, -1); }} className={`min-w-[54px] h-[54px] rounded-2xl font-bold text-sm transition-all flex flex-col items-center justify-center relative ${isSelected ? 'bg-indigo-600 text-white shadow-lg scale-105' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}>
                    {size}
                    {isMultiSizeMode && (multiSizeSelections[size] || 0) > 0 && <span className="absolute -top-2 -right-2 bg-indigo-200 text-indigo-900 text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">{multiSizeSelections[size]}</span>}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* ЦВЕТ ИЗДЕЛИЯ */}
        <div>
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Цвет изделия {isMultiColorMode ? '(выберите несколько)' : ''}</label>
          <div className="grid grid-cols-5 gap-3">
            {COLORS.map(c => {
              const isSelected = isMultiColorMode ? !!multiColorSelections[c.name] : formData.color === c.name;
              return (
                <button key={c.hex} onClick={() => isMultiColorMode ? setMultiColorSelections(p => ({...p, [c.name]: p[c.name] ? p[c.name] : 1})) : setFormData({ ...formData, color: c.name })} className={`aspect-square rounded-[24px] transition-all relative flex items-center justify-center ${isSelected ? 'ring-4 ring-indigo-500 ring-offset-4 scale-[1.05]' : 'hover:scale-[1.02]'}`} style={{ backgroundColor: c.hex, border: c.hex === '#FFFFFF' ? '1px solid #e5e7eb' : 'none' }}>
                  {isSelected && <div className={`w-8 h-8 rounded-full flex items-center justify-center ${c.hex === '#FFFFFF' ? 'bg-indigo-600' : 'bg-white'}`}>{isMultiColorMode ? <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-xs`}>{multiColorSelections[c.name]}</span> : <span className={`${c.hex === '#FFFFFF' ? 'text-white' : 'text-gray-900'} font-black text-lg`}>✓</span>}</div>}
                </button>
              );
            })}
          </div>
          {isMultiColorMode && Object.keys(multiColorSelections).length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-6">
               {Object.entries(multiColorSelections).map(([cName, qty]) => (
                 <div key={cName} className="flex items-center justify-between bg-gray-50/50 p-4 rounded-[24px] border border-gray-100 shadow-sm">
                    <span className="text-[13px] font-black text-gray-700 uppercase">{cName}</span>
                    <div className="flex items-center bg-white/80 rounded-xl p-1 gap-4">
                       <button onClick={() => setMultiColorSelections(p => { const n = {...p}; if(qty <= 1) delete n[cName]; else n[cName] = qty-1; return n; })} className="w-8 h-8 flex items-center justify-center font-bold text-lg">−</button>
                       <span className="text-sm font-black">{qty}</span>
                       <button onClick={() => setMultiColorSelections(p => ({...p, [cName]: qty+1}))} className="w-8 h-8 flex items-center justify-center font-bold text-lg">+</button>
                    </div>
                 </div>
               ))}
            </div>
          )}
        </div>

        {isTeamMode && <PlayerTable players={formData.players || []} onChange={(players) => setFormData({ ...formData, players })} productType={productType} />}

        {/* ПОЖЕЛАНИЯ ЗАКАЗЧИКА */}
        <div className="animate-in slide-in-from-bottom-4 duration-400">
          <label className="block text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4">Ваши пожелания к этому изделию</label>
          <textarea 
            value={formData.wishes}
            onChange={(e) => setFormData({ ...formData, wishes: e.target.value })}
            placeholder="Напишите здесь любые детали или уточнения по заказу этого товара..."
            className="w-full h-32 p-6 bg-gray-50 border border-gray-100 rounded-[32px] outline-none focus:bg-white focus:border-indigo-400 transition-all text-sm font-medium resize-none shadow-inner"
          />
        </div>
      </div>

      <div className="mt-14 flex flex-col items-center">
        {(isMultiSizeMode || isMultiColorMode) && <p className="mb-6 text-sm font-black text-gray-400 uppercase tracking-widest">Итого: <span className="text-indigo-600 font-black text-lg">{isMultiSizeMode ? totalMultiSizeQty : Object.values(multiColorSelections).reduce((a, b) => a + b, 0)} шт.</span></p>}
        <Button onClick={handleAdd} variant="primary" size="lg" fullWidth className="h-16 rounded-3xl font-black text-[14px] uppercase tracking-[0.1em] shadow-xl hover:shadow-indigo-200" disabled={(initialSubtype === OrderSubtype.SCHOOL && !formData.school) || (isMultiSizeMode && totalMultiSizeQty === 0) || (isMultiColorMode && Object.keys(multiColorSelections).length === 0) || (isTeamMode && !formData.players?.length) || (initialSubtype === OrderSubtype.PERSONAL && formData.printPlaces?.length === 0)}>
          {formData.id ? 'Обновить данные' : 'Добавить в корзину'}
        </Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, ProductType, OrderSubtype } from '../types';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  // Bulk selection state
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const data = await apiService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error("Dashboard fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const updated = await apiService.updateOrder(orderNumber, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return updated;
    } catch (error) {
      console.error("Dashboard update error:", error);
      throw error;
    }
  };

  const handleBulkStatusUpdate = async (newStatus: OrderStatus) => {
    if (selectedOrderIds.size === 0) return;
    setIsBulkUpdating(true);

    try {
      const promises = Array.from(selectedOrderIds).map(id => 
        apiService.updateOrder(id, { status: newStatus, viewed: true })
      );

      await Promise.all(promises);

      setOrders(prev => prev.map(o => 
        selectedOrderIds.has(o.orderNumber) ? { ...o, status: newStatus, viewed: true } : o
      ));

      setSelectedOrderIds(new Set());
      alert(`Обновлено заказов: ${selectedOrderIds.size}`);
    } catch (error) {
      console.error("Bulk update error:", error);
      alert("Некоторые заказы не удалось обновить.");
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const toggleOrderSelection = (id: string, event?: React.MouseEvent) => {
    if (event) event.stopPropagation();
    setSelectedOrderIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const handleSelectAll = (visibleOrders: Order[]) => {
    if (selectedOrderIds.size === visibleOrders.length && visibleOrders.length > 0) {
      setSelectedOrderIds(new Set());
    } else {
      setSelectedOrderIds(new Set(visibleOrders.map(o => o.orderNumber)));
    }
  };

  const handleSelectOrder = (order: Order) => {
    setSelectedOrder(order);
    if (!order.viewed) {
      updateOrderData(order.orderNumber, { viewed: true });
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const resetFilters = () => {
    setFilterText('');
    setStatusFilter('all');
    setSelectedOrderIds(new Set());
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getItemIcon = (type: ProductType) => {
    switch(type) {
      case ProductType.TSHIRT: return '👕';
      case ProductType.HOODIE: return '🧥';
      case ProductType.CAP: return '🧢';
      case ProductType.TANK_TOP: return '🎽';
      default: return '📦';
    }
  };

  const getStatusCount = (status: OrderStatus) => orders.filter(o => o.status === status).length;
  const getUnreadCount = (status: OrderStatus) => orders.filter(o => o.status === status && !o.viewed).length;

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500 relative">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <Button onClick={fetchOrders} variant="outline" size="sm" className="w-full md:w-auto">
          🔄 Обновить данные
        </Button>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
        {(Object.keys(STATUS_LABELS) as OrderStatus[]).map((status) => {
          const unread = getUnreadCount(status);
          return (
            <div 
              key={status} 
              onClick={() => setStatusFilter(status)}
              className={`p-5 rounded-2xl cursor-pointer transition-all border-2 relative overflow-hidden ${
                statusFilter === status 
                  ? 'bg-indigo-50 border-indigo-500 shadow-md scale-[1.02]' 
                  : 'bg-white border-gray-100 hover:border-indigo-200'
              }`}
            >
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{STATUS_LABELS[status]}</p>
              <div className="flex items-center justify-between">
                <span className="text-3xl font-black text-gray-800">{getStatusCount(status)}</span>
                <span className={`w-3 h-3 rounded-full ${getStatusColor(status).split(' ')[0]}`}></span>
              </div>
              {unread > 0 && (
                <div className="absolute top-2 right-2 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse"></span>
                  <span className="text-[9px] font-bold text-indigo-600 uppercase">{unread} нов.</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-4 mb-6 bg-gray-50 p-6 rounded-2xl border border-gray-100">
        <div className="flex-1 w-full">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Поиск</label>
          <input 
            type="text" 
            placeholder="Имя, ID или заметки..."
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
        <div className="w-full md:w-64">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Фильтр по статусу</label>
          <select 
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none cursor-pointer text-sm shadow-sm font-medium"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>
        {(statusFilter !== 'all' || filterText) && (
          <button 
            onClick={resetFilters}
            className="text-xs font-bold text-indigo-600 hover:text-indigo-800 px-2 py-3 transition-colors"
          >
            Очистить
          </button>
        )}
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация данных...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-4 text-left">
                  <input 
                    type="checkbox" 
                    className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                    checked={filteredOrders.length > 0 && selectedOrderIds.size === filteredOrders.length}
                    onChange={() => handleSelectAll(filteredOrders)}
                  />
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Действия</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredOrders.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-gray-400 italic">Заказы не найдены</td>
                </tr>
              ) : (
                filteredOrders.map((order) => (
                  <tr 
                    key={order.orderNumber} 
                    className={`transition-colors group cursor-pointer ${selectedOrderIds.has(order.orderNumber) ? 'bg-indigo-50' : 'hover:bg-indigo-50/50'}`}
                    onClick={() => handleSelectOrder(order)}
                  >
                    <td className="px-4 py-4 whitespace-nowrap" onClick={(e) => e.stopPropagation()}>
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                        checked={selectedOrderIds.has(order.orderNumber)}
                        onChange={() => toggleOrderSelection(order.orderNumber)}
                      />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {new Date(order.createdAt).toLocaleDateString()}
                      <div className="text-[10px] text-gray-400">{new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        {!order.viewed && (
                          <span className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse shadow-sm shadow-indigo-200" title="Не просмотрено"></span>
                        )}
                        <span className="font-mono text-[10px] font-bold text-indigo-500">
                          {order.orderNumber.split('-')[1]}
                        </span>
                        {order.internalNotes && (
                          <span className="inline-block w-2 h-2 rounded-full bg-amber-400 shadow-sm" title="Есть внутренняя заметка"></span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-800">{order.customer.name}</div>
                      <div className="text-[10px] text-gray-400">{order.customer.phone}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex -space-x-2">
                        {order.items.slice(0, 3).map((item, idx) => (
                          <div key={idx} className="w-8 h-8 rounded-full bg-white border-2 border-gray-100 flex items-center justify-center text-sm shadow-sm" title={item.type}>
                            {getItemIcon(item.type)}
                          </div>
                        ))}
                        {order.items.length > 3 && (
                          <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-[10px] font-bold text-gray-500">
                            +{order.items.length - 3}
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <select 
                        className={`text-xs font-bold rounded-full px-3 py-1 outline-none appearance-none cursor-pointer border-none shadow-sm ${getStatusColor(order.status)}`}
                        value={order.status}
                        onClick={(e) => e.stopPropagation()} 
                        onChange={(e) => updateOrderData(order.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                      >
                        {Object.entries(STATUS_LABELS).map(([key, label]) => (
                          <option key={key} value={key}>{label}</option>
                        ))}
                      </select>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-lg">
                      👁️
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* Floating Bulk Actions Bar */}
      {selectedOrderIds.size > 0 && (
        <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 bg-gray-900 text-white rounded-2xl px-6 py-4 shadow-2xl flex items-center gap-6 z-[60] animate-in slide-in-from-bottom-4 duration-300 border border-gray-700">
          <div className="flex items-center gap-3 pr-6 border-r border-gray-700">
            <span className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center font-bold text-sm">
              {selectedOrderIds.size}
            </span>
            <span className="text-sm font-medium text-gray-300">выбрано</span>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => handleBulkStatusUpdate('Processing')}
              disabled={isBulkUpdating}
              className="px-4 py-2 bg-yellow-500 hover:bg-yellow-600 text-black text-xs font-bold rounded-xl transition-colors disabled:opacity-50"
            >
              В работу
            </button>
            <button 
              onClick={() => handleBulkStatusUpdate('Completed')}
              disabled={isBulkUpdating}
              className="px-4 py-2 bg-green-500 hover:bg-green-600 text-white text-xs font-bold rounded-xl transition-colors disabled:opacity-50"
            >
              Завершить
            </button>
            <button 
              onClick={() => handleBulkStatusUpdate('Cancelled')}
              disabled={isBulkUpdating}
              className="px-4 py-2 bg-red-500 hover:bg-red-600 text-white text-xs font-bold rounded-xl transition-colors disabled:opacity-50"
            >
              Отменить
            </button>
          </div>

          <button 
            onClick={() => setSelectedOrderIds(new Set())}
            className="text-gray-400 hover:text-white transition-colors"
            title="Отменить выбор"
          >
            ✕
          </button>
        </div>
      )}

      {selectedOrder && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <div>
                <h3 className="text-xl font-bold text-gray-800">Детали заказа {selectedOrder.orderNumber}</h3>
                <p className="text-sm text-gray-500">{new Date(selectedOrder.createdAt).toLocaleString()}</p>
              </div>
              <button onClick={() => setSelectedOrder(null)} className="text-gray-400 hover:text-gray-600 text-2xl transition-colors">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
              <div className="grid md:grid-cols-2 gap-6 bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Клиент</h4>
                  <p className="font-bold text-gray-800 text-lg">{selectedOrder.customer.name}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">✉️ {selectedOrder.customer.email}</p>
                  <p className="text-sm text-gray-600 flex items-center gap-1">📞 {selectedOrder.customer.phone}</p>
                </div>
                <div>
                  <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">Доставка и примечания</h4>
                  <p className="text-sm text-gray-700"><strong>Адрес:</strong> {selectedOrder.customer.address || 'Не указан'}</p>
                  <p className="text-sm text-gray-700 mt-1"><strong>От клиента:</strong> {selectedOrder.customer.comments || 'Нет'}</p>
                </div>
              </div>

              <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-600 uppercase tracking-wider mb-2">📝 Внутренние заметки</h4>
                <textarea 
                  className="w-full p-4 bg-white border border-amber-200 rounded-xl outline-none focus:ring-2 ring-amber-400 text-sm h-24 resize-none shadow-inner"
                  value={editingNotes}
                  onChange={(e) => setEditingNotes(e.target.value)}
                  placeholder="Добавьте рабочую заметку..."
                />
                <div className="mt-2 flex justify-end">
                   <Button 
                    size="sm" 
                    variant="primary" 
                    className="bg-amber-600 hover:bg-amber-700 shadow-sm" 
                    onClick={handleSaveNotes}
                    disabled={isSavingNotes || editingNotes === (selectedOrder.internalNotes || '')}
                  >
                    {isSavingNotes ? 'Сохранение...' : 'Сохранить заметку'}
                  </Button>
                </div>
              </div>

              <div className="space-y-6">
                <h4 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                  📦 Состав заказа <span className="text-sm font-normal text-gray-400">({selectedOrder.items.length} поз.)</span>
                </h4>
                {selectedOrder.items.map((item, idx) => {
                  const isTeamItem = item.subtype === OrderSubtype.TEAM;
                  // Ensure players is an array even if missing in old data
                  const playersList = Array.isArray(item.players) ? item.players : [];

                  return (
                    <div key={idx} className="border border-gray-100 rounded-2xl p-6 hover:border-indigo-200 transition-all bg-white shadow-sm">
                      <div className="flex flex-col md:flex-row gap-6">
                        <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center text-3xl shrink-0">
                          {getItemIcon(item.type)}
                        </div>
                        <div className="flex-1">
                          <div className="flex justify-between items-start mb-4">
                            <div>
                              <h5 className="text-lg font-bold text-gray-800 leading-tight">
                                {item.type === ProductType.TSHIRT ? 'Футболка' : item.type === ProductType.HOODIE ? 'Худи' : item.type === ProductType.CAP ? 'Шапка' : 'Майка'} 
                                <span className="text-indigo-600 ml-1">[{item.subtype}]</span>
                              </h5>
                              <div className="flex flex-wrap gap-2 mt-2">
                                <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">{item.color}</span>
                                {item.fabric && <span className="px-2 py-1 bg-amber-100 rounded-md text-[10px] font-bold text-amber-700 uppercase">Ткань: {item.fabric}</span>}
                                {!isTeamItem && <span className="px-2 py-1 bg-gray-100 rounded-md text-[10px] font-bold text-gray-600 uppercase">Размер: {item.size}</span>}
                                <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${isTeamItem ? 'bg-purple-100 text-purple-700' : 'bg-indigo-100 text-indigo-700'}`}>
                                  {isTeamItem ? `Состав: ${playersList.length || item.quantity} чел.` : `Кол-во: ${item.quantity} шт.`}
                                </span>
                              </div>
                            </div>
                          </div>

                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 text-sm bg-gray-50/50 p-4 rounded-xl border border-gray-100 mb-4">
                            {item.school && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Школа</p><p className="text-gray-800 font-medium">{item.school}</p></div>)}
                            {item.gender && !isTeamItem && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Пол</p><p className="text-gray-800 font-medium">{item.gender}</p></div>)}
                            {item.sleeve && !isTeamItem && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Рукав</p><p className="text-gray-800 font-medium">{item.sleeve}</p></div>)}
                            {item.hoodieType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Тип худи</p><p className="text-gray-800 font-medium">{item.hoodieType}</p></div>)}
                            {item.capType && (<div><p className="text-gray-400 text-xs font-bold uppercase mb-1">Модель шапки</p><p className="text-gray-800 font-medium">{item.capType}</p></div>)}
                            {item.printPlaces && item.printPlaces.length > 0 && (
                               <div className="sm:col-span-2">
                                 <p className="text-gray-400 text-xs font-bold uppercase mb-1">Места печати</p>
                                 <div className="flex flex-wrap gap-1">{item.printPlaces.map(p => (<span key={p} className="bg-white px-2 py-0.5 rounded border border-gray-200 text-xs text-gray-700 font-medium">{p}</span>))}</div>
                               </div>
                            )}
                          </div>

                          {/* Item-specific Wishes */}
                          {item.wishes && (
                            <div className="mb-4 bg-indigo-50/30 p-4 rounded-xl border border-indigo-100">
                              <p className="text-indigo-600 text-[10px] font-black uppercase mb-1 tracking-widest flex items-center gap-2">
                                <span>💬 Пожелания к товару</span>
                              </p>
                              <p className="text-xs text-gray-700 whitespace-pre-wrap">{item.wishes}</p>
                            </div>
                          )}

                          {/* Player Roster - Enhanced Rendering */}
                          {isTeamItem && (
                            <div className="mt-6 border-t pt-4 animate-in slide-in-from-top-2 duration-300">
                              <p className="text-indigo-600 text-[10px] font-black uppercase mb-3 tracking-widest flex items-center gap-2">
                                <span>📋 СПИСОК КОМАНДЫ ДЛЯ ПЕЧАТИ</span>
                                <span className="bg-indigo-600 text-white px-2 py-0.5 rounded-full text-[9px]">{playersList.length} ИГРОКОВ</span>
                              </p>

                              {playersList.length > 0 ? (
                                <div className="overflow-hidden border border-indigo-100 rounded-xl shadow-sm">
                                  <table className="min-w-full divide-y divide-indigo-50">
                                    <thead className="bg-indigo-50/50">
                                      <tr className="text-left text-[9px] font-black text-indigo-400 uppercase">
                                        <th className="px-3 py-2">Имя</th>
                                        <th className="px-3 py-2 text-center">Номер</th>
                                        <th className="px-3 py-2">Пол</th>
                                        <th className="px-3 py-2 text-center">Размер</th>
                                        <th className="px-3 py-2">Рукав</th>
                                      </tr>
                                    </thead>
                                    <tbody className="bg-white divide-y divide-gray-50 text-[11px]">
                                      {playersList.map((player, pIdx) => (
                                        <tr key={player.id || pIdx} className="hover:bg-indigo-50/20 transition-colors">
                                          <td className="px-3 py-2 font-bold text-gray-800">{player.name || '—'}</td>
                                          <td className="px-3 py-2 text-center text-indigo-600 font-black">{player.number || '—'}</td>
                                          <td className="px-3 py-2 text-gray-500">{player.gender}</td>
                                          <td className="px-3 py-2 text-center font-black bg-indigo-50/30 text-indigo-700">{player.size}</td>
                                          <td className="px-3 py-2 text-gray-400">{player.sleeve}</td>
                                        </tr>
                                      ))}
                                    </tbody>
                                  </table>
                                </div>
                              ) : (
                                <div className="p-6 bg-red-50 rounded-xl border border-red-100 flex flex-col items-center gap-2 text-center">
                                  <span className="text-2xl">⚠️</span>
                                  <p className="text-red-600 font-bold text-sm">Данные об игроках отсутствуют!</p>
                                  <p className="text-red-400 text-xs">Проверьте корректность заполнения формы или целостность базы данных.</p>
                                </div>
                              )}
                            </div>
                          )}

                          {item.images && item.images.length > 0 && (
                            <div className="mt-4">
                               <p className="text-gray-400 text-[10px] font-black uppercase mb-2 tracking-widest">Файлы макетов ({item.images.length})</p>
                               <div className="flex flex-wrap gap-2">{item.images.map((img, i) => (<a key={i} href={img} target="_blank" rel="noreferrer" className="block w-20 h-20 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 hover:border-indigo-400 transition-all shadow-sm"><img src={img} alt="layout" className="w-full h-full object-cover" /></a>))}</div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
            <div className="p-6 border-t border-gray-100 flex justify-between items-center bg-gray-50">
              <div className="flex gap-2">
                <Button onClick={() => setSelectedOrder(null)} variant="outline">Закрыть</Button>
                <Button onClick={() => window.print()} variant="outline" className="hidden sm:inline-flex">🖨️ Печать</Button>
              </div>
              <div className="flex items-center gap-3">
                <span className="text-xs font-bold text-gray-400 uppercase">Статус:</span>
                <select 
                  className={`text-sm font-bold rounded-xl px-4 py-2 outline-none border border-gray-200 shadow-sm transition-all focus:ring-2 ring-indigo-500 ${getStatusColor(selectedOrder.status)}`}
                  value={selectedOrder.status}
                  onChange={(e) => updateOrderData(selectedOrder.orderNumber, { status: e.target.value as OrderStatus, viewed: true })}
                >
                  {Object.entries(STATUS_LABELS).map(([key, label]) => (<option key={key} value={key}>{label}</option>))}
                </select>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Fix: Explicitly import Buffer to resolve 'Cannot find name Buffer' TypeScript error.
import { Buffer } from 'buffer';
import PDFDocument from 'pdfkit';
import { Order, OrderSubtype } from '../types';

export async function generateOrderPDF(order: Order): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    const doc = new PDFDocument({ margin: 50 });
    const chunks: Buffer[] = [];

    doc.on('data', (chunk) => chunks.push(chunk));
    doc.on('end', () => resolve(Buffer.concat(chunks)));
    doc.on('error', (err) => reject(err));

    // Header
    doc.fontSize(20).text('ЗАКАЗ - ' + order.orderNumber, { align: 'center' });
    doc.moveDown();

    // Status
    doc.fontSize(12).text(`Статус: ${order.status}`, { align: 'right' });
    doc.moveDown();

    // Customer Info
    doc.fontSize(14).text('Контактные данные клиента:', { underline: true });
    doc.fontSize(12).text(`Имя: ${order.customer.name}`);
    doc.text(`Телефон: ${order.customer.phone}`);
    doc.text(`Email: ${order.customer.email}`);
    if (order.customer.address) doc.text(`Адрес: ${order.customer.address}`);
    if (order.customer.comments) doc.text(`Комментарий: ${order.customer.comments}`);
    doc.moveDown();

    // Order Items
    doc.fontSize(14).text('Позиции заказа:', { underline: true });
    doc.moveDown(0.5);

    order.items.forEach((item, index) => {
      const displayType = item.type === 'TANK_TOP' ? 'Майка' : 
                          item.type === 'TSHIRT' ? 'Футболка' : 
                          item.type === 'HOODIE' ? 'Худи' : 'Шапка';

      doc.fontSize(12).text(`${index + 1}. ${displayType} [${item.subtype}]`, { bold: true });
      doc.fontSize(10);
      doc.text(`Цвет: ${item.color}`);
      if (item.fabric) doc.text(`Ткань: ${item.fabric}`);
      doc.text(`Размер: ${item.size}`);
      doc.text(`Количество: ${item.quantity}`);

      if (item.school) doc.text(`Школа: ${item.school}`);
      if (item.gender && item.subtype !== OrderSubtype.TEAM) doc.text(`Пол: ${item.gender}`);
      if (item.sleeve && item.subtype !== OrderSubtype.TEAM) doc.text(`Рукав: ${item.sleeve}`);
      if (item.hoodieType) doc.text(`Тип худи: ${item.hoodieType}`);
      if (item.capType) doc.text(`Тип шапки: ${item.capType}`);

      if (item.printPlaces && item.printPlaces.length > 0) {
        doc.text(`Места печати: ${item.printPlaces.join(', ')}`);
      }

      // Wishes inclusion
      if (item.wishes) {
        doc.moveDown(0.2);
        doc.fontSize(10).text('Пожелания:', { underline: true });
        doc.fontSize(10).text(item.wishes, { italic: true });
        doc.moveDown(0.2);
      }

      if (item.subtype === OrderSubtype.TEAM && item.players && item.players.length > 0) {
        doc.moveDown(0.2);
        doc.fontSize(11).text('СПИСОК ИГРОКОВ КОМАНДЫ:', { bold: true });
        doc.fontSize(10);
        item.players.forEach((p, pIdx) => {
          doc.text(`  ${pIdx + 1}. ${p.name} — №${p.number} — Разм: ${p.size} — ${p.gender} — Рукав: ${p.sleeve}`);
        });
      }

      doc.moveDown();
    });

    doc.fontSize(10).text(`Дата создания: ${new Date(order.createdAt).toLocaleString()}`, { align: 'right' });

    doc.end();
  });
}

import axios from 'axios';
import { Order, OrderSubtype } from '../types';

const TRELLO_KEY = process.env.TRELLO_KEY;
const TRELLO_TOKEN = process.env.TRELLO_TOKEN;
const TRELLO_LIST_ID = process.env.TRELLO_LIST_ID || 'Egor2_List_ID';

export async function createTrelloCard(order: Order) {
  if (!TRELLO_KEY || !TRELLO_TOKEN) {
    console.warn('Trello API keys missing, skipping card creation');
    return;
  }

  const itemsDetails = order.items.map(item => {
    let detail = `- ${item.quantity}x ${item.type} (${item.subtype}), Цвет: ${item.color}, Размер: ${item.size}`;

    if (item.fabric) detail += `, Ткань: ${item.fabric}`;

    if (item.subtype === OrderSubtype.TEAM && item.players && item.players.length > 0) {
      detail += `\n  **СПИСОК КОМАНДЫ (${item.players.length} чел.):**`;
      item.players.forEach(p => {
        detail += `\n  • ${p.name} | №${p.number} | ${p.size} | ${p.gender} | Рукав: ${p.sleeve}`;
      });
    } else if (item.subtype === OrderSubtype.SCHOOL && item.school) {
      detail += `\n  Школа: ${item.school}`;
    }

    if (item.printPlaces && item.printPlaces.length > 0) {
      detail += `\n  Места печати: ${item.printPlaces.join(', ')}`;
    }

    if (item.wishes) {
      detail += `\n  **ПОЖЕЛАНИЯ:** ${item.wishes}`;
    }

    return detail;
  }).join('\n\n');

  const description = `
**КЛИЕНТ:** ${order.customer.name}
**ТЕЛЕФОН:** ${order.customer.phone}
**EMAIL:** ${order.customer.email}
**АДРЕС:** ${order.customer.address || 'Не указан'}

---
**СОСТАВ ЗАКАЗА:**
${itemsDetails}

---
**КОММЕНТАРИЙ:** ${order.customer.comments || 'Нет'}
**ДАТА:** ${new Date(order.createdAt).toLocaleString()}
  `;

  try {
    await axios.post(`https://api.trello.com/1/cards`, null, {
      params: {
        idList: TRELLO_LIST_ID,
        key: TRELLO_KEY,
        token: TRELLO_TOKEN,
        name: `ЗАКАЗ ${order.orderNumber} - ${order.customer.name}`,
        desc: description,
        pos: 'top'
      }
    });
    console.log('Trello card created successfully');
  } catch (error) {
    console.error('Failed to create Trello card:', error);
  }
}

import axios from 'axios';
import { Order, OrderItem } from '../types';

const API_URL = 'http://localhost:3001/api';
const LOCAL_STORAGE_KEY = 'printmaster_orders_backup';

/**
 * Strips heavy base64 data from order items to prevent localStorage QuotaExceededError.
 * Local backup is primarily for text data; images are handled by the server.
 */
const sanitizeOrderForStorage = (order: Order): Order => {
  return {
    ...order,
    items: order.items.map(item => ({
      ...item,
      images: [], // Remove legacy images array
      printImages: item.printImages ? Object.keys(item.printImages).reduce((acc, key) => {
        acc[key] = "[Image Data Removed for Local Storage]";
        return acc;
      }, {} as Record<string, string>) : {}
    }))
  };
};

export const apiService = {
  /**
   * Simple login method
   */
  login: async (password: string): Promise<boolean> => {
    try {
      const response = await axios.post(`${API_URL}/login`, { password }, { timeout: 2000 });
      return response.data.success === true;
    } catch (error) {
      // Offline fallback: if server is down, allow "admin123" locally for preview purposes
      console.warn("Auth server unreachable. Using local validation for preview.");
      return password === 'admin123';
    }
  },

  getOrders: async (): Promise<Order[]> => {
    let remoteOrders: Order[] = [];
    try {
      const response = await axios.get(`${API_URL}/orders`, { timeout: 2000 });
      remoteOrders = response.data;
    } catch (error) {
      console.warn("Backend unreachable. Operating in Local Mode.");
    }

    const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
    const localOrders: Order[] = localData ? JSON.parse(localData) : [];

    const orderMap = new Map<string, Order>();
    remoteOrders.forEach(o => orderMap.set(o.orderNumber, o));
    localOrders.forEach(o => orderMap.set(o.orderNumber, o));

    return Array.from(orderMap.values()).sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  },

  submitOrder: async (order: Order): Promise<void> => {
    // 1. Attempt to sync with server FIRST with full data
    try {
      await axios.post(`${API_URL}/orders`, order, { timeout: 10000 });
    } catch (error) {
      console.warn("Server sync failed, order will be saved locally (without images).");
    }

    // 2. Save a lightweight version to localStorage to prevent QuotaExceededError
    try {
      const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
      const localOrders: Order[] = localData ? JSON.parse(localData) : [];

      const sanitizedOrder = sanitizeOrderForStorage(order);
      localOrders.push(sanitizedOrder);

      // Keep only last 50 orders in local storage to prevent bloat
      const trimmedOrders = localOrders.slice(-50);
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(trimmedOrders));
    } catch (storageError) {
      console.error("Local storage backup failed entirely:", storageError);
    }
  },

  updateOrder: async (orderNumber: string, data: Partial<Order>): Promise<Order> => {
    const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
    let localOrders: Order[] = localData ? JSON.parse(localData) : [];

    let updatedOrder: Order | null = null;
    localOrders = localOrders.map(o => {
      if (o.orderNumber === orderNumber) {
        updatedOrder = { ...o, ...data };
        return updatedOrder;
      }
      return o;
    });

    if (updatedOrder) {
      try {
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(localOrders));
      } catch (e) {
        console.warn("Failed to update localStorage due to quota.");
      }
    }

    try {
      const response = await axios.patch(`${API_URL}/orders/${orderNumber}`, data, { timeout: 2000 });
      return response.data;
    } catch (error) {
      console.warn("Order updated locally, but server sync failed.");
      if (!updatedOrder) throw new Error("Order not found in local storage.");
      return updatedOrder;
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, ProductType, OrderSubtype, OrderItem } from '../types';
import { Button } from './ui/Button';
import { apiService } from '../services/apiService';

type SortField = 'date' | 'customer' | 'status';

const STATUS_LABELS: Record<OrderStatus, string> = {
  'New': 'Новый',
  'Processing': 'В работе',
  'Completed': 'Завершен',
  'Cancelled': 'Отменен'
};

export const AdminDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterText, setFilterText] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<'desc' | 'asc'>('desc');
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [editingNotes, setEditingNotes] = useState<string>('');
  const [isSavingNotes, setIsSavingNotes] = useState(false);

  // Bulk selection state
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);

  useEffect(() => {
    fetchOrders();
  }, []);

  useEffect(() => {
    if (selectedOrder) {
      setEditingNotes(selectedOrder.internalNotes || '');
    }
  }, [selectedOrder]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const data = await apiService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error("Dashboard fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderData = async (orderNumber: string, data: Partial<Order>) => {
    try {
      const updated = await apiService.updateOrder(orderNumber, data);
      setOrders(prev => prev.map(o => o.orderNumber === orderNumber ? { ...o, ...data } : o));
      if (selectedOrder?.orderNumber === orderNumber) {
        setSelectedOrder({ ...selectedOrder, ...data });
      }
      return updated;
    } catch (error) {
      console.error("Dashboard update error:", error);
      throw error;
    }
  };

  const handleBulkStatusUpdate = async (newStatus: OrderStatus) => {
    if (selectedOrderIds.size === 0) return;
    setIsBulkUpdating(true);

    try {
      const promises = Array.from(selectedOrderIds).map(id => 
        apiService.updateOrder(id, { status: newStatus, viewed: true })
      );

      await Promise.all(promises);

      setOrders(prev => prev.map(o => 
        selectedOrderIds.has(o.orderNumber) ? { ...o, status: newStatus, viewed: true } : o
      ));

      setSelectedOrderIds(new Set());
      alert(`Обновлено заказов: ${selectedOrderIds.size}`);
    } catch (error) {
      console.error("Bulk update error:", error);
      alert("Некоторые заказы не удалось обновить.");
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const toggleOrderSelection = (id: string, event?: React.MouseEvent) => {
    if (event) event.stopPropagation();
    setSelectedOrderIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  const handleSelectAll = (visibleOrders: Order[]) => {
    if (selectedOrderIds.size === visibleOrders.length && visibleOrders.length > 0) {
      setSelectedOrderIds(new Set());
    } else {
      setSelectedOrderIds(new Set(visibleOrders.map(o => o.orderNumber)));
    }
  };

  const handleSelectOrder = (order: Order) => {
    setSelectedOrder(order);
    if (!order.viewed) {
      updateOrderData(order.orderNumber, { viewed: true });
    }
  };

  const handleSaveNotes = async () => {
    if (!selectedOrder) return;
    setIsSavingNotes(true);
    try {
      await updateOrderData(selectedOrder.orderNumber, { internalNotes: editingNotes });
    } finally {
      setIsSavingNotes(false);
    }
  };

  const handleSort = (field: SortField) => {
    if (sortField === field) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortField(field);
      setSortOrder('desc');
    }
  };

  const resetFilters = () => {
    setFilterText('');
    setStatusFilter('all');
    setSelectedOrderIds(new Set());
  };

  const downloadImage = (base64: string, filename: string) => {
    const link = document.createElement('a');
    link.href = base64;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const filteredOrders = orders
    .filter(order => {
      const matchesText = 
        order.customer.name.toLowerCase().includes(filterText.toLowerCase()) ||
        order.orderNumber.toLowerCase().includes(filterText.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(filterText.toLowerCase()) ||
        (order.internalNotes && order.internalNotes.toLowerCase().includes(filterText.toLowerCase()));
      const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
      return matchesText && matchesStatus;
    })
    .sort((a, b) => {
      let comparison = 0;
      if (sortField === 'date') {
        comparison = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      } else if (sortField === 'customer') {
        comparison = a.customer.name.localeCompare(b.customer.name);
      } else if (sortField === 'status') {
        comparison = a.status.localeCompare(b.status);
      }
      return sortOrder === 'desc' ? -comparison : comparison;
    });

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Processing': return 'bg-yellow-100 text-yellow-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Cancelled': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const getItemIcon = (type: ProductType) => {
    switch(type) {
      case ProductType.TSHIRT: return '👕';
      case ProductType.HOODIE: return '🧥';
      case ProductType.CAP: return '🧢';
      case ProductType.TANK_TOP: return '🎽';
      default: return '📦';
    }
  };

  const getStatusCount = (status: OrderStatus) => orders.filter(o => o.status === status).length;
  const getUnreadCount = (status: OrderStatus) => orders.filter(o => o.status === status && !o.viewed).length;

  return (
    <div className="bg-white rounded-3xl p-8 shadow-2xl border border-gray-100 animate-in fade-in duration-500 relative">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Панель управления</h2>
          <p className="text-gray-500 text-sm">Управление заказами и статусами</p>
        </div>
        <Button onClick={fetchOrders} variant="outline" size="sm" className="w-full md:w-auto">
          🔄 Обновить данные
        </Button>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-10">
        {(Object.keys(STATUS_LABELS) as OrderStatus[]).map((status) => {
          const unread = getUnreadCount(status);
          return (
            <div 
              key={status} 
              onClick={() => setStatusFilter(status)}
              className={`p-5 rounded-2xl cursor-pointer transition-all border-2 relative overflow-hidden ${
                statusFilter === status 
                  ? 'bg-indigo-50 border-indigo-500 shadow-md scale-[1.02]' 
                  : 'bg-white border-gray-100 hover:border-indigo-200'
              }`}
            >
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{STATUS_LABELS[status]}</p>
              <div className="flex items-center justify-between">
                <span className="text-3xl font-black text-gray-800">{getStatusCount(status)}</span>
                <span className={`w-3 h-3 rounded-full ${getStatusColor(status).split(' ')[0]}`}></span>
              </div>
              {unread > 0 && (
                <div className="absolute top-2 right-2 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse"></span>
                  <span className="text-[9px] font-bold text-indigo-600 uppercase">{unread} нов.</span>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-4 mb-6 bg-gray-50 p-6 rounded-2xl border border-gray-100">
        <div className="flex-1 w-full">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Поиск</label>
          <input 
            type="text" 
            placeholder="Имя, ID или заметки..."
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none focus:ring-2 ring-indigo-500 text-sm shadow-sm"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
        <div className="w-full md:w-64">
          <label className="block text-xs font-bold text-gray-400 uppercase mb-2 ml-1">Фильтр по статусу</label>
          <select 
            className="w-full p-3 bg-white border border-gray-200 rounded-xl outline-none cursor-pointer text-sm shadow-sm font-medium"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">Все статусы</option>
            {Object.entries(STATUS_LABELS).map(([key, label]) => (
              <option key={key} value={key}>{label}</option>
            ))}
          </select>
        </div>
        {(statusFilter !== 'all' || filterText) && (
          <button 
            onClick={resetFilters}
            className="text-xs font-bold text-indigo-600 hover:text-indigo-800 px-2 py-3 transition-colors"
          >
            Очистить
          </button>
        )}
      </div>

      {loading ? (
        <div className="py-20 text-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-500 font-medium">Синхронизация данных...</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-2xl border border-gray-100">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-4 text-left">
                  <input 
                    type="checkbox" 
                    className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500 cursor-pointer"
                    checked={filteredOrders.length > 0 && selectedOrderIds.size === filteredOrders.length}
                    onChange={() => handleSelectAll(filteredOrders)}
                  />
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('date')}>
                  Дата {sortField === 'date' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('customer')}>
                  Клиент {sortField === 'customer' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Товары</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider cursor-pointer hover:text-indigo-600" onClick={() => handleSort('status')}>
                  Статус {sortField === 'status' && (sortOrder === 'desc' ? '↓' : '↑')}
                </th>
